window.RG_DATA["unit:gra-12"]={"id":"gra-12","num":12,"title":"Liên kết phụ thuộc: sự tiếp hợp","vi":"Liên kết phụ thuộc: sự tiếp hợp","ru":"Подчинительная связь: примыкание","icon":"🧮","color":"#22c55e","sectionPrefix":"gra-12-s","sections":[{"id":"gra-12-s001","type":"grammar","title":"Liên kết phụ thuộc: sự tiếp hợp","num":null,"blocks":[{"t":"para","text":"Примыкание к глаголу (Sự tiếp hợp với động từ)"}]},{"id":"gra-12-s002","type":"exercise","title":"Упражнение 128","num":128,"blocks":[{"t":"instruction","text":"Đọc các cụm từ. Hãy chú ý đến những từ được sử dụng bên cạnh động từ với vai trò là từ phụ thuộc."},{"t":"para","text":"1. Примыкание к глаголу инфинитива с субъектным значением (Sự tiếp hợp của động từ nguyên thể với động từ mang ý nghĩa chủ ngữ - hành động do chính chủ thể thực hiện):"},{"t":"para","text":"а) При глаголах со значением возможности, способности, умения (Với các động từ mang ý nghĩa khả năng, năng lực, kỹ năng):"},{"t":"para","text":"мочь/смочь прийти́: có thể/sẽ có thể đến."},{"t":"para","text":"мочь/смочь приходи́ть: có thể/sẽ có thể đến (thường xuyên)."},{"t":"para","text":"уме́ть расска́зывать/рассказа́ть (суме́ть рассказа́ть): biết kể chuyện/kể lại (xoay xở kể lại được)."},{"t":"para","text":"учи́ться/научи́ться чита́ть: học/học được (đã biết) đọc."},{"t":"subhead","text":"б) При фазовых глаголах (Với các động từ chỉ giai đoạn):"},{"t":"para","text":"начина́ть/нача́ть рабо́тать: bắt đầu làm việc."},{"t":"para","text":"поступи́ть учи́ться: vào học (nhập học)."},{"t":"para","text":"принима́ться/приня́ться объясня́ть: bắt tay vào/bắt đầu giải thích."},{"t":"para","text":"продолжа́ть/продо́лжить спо́рить: tiếp tục tranh luận."},{"t":"para","text":"зака́нчивать/зако́нчить стро́ить: hoàn thành việc xây dựng."},{"t":"para","text":"перестава́ть/переста́ть игра́ть: ngừng chơi."},{"t":"para","text":"прекраща́ть/прекрати́ть волнова́ться: thôi lo lắng."},{"t":"para","text":"в) При глаголах со значением цели (Với các động từ mang ý nghĩa mục đích):"},{"t":"para","text":"оста́ться жить: ở lại (để) sống."},{"t":"para","text":"пойти́ пообе́дать: đi ăn trưa."},{"t":"para","text":"взять почита́ть: lấy (mượn) để đọc."},{"t":"para","text":"позвони́ть прове́рить: gọi điện (để) kiểm tra."},{"t":"para","text":"сесть занима́ться: ngồi xuống (để) học bài."},{"t":"para","text":"прие́хать отдохну́ть: đến (để) nghỉ ngơi."},{"t":"para","text":"пойти́ погуля́ть: đi dạo."},{"t":"para","text":"принести́ обсуди́ть: mang đến (để) thảo luận."},{"t":"para","text":"г) При глаголах со значением желания (Với các động từ mang ý nghĩa mong muốn):"},{"t":"para","text":"хоте́ть/захоте́ть помо́чь: muốn/nảy sinh mong muốn giúp đỡ."},{"t":"para","text":"жела́ть/пожела́ть уви́деть: mong muốn/ước được nhìn thấy."},{"t":"para","text":"наде́яться/понаде́яться испра́вить: hy vọng/đặt hy vọng sửa chữa được."},{"t":"para","text":"мечта́ть прие́хать: mơ ước được đến."},{"t":"para","text":"предпочита́ть/предпоче́сть уйти́: thích hơn/ưu tiên việc rời đi."},{"t":"para","text":"люби́ть сочиня́ть: thích sáng tác."},{"t":"para","text":"д) При глаголах со значением намерения (Với các động từ mang ý nghĩa ý định):"},{"t":"para","text":"собира́ться/собра́ться е́хать: định/thu xếp để đi."},{"t":"para","text":"пыта́ться/попыта́ться объясни́ть: cố gắng/thử giải thích."},{"t":"para","text":"стара́ться/постара́ться успе́ть: cố gắng/nỗ lực để kịp."},{"t":"para","text":"рассчи́тывать победи́ть: tính toán/dự định sẽ chiến thắng."},{"t":"para","text":"реши́ть оста́ться: quyết định ở lại."},{"t":"para","text":"рискова́ть игра́ть / рискну́ть сыгра́ть: mạo hiểm chơi / liều chơi một ván."},{"t":"para","text":"согласи́ться вы́слушать: đồng ý lắng nghe."},{"t":"para","text":"отка́зываться принима́ть / отказа́ться приня́ть: từ chối tiếp nhận."},{"t":"para","text":"е) При глаголах со значением предрасположенности/непредрасположенности (Với các động từ mang ý nghĩa có khuynh hướng/không có khuynh hướng):"},{"t":"para","text":"привыка́ть/привы́кнуть ду́мать: quen với việc suy nghĩ."},{"t":"para","text":"забыва́ть звони́ть/позвони́ть (забы́ть позвони́ть): hay quên gọi/quên gọi (một lần cụ thể)."},{"t":"para","text":"не ожида́ть встре́тить: không ngờ sẽ gặp."},{"t":"para","text":"устава́ть/уста́ть спо́рить: mệt mỏi vì tranh luận/mệt (đã chán) tranh luận."},{"t":"para","text":"наску́чить рисова́ть: chán vẽ."},{"t":"para","text":"отча́яться ждать: tuyệt vọng khi chờ đợi (hết hy vọng chờ đợi)."},{"t":"para","text":"2. Примыкание к глаголу инфинитива с объектным значением (Sự tiếp hợp của động từ nguyên thể với động từ mang ý nghĩa bổ ngữ - hành động hướng vào đối tượng khác):"},{"t":"para","text":"а) При глаголах с конкретным значением (Với các động từ có ý nghĩa cụ thể):"},{"t":"para","text":"дава́ть/дать пое́сть: cho ăn."},{"t":"para","text":"принести́ умы́ться: mang (nước) đến để rửa mặt."},{"t":"para","text":"поста́вить вари́ть: đặt (bếp) để nấu."},{"t":"para","text":"положи́ть спать: đặt nằm xuống ngủ (cho ngủ)."},{"t":"para","text":"б) При глаголах со значением волеизъявления (Với các động từ mang ý nghĩa thể hiện ý chí/sai khiến):"},{"t":"para","text":"проси́ть/попроси́ть оста́ться: xin/yêu cầu ở lại."},{"t":"para","text":"умоля́ть прости́ть: van xin tha thứ."},{"t":"para","text":"прика́зывать/приказа́ть сде́лать: ra lệnh làm."},{"t":"para","text":"веле́ть останови́ться: bảo dừng lại."},{"t":"para","text":"заставля́ть/заста́вить рабо́тать: bắt buộc làm việc."},{"t":"para","text":"принужда́ть/прину́дить оста́ться: cưỡng ép ở lại."},{"t":"para","text":"обяза́ть жени́ться: buộc phải cưới."},{"t":"para","text":"угова́ривать/уговори́ть пое́хать: thuyết phục đi."},{"t":"para","text":"сове́товать/посове́товать подожда́ть: khuyên chờ đợi."},{"t":"para","text":"разреша́ть выходи́ть / разреши́ть вы́йти: cho phép đi ra."},{"t":"para","text":"позволя́ть приходи́ть / позво́лить прийти́: cho phép đến."},{"t":"para","text":"запреща́ть/запрети́ть разгова́ривать: cấm nói chuyện."},{"t":"para","text":"помога́ть/помо́чь найти́: giúp tìm kiếm."},{"t":"para","text":"меша́ть/помеша́ть рабо́тать: làm phiền/cản trở làm việc."},{"t":"para","text":"распоряжа́ться/распоряди́ться взять на рабо́ту: chỉ thị nhận vào làm việc."},{"t":"para","text":"дава́ть/дать (возмо́жность) отдохну́ть: cho (cơ hội) nghỉ ngơi."},{"t":"para","text":"3. Примыкание к глаголу обстоятельств и определений (Sự tiếp hợp của trạng ngữ và định ngữ với động từ):"},{"t":"subhead","text":"а) наречия (trạng từ):"},{"t":"para","text":"идти́ до́лго: đi lâu."},{"t":"para","text":"игра́ть хорошо́: chơi tốt."},{"t":"para","text":"есть всухомя́тку: ăn thức ăn khô (không có canh/nước)."},{"t":"para","text":"прие́хать но́чью: đến vào ban đêm."},{"t":"para","text":"говори́ть по-ру́сски: nói tiếng Nga."},{"t":"subhead","text":"б) сравнительной степени наречия (trạng từ so sánh hơn):"},{"t":"para","text":"говори́ть поня́тнее: nói dễ hiểu hơn."},{"t":"para","text":"получи́ть (на балл) бо́льше: nhận điểm cao hơn (một điểm)."},{"t":"para","text":"рабо́тать лу́чше (всех): làm việc tốt hơn (tất cả mọi người)."},{"t":"para","text":"бежа́ть быстре́е (чем други́е): chạy nhanh hơn (người khác)."},{"t":"subhead","text":"в) деепричастия (động tính từ/trạng động từ):"},{"t":"para","text":"говори́ть жестикули́руя: vừa nói vừa khua tay."},{"t":"para","text":"аплоди́ровать сто́я: đứng vỗ tay."},{"t":"para","text":"сказа́ть не поду́мав: nói mà không suy nghĩ."},{"t":"para","text":"уйти́ оби́девшись: bỏ đi vì bị xúc phạm (với vẻ giận dỗi)."}]},{"id":"gra-12-s003","type":"exercise","title":"Упражнение 129","num":129,"blocks":[{"t":"para","text":"Mở ngoặc đơn, sử dụng các cấu trúc nguyên thể với động từ thể hoàn thành (СВ) hoặc chưa hoàn thành (НСВ). Giải thích sự lựa chọn của bạn, chỉ ra các phương án."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"instruction","text":"Việc sử dụng động từ thể hoàn thành hoặc chưa hoàn thành trong cấu trúc nguyên thể phụ thuộc vào tình huống:"},{"t":"para","text":"Он смо́жет научи́ться (Cậu ấy sẽ có thể học được [kết quả]) — hành động một lần + kết quả."},{"t":"para","text":"Он мо́жет хорошо́ учи́ться (Cậu ấy có thể học tốt [quá trình]) — khả năng + quá trình."},{"t":"para","text":"Он смо́жет учи́ться без тро́ек (Cậu ấy sẽ có thể học không bị điểm 3) — kết quả + quá trình."},{"t":"para","text":"Он мо́жет научи́ться э́тому (Cậu ấy có thể học được điều này) — khả năng + kết quả."},{"t":"para","text":"Ở thì tương lai, động từ мочь (có thể) chỉ có dạng thể hoàn thành (смочь)."},{"t":"para","text":"Các động từ chỉ giai đoạn (bắt đầu, kết thúc, tiếp tục...) không kết hợp với các dạng thể hoàn thành."},{"t":"para","text":"Я могу́ (смогу́) зако́нчить э́ту рабо́ту пря́мо сейча́с, е́сли ты наста́иваешь;"},{"t":"para","text":"Dịch: Tôi có thể (sẽ có thể) hoàn thành công việc này ngay bây giờ, nếu bạn khăng khăng."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng могу́ (hiện tại) hoặc смогу́ (tương lai) đều được, tùy thuộc vào sắc thái \"tôi có khả năng ngay lúc này\" hoặc \"tôi sẽ làm được ngay\"."},{"t":"para","text":"Dùng nguyên thể hoàn thành зако́нчить vì câu nói nhấn mạnh vào kết quả cụ thể (\"hoàn thành ngay bây giờ\")."},{"t":"para","text":"Она́ уме́ет хорошо́ гото́вить;"},{"t":"para","text":"Dịch: Cô ấy biết nấu ăn ngon."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng уме́ет (biết/có kỹ năng) chỉ khả năng thường xuyên."},{"t":"para","text":"Dùng nguyên thể chưa hoàn thành гото́вить vì chỉ kỹ năng tổng quát, một quá trình lặp lại, không phải một lần cụ thể."},{"t":"para","text":"Тебе́ ну́жно обяза́тельно научи́ться (учи́ться) пра́вильно излага́ть свои́ мы́сли;"},{"t":"para","text":"Dịch: Bạn nhất định cần phải học cách diễn đạt suy nghĩ của mình cho đúng."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Có thể dùng научи́ться (học được/đạt được kỹ năng - kết quả) hoặc учи́ться (học tập - quá trình). Tuy nhiên, với từ \"обязательно\" (nhất định) thường hướng tới kết quả đạt được (научи́ться)."},{"t":"para","text":"Động từ phụ thuộc излага́ть (diễn đạt) để ở thể chưa hoàn thành (НСВ) vì nó chỉ kỹ năng thực hiện hành động đó nói chung (quá trình)."},{"t":"para","text":"Он суме́ет (уме́ет), е́сли ну́жно, предста́вить свою́ рабо́ту в лу́чшем ви́де;"},{"t":"para","text":"Dịch: Cậu ấy sẽ biết cách (biết cách), nếu cần, trình bày công việc của mình ở dạng tốt nhất."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng суме́ет (tương lai của суметь - xoay xở được) vì có điều kiện \"nếu cần\" (tình huống cụ thể). Cũng có thể dùng уме́ет (có kỹ năng đó)."},{"t":"para","text":"Dùng nguyên thể hoàn thành предста́вить vì nhấn mạnh vào kết quả trình bày trong tình huống cụ thể đó."},{"t":"para","text":"Мне лу́чше не быва́ть у вас, но ты мо́жешь приходи́ть ко мне, когда́ захо́чешь;"},{"t":"para","text":"Dịch: Tốt hơn là tôi không nên đến chỗ bạn, nhưng bạn có thể đến chỗ tôi bất cứ khi nào bạn muốn."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng мо́жешь."},{"t":"para","text":"Dùng nguyên thể chưa hoàn thành приходи́ть vì có từ \"когда захочешь\" (bất cứ khi nào) chỉ hành động lặp lại, cho phép chung."},{"t":"para","text":"Переста́ньте спо́рить, все уже́ уста́ли от бесконе́чных конфли́ктов;"},{"t":"para","text":"Dịch: Hãy ngừng tranh luận đi, mọi người đã mệt mỏi vì những xung đột bất tận rồi."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng mệnh lệnh thức Переста́ньте (ngừng lại)."},{"t":"para","text":"Dùng nguyên thể chưa hoàn thành спо́рить vì theo quy tắc, động từ chỉ giai đoạn (перестать) không đi với thể hoàn thành."},{"t":"para","text":"Не волну́йся, за́втра в ну́жный моме́нт он суме́ет вы́сказать своё мне́ние;"},{"t":"para","text":"Dịch: Đừng lo, ngày mai vào thời điểm cần thiết anh ấy sẽ biết cách (xoay xở để) nói ra ý kiến của mình."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng суме́ет (hoặc сможет) vì chỉ khả năng trong một tình huống cụ thể tương lai."},{"t":"para","text":"Dùng nguyên thể hoàn thành вы́сказать vì nhấn mạnh kết quả của hành động nói ra một lần cụ thể."},{"t":"para","text":"Я не́сколько раз принима́лся расска́зывать, но ка́ждый раз приходи́л кто́-нибудь из мои́х колле́г и я до́лжен был начина́ть всё снача́ла;"},{"t":"para","text":"Dịch: Tôi đã vài lần bắt tay vào kể, nhưng lần nào cũng có ai đó trong số đồng nghiệp bước vào và tôi phải bắt đầu lại từ đầu."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng принима́лся (bắt đầu - quá khứ)."},{"t":"para","text":"Dùng nguyên thể chưa hoàn thành расска́зывать vì đi sau động từ chỉ giai đoạn (приниматься)."},{"t":"para","text":"Она́ не перестава́ла болта́ть ни на мину́ту, и мне с трудо́м удало́сь вста́вить в наш диало́г не́сколько слов;"},{"t":"para","text":"Dịch: Cô ấy không ngừng huyên thuyên dù chỉ một phút, và tôi khó khăn lắm mới chêm được vài từ vào cuộc đối thoại của chúng tôi."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng перестава́ла (ngừng)."},{"t":"para","text":"Dùng nguyên thể chưa hoàn thành болта́ть vì đi sau động từ chỉ giai đoạn (переставать)."},{"t":"para","text":"Входи́те, пожа́луйста, мы уже́ зака́нчиваем (зако́нчили) обсужда́ть на́ши дела́, оста́лся то́лько оди́н вопро́с;"},{"t":"para","text":"Dịch: Mời vào, chúng tôi đang kết thúc (đã kết thúc) việc thảo luận công việc, chỉ còn lại một vấn đề."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Có thể dùng зака́нчиваем (đang kết thúc) hoặc зако́нчили (đã xong phần chính)."},{"t":"para","text":"Dùng nguyên thể chưa hoàn thành обсужда́ть vì đi sau động từ chỉ giai đoạn (заканчивать)."},{"t":"para","text":"Она́ начала́ учи́ться на истори́ческом факульте́те, но пото́м перешла́ на филологи́ческий факульте́т;"},{"t":"para","text":"Dịch: Cô ấy đã bắt đầu học ở khoa lịch sử, nhưng sau đó chuyển sang khoa ngữ văn."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng начала́ (bắt đầu)."},{"t":"para","text":"Dùng nguyên thể chưa hoàn thành учи́ться vì đi sau động từ chỉ giai đoạn (начать)."},{"t":"para","text":"Дождь прекрати́л идти́ (идёт) в два часа́ но́чи;"},{"t":"para","text":"Dịch: Mưa đã ngừng rơi lúc hai giờ đêm."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng прекрати́л (ngừng)."},{"t":"para","text":"Dùng nguyên thể chưa hoàn thành идти́ vì đi sau động từ chỉ giai đoạn."},{"t":"para","text":"Нет, он никуда́ не ушёл, он продолжа́ет (продо́лжил) рабо́тать в на́шем институ́те;"},{"t":"para","text":"Dịch: Không, ông ấy không đi đâu cả, ông ấy tiếp tục làm việc ở viện của chúng tôi."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng продолжа́ет (đang tiếp tục) hoặc продо́лжил (đã tiếp tục sau khi ngắt quãng)."},{"t":"para","text":"Dùng nguyên thể chưa hoàn thành рабо́тать vì đi sau động từ chỉ giai đoạn (продолжать)."},{"t":"para","text":"То́лько че́рез час, когда́ почини́ли компью́тер, я смог продо́лжить рабо́ту;"},{"t":"para","text":"Dịch: Chỉ một tiếng sau, khi máy tính đã được sửa, tôi mới có thể tiếp tục công việc."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng смог (đã có thể - chỉ kết quả cụ thể)."},{"t":"para","text":"Dùng nguyên thể hoàn thành продо́лжить vì đây là bổ ngữ cho động từ смог (có thể làm gì? -> có thể tiếp tục). Lưu ý: Ở đây продолжить đóng vai trò là hành động trọn vẹn đạt được nhờ khả năng (смог), và nó bổ ngữ cho смог, chứ không phải là động từ pha đi kèm với một động từ khác (vì работу ở đây là danh từ bổ ngữ). Nếu là động từ: смог продолжить работать."},{"t":"para","text":"Позвони́ ей, ка́жется, она́ суме́ет (смо́жет) вы́яснить ну́жную тебе́ информа́цию;"},{"t":"para","text":"Dịch: Hãy gọi cho cô ấy, hình như cô ấy sẽ biết cách (sẽ có thể) làm sáng tỏ (tìm ra) thông tin bạn cần."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng суме́ет (xoay xở được) hoặc смо́жет (có khả năng)."},{"t":"para","text":"Dùng nguyên thể hoàn thành вы́яснить vì chỉ kết quả cụ thể cần đạt được (tìm ra thông tin)."},{"t":"para","text":"Я наде́юсь встре́титься с ва́ми за́втра у́тром;"},{"t":"para","text":"Dịch: Tôi hy vọng được gặp các bạn vào sáng mai."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Dùng наде́юсь."},{"t":"para","text":"Dùng nguyên thể hoàn thành встре́титься vì chỉ một sự kiện cụ thể, một kết quả mong đợi trong tương lai gần."},{"t":"para","text":"На́до учи́ться (научи́ться) ду́мать самостоя́тельно, без э́того ты не смо́жешь получи́ть образова́ние."},{"t":"para","text":"Dịch: Cần phải học (học được) cách suy nghĩ độc lập, không có điều đó bạn sẽ không thể nhận được sự giáo dục (tốt)."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: учи́ться ду́мать (học quá trình suy nghĩ) hoặc научи́ться ду́мать (đạt được kỹ năng suy nghĩ). Cả hai đều được, научиться nhấn mạnh kết quả cần đạt. Думать là NSV vì chỉ kỹ năng tư duy nói chung."},{"t":"para","text":"Vế 2: не смо́жешь (sẽ không thể - tương lai). получи́ть (hoàn thành - kết quả: nhận được tấm bằng/sự giáo dục)."}]},{"id":"gra-12-s004","type":"exercise","title":"Примыкание к глаголу (Sự tiếp hợp với động từ)","num":null,"blocks":[]},{"id":"gra-12-s005","type":"exercise","title":"Упражнение 130","num":130,"blocks":[{"t":"para","text":"Điền liên từ что́бы vào chỗ trống nếu cần thiết. Giải thích sự lựa chọn của bạn, chỉ ra các phương án."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Trong các cấu trúc mang ý nghĩa chỉ mục đích \"động từ + động từ nguyên thể\", liên từ что́бы được sử dụng:"},{"t":"para","text":"Nếu từ chính diễn đạt một hành động độc lập (chứ không phải trung gian/phụ trợ) (Мы еди́м, что́бы жить, а не живём, что́бы есть — Chúng ta ăn để sống, chứ không phải sống để ăn) — giữa các động từ tồn tại mối liên hệ logic, chứ không phải tình huống."},{"t":"para","text":"Nếu động từ nguyên thể dẫn nhập (hoặc ngụ ý) một bổ ngữ bổ sung. So sánh: Взять (кни́гу), что́бы переда́ть её дру́гу (Lấy cuốn sách để đưa nó cho bạn) — Взять (кни́гу) почита́ть (Lấy cuốn sách [để] đọc); Оста́ться, что́бы встре́тить ро́дственников (Ở lại để đón họ hàng) — Оста́ться помо́чь (Ở lại [để] giúp đỡ); Подозва́ть официа́нта, что́бы расплати́ться (по счёту) (Gọi người phục vụ để thanh toán hóa đơn)."},{"t":"para","text":"Sau các động từ дать (đưa/cho), взять (lấy), сесть (ngồi), лечь (nằm) và các động từ khác mang ý nghĩa phụ trợ, trung gian, liên từ что́бы thường được lược bỏ: Он э́ту кни́гу взял почита́ть (Anh ấy đã lấy cuốn sách này [để] đọc)."},{"t":"para","text":"Я сде́лал э́ту рабо́ту, что́бы отчита́ться пе́ред нача́льством;"},{"t":"instruction","text":"Dịch: Tôi đã làm công việc này để báo cáo trước ban lãnh đạo."},{"t":"para","text":"Giải thích: Động từ chính сде́лал (đã làm) diễn tả một hành động độc lập, trọn vẹn. Mục đích là отчита́ться (báo cáo). Cần dùng что́бы."},{"t":"para","text":"За́втра я пригласи́л их пообе́дать (что́бы пообе́дать), а по́сле обе́да мы мо́жем сходи́ть на экску́рсию;"},{"t":"para","text":"Dịch: Ngày mai tôi đã mời họ ăn trưa (để ăn trưa), và sau bữa trưa chúng tôi có thể đi tham quan."},{"t":"para","text":"Giải thích: Thông thường, пригласи́ть đi trực tiếp với động từ nguyên thể (пригласи́л пообе́дать), nhưng cũng có thể dùng что́бы nếu muốn nhấn mạnh mục đích rõ ràng. Cả hai phương án đều có thể chấp nhận, nhưng không có что́бы phổ biến hơn."},{"t":"para","text":"Я верну́лся (что́бы) взять зонт;"},{"t":"para","text":"Dịch: Tôi đã quay lại (để) lấy ô."},{"t":"para","text":"Giải thích: Верну́лся là động từ chuyển động. Thường không cần что́бы, nhưng nếu nhấn mạnh mục đích của việc quay lại, có thể dùng что́бы. (Thông thường: верну́лся взять)."},{"t":"para","text":"Она́ вчера́ мне звони́ла, что́бы напо́мнить о встре́че;"},{"t":"para","text":"Dịch: Hôm qua cô ấy đã gọi cho tôi để nhắc về cuộc gặp."},{"t":"para","text":"Giải thích: Звони́ла (gọi điện) là hành động độc lập, không phải động từ chuyển động hay động từ phụ trợ. Cần dùng что́бы."},{"t":"para","text":"Снача́ла дава́й пригото́вим что́-нибудь пое́сть;"},{"t":"para","text":"Dịch: Trước tiên hãy nấu cái gì đó (để) ăn đi."},{"t":"para","text":"Giải thích: Пригото́вим пое́сть là cụm từ thông dụng, không cần что́бы. Đây là hành động tạo ra đối tượng để thực hiện hành động tiếp theo."},{"t":"para","text":"Он сказа́л э́то специа́льно, что́бы оби́деть нас;"},{"t":"para","text":"Dịch: Hắn ta nói điều đó cố tình để xúc phạm chúng tôi."},{"t":"para","text":"Giải thích: Trạng từ специа́льно (cố tình/đặc biệt) nhấn mạnh mục đích, nên bắt buộc dùng что́бы."},{"t":"para","text":"По́сле обе́да я сел занима́ться, и тут разда́лся телефо́нный звоно́к;"},{"t":"para","text":"Dịch: Sau bữa trưa tôi ngồi xuống (để) học bài, và lúc đó chuông điện thoại reo."},{"t":"para","text":"Giải thích: Sau động từ сесть (ngồi), liên từ что́бы được lược bỏ."},{"t":"para","text":"Я игра́ю, что́бы выи́грывать, поэ́тому ка́ждая неуда́ча бо́льно бьёт по моему́ самолю́бию;"},{"t":"para","text":"Dịch: Tôi chơi để thắng, vì thế mỗi thất bại đều đánh mạnh vào lòng tự trọng của tôi."},{"t":"para","text":"Giải thích: Игра́ю là hành động độc lập. Mối liên hệ logic giữa \"chơi\" và \"thắng\" đòi hỏi что́бы."},{"t":"para","text":"Она́ вста́ла, что́бы уйти́, но неожи́данно в ко́мнату вошёл но́вый посети́тель;"},{"t":"para","text":"Dịch: Cô ấy đứng dậy để rời đi, nhưng bất ngờ một vị khách mới bước vào phòng."},{"t":"para","text":"Giải thích: Вста́ла (đứng dậy) là một hành động độc lập để thực hiện mục đích rời đi. Dùng что́бы để rõ nghĩa mục đích."},{"t":"para","text":"В э́тот день я о́чень уста́л и лёг спать в де́сять часо́в ве́чера;"},{"t":"para","text":"Dịch: Ngày hôm đó tôi rất mệt và đã nằm ngủ lúc mười giờ tối."},{"t":"para","text":"Giải thích: Sau động từ лечь (nằm), liên từ что́бы được lược bỏ."},{"t":"para","text":"Мы подняли́сь на смотрову́ю площа́дку, (что́бы) осмотре́ть окре́стности го́рода;"},{"t":"para","text":"Dịch: Chúng tôi đã leo lên đài quan sát (để) ngắm cảnh ngoại ô thành phố."},{"t":"para","text":"Giải thích: Подняли́сь là động từ chuyển động, thường không cần что́бы, nhưng dùng что́бы cũng không sai để nhấn mạnh mục đích."},{"t":"para","text":"Он пригласи́л меня́ танцева́ть, и так начало́сь на́ше знако́мство;"},{"t":"para","text":"Dịch: Anh ấy đã mời tôi nhảy, và sự quen biết của chúng tôi đã bắt đầu như thế."},{"t":"para","text":"Giải thích: Пригласи́л танцева́ть là cụm cố định chỉ lời mời thực hiện hành động chung, không cần что́бы."},{"t":"para","text":"Я позвони́л, что́бы прости́ться, за́втра я улета́ю;"},{"t":"para","text":"Dịch: Tôi gọi điện để tạm biệt, ngày mai tôi bay rồi."},{"t":"para","text":"Giải thích: Позвони́л là hành động độc lập, cần что́бы để chỉ mục đích."},{"t":"para","text":"Я по́днял ру́ку, что́бы зада́ть вопро́с, но жела́ющих спроси́ть бы́ло так мно́го, что о́чередь до меня́ так и не дошла́;"},{"t":"para","text":"Dịch: Tôi đã giơ tay để đặt câu hỏi, nhưng người muốn hỏi quá nhiều đến nỗi không đến lượt tôi."},{"t":"para","text":"Giải thích: По́днял ру́ку là hành động cụ thể nhằm mục đích xin phép nói, cần что́бы."},{"t":"para","text":"Дай мне, пожа́луйста, посмотре́ть твой журна́л;"},{"t":"para","text":"Dịch: Làm ơn cho tôi xem tạp chí của bạn."},{"t":"para","text":"Giải thích: Sau động từ дать (đưa/cho), liên từ что́бы được lược bỏ."},{"t":"para","text":"Мы се́ли на авто́бус, что́бы дое́хать до институ́та;"},{"t":"para","text":"Dịch: Chúng tôi đã lên xe buýt để đi đến học viện."},{"t":"para","text":"Giải thích: Hành động се́ли на авто́бус (lên xe buýt) là phương tiện để đạt mục đích дое́хать (đi đến nơi). Cần что́бы (hoặc dùng се́ли ... дое́хать trong khẩu ngữ, nhưng что́бы chuẩn hơn vì дое́хать có tiền tố chỉ giới hạn)."},{"t":"para","text":"Повтори́ стихотворе́ние ещё раз, что́бы лу́чше запо́мнить;"},{"t":"para","text":"Dịch: Hãy lặp lại bài thơ một lần nữa để ghi nhớ tốt hơn."},{"t":"para","text":"Giải thích: Hành động độc lập và mục đích logic. Cần что́бы."},{"t":"para","text":"Прополощи́ бельё и пове́сь его́ суши́ться;"},{"t":"para","text":"Dịch: Hãy giũ quần áo và treo nó phơi khô (cho khô)."},{"t":"para","text":"Giải thích: Пове́сь суши́ться là cụm động từ chỉ vị trí + mục đích trạng thái, không cần что́бы."},{"t":"para","text":"Sử dụng động từ nguyên thể với tiểu từ phủ định не, hãy đặt câu của riêng bạn từ những câu đã cho. Hãy lưu ý rằng trong trường hợp này chỉ có thể sử dụng cấu trúc với liên từ что́бы."},{"t":"para","text":"Ví dụ: Я позвони́л, что́бы не опозда́ть (Tôi đã gọi điện để không bị muộn)."},{"t":"para","text":"Ví dụ: Мы подняли́сь на площа́дку, что́бы не пропусти́ть зака́т (Chúng tôi leo lên sân thượng để không bỏ lỡ hoàng hôn)."}]},{"id":"gra-12-s006","type":"exercise","title":"Упражнение 131","num":131,"blocks":[{"t":"para","text":"Điền liên từ что́бы vào chỗ trống, ở những nơi cần thiết. Giải thích sự lựa chọn của bạn, chỉ ra các phương án."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Trong các cấu trúc mang ý nghĩa chỉ mục đích \"động từ chuyển động + động từ nguyên thể\", liên từ что́бы được sử dụng:"},{"t":"para","text":"Với các động từ chuyển động có tiền tố об-, до-, у-."},{"t":"para","text":"Khi có sự phủ định (Мы пое́хали на такси́, что́бы не заблуди́ться — Chúng tôi đi taxi để không bị lạc)."},{"t":"para","text":"Khi có sự đối lập giữa các động từ nguyên thể, liên từ что́бы bị lược bỏ: Я пришёл не спо́рить, а мири́ться (Tôi đến không phải để tranh cãi, mà để làm hòa)."},{"t":"para","text":"Hầu hết các động từ chuyển động một chiều (thể hoàn thành) kết hợp với động từ nguyên thể thể hoàn thành mà không cần что́бы (вы́шел купи́ть), nhưng các động từ với tiền tố у-, по-, при- có thể kết hợp với nguyên thể chưa hoàn thành (không có что́бы) hoặc nguyên thể hoàn thành (thường có что́бы)."},{"t":"para","text":"Он вы́шел купи́ть сигаре́т;"},{"t":"instruction","text":"Dịch: Anh ấy đã đi ra ngoài (để) mua thuốc lá."},{"t":"para","text":"Giải thích: Вы́шел là động từ chuyển động. Thường dùng không có что́бы."},{"t":"para","text":"Хозя́йка отошла́ поздоро́ваться с но́выми гостя́ми;"},{"t":"para","text":"Dịch: Bà chủ đã đi ra chỗ khác (để) chào hỏi những vị khách mới."},{"t":"para","text":"Giải thích: Отошла́ là động từ chuyển động. Không cần что́бы."},{"t":"para","text":"Мы объе́хали вокру́г до́ма, что́бы найти́ стоя́нку для маши́ны;"},{"t":"para","text":"Dịch: Chúng tôi đã lái xe vòng quanh nhà để tìm chỗ đậu xe."},{"t":"para","text":"Giải thích: Động từ chuyển động объе́хали có tiền tố об-, cần dùng что́бы."},{"t":"para","text":"Он зашёл ко мне́ на мину́ту переда́ть запи́ску;"},{"t":"para","text":"Dịch: Anh ấy đã ghé qua chỗ tôi một phút (để) đưa mảnh giấy."},{"t":"para","text":"Giải thích: Зашёл là động từ chuyển động. Không cần что́бы."},{"t":"para","text":"Мы пришли́ в университе́т получи́ть зачёт;"},{"t":"para","text":"Dịch: Chúng tôi đã đến trường đại học (để) nhận điểm kiểm tra."},{"t":"para","text":"Giải thích: Пришли́ là động từ chuyển động. Không cần что́бы."},{"t":"para","text":"Мы дое́хали до кольца́, что́бы осмотре́ть центр го́рода;"},{"t":"para","text":"Dịch: Chúng tôi đã đi xe đến vòng xoay để ngắm trung tâm thành phố."},{"t":"para","text":"Giải thích: Động từ дое́хали có tiền tố до-, cần dùng что́бы."},{"t":"para","text":"Он зашёл не сдава́ть докуме́нты, а вы́яснить, как их заполня́ть;"},{"t":"para","text":"Dịch: Anh ấy ghé vào không phải để nộp tài liệu, mà để tìm hiểu cách điền chúng."},{"t":"para","text":"Giải thích: Có sự đối lập (не... а), liên từ что́бы bị lược bỏ."},{"t":"para","text":"Мы зае́хали к нему́ познако́миться с его́ роди́телями;"},{"t":"para","text":"Dịch: Chúng tôi đã ghé qua chỗ cậu ấy (để) làm quen với bố mẹ cậu ấy."},{"t":"para","text":"Giải thích: Зае́хали là động từ chuyển động. Không cần что́бы."},{"t":"para","text":"Кот зале́з на де́рево пойма́ть пти́чку;"},{"t":"para","text":"Dịch: Con mèo đã leo lên cây (để) bắt chim."},{"t":"para","text":"Giải thích: Зале́з là động từ chuyển động. Không cần что́бы."},{"t":"para","text":"Догони́ его́, что́бы напо́мнить о за́втрашней встре́че;"},{"t":"para","text":"Dịch: Hãy đuổi theo anh ấy để nhắc về cuộc gặp ngày mai."},{"t":"para","text":"Giải thích: Động từ догони́ có tiền tố до-, cần dùng что́бы."},{"t":"para","text":"Я пришёл к врачу́ не лечи́ться, а получи́ть но́вый реце́пт;"},{"t":"para","text":"Dịch: Tôi đến bác sĩ không phải để chữa bệnh, mà để lấy đơn thuốc mới."},{"t":"para","text":"Giải thích: Có sự đối lập (не... а), liên từ что́бы bị lược bỏ."},{"t":"para","text":"Мы зашли́ в бесе́дку спря́таться от дождя́;"},{"t":"para","text":"Dịch: Chúng tôi đã ghé vào vọng lâu (để) trú mưa."},{"t":"para","text":"Giải thích: Зашли́ là động từ chuyển động. Không cần что́бы."},{"t":"para","text":"Мы обошли́ не́сколько магази́нов, что́бы купи́ть все необходи́мые проду́кты;"},{"t":"para","text":"Dịch: Chúng tôi đã đi vòng qua vài cửa hàng để mua tất cả thực phẩm cần thiết."},{"t":"para","text":"Giải thích: Động từ обошли́ có tiền tố об-, cần dùng что́бы."},{"t":"para","text":"Я заходи́л прове́рить, до́ма он и́ли нет;"},{"t":"para","text":"Dịch: Tôi đã ghé qua (để) kiểm tra xem anh ấy có nhà hay không."},{"t":"para","text":"Giải thích: Заходи́л là động từ chuyển động. Không cần что́бы."},{"t":"para","text":"Она́ приходи́ла рассказа́ть после́дние но́вости;"},{"t":"para","text":"Dịch: Cô ấy đã đến (để) kể những tin tức mới nhất."},{"t":"para","text":"Giải thích: Приходи́ла là động từ chuyển động. Không cần что́бы."},{"t":"para","text":"Я дошёл с ни́ми до гости́ницы, что́бы быть уве́ренным, что они́ не заблу́дятся;"},{"t":"para","text":"Dịch: Tôi đã đi cùng họ đến khách sạn để chắc chắn rằng họ không bị lạc."},{"t":"para","text":"Giải thích: Động từ дошёл có tiền tố до-, cần dùng что́бы."},{"t":"para","text":"Он вы́шел на полчаса́ погуля́ть с соба́кой;"},{"t":"para","text":"Dịch: Anh ấy đã đi ra ngoài nửa tiếng (để) đi dạo với chó."},{"t":"para","text":"Giải thích: Вы́шел là động từ chuyển động. Không cần что́бы."},{"t":"para","text":"Мы зае́дем в рестора́н поу́жинать, а пото́м пое́дем в теа́тр;"},{"t":"para","text":"Dịch: Chúng tôi sẽ ghé vào nhà hàng (để) ăn tối, rồi sau đó sẽ đi nhà hát."},{"t":"para","text":"Giải thích: Зае́дем là động từ chuyển động. Không cần что́бы."},{"t":"para","text":"Она́ пришла́ пора́ньше, что́бы не пропусти́ть свою́ люби́мую переда́чу."},{"t":"para","text":"Dịch: Cô ấy đã đến sớm hơn để không bỏ lỡ chương trình yêu thích của mình."},{"t":"para","text":"Giải thích: Có sự phủ định (не + động từ nguyên thể), cần dùng что́бы."}]},{"id":"gra-12-s007","type":"exercise","title":"Примыкание к глаголу (Sự tiếp hợp với động từ)","num":null,"blocks":[]},{"id":"gra-12-s008","type":"exercise","title":"Упражнение 132","num":132,"blocks":[{"t":"para","text":"Mở ngoặc đơn, sử dụng động từ nguyên thể thể hoàn thành hoặc chưa hoàn thành không có liên từ hoặc với liên từ что́бы. Giải thích sự lựa chọn của bạn, chỉ ra các phương án."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Trong các cấu trúc chỉ mục đích \"động từ chuyển động + động từ nguyên thể\", liên từ что́бы được sử dụng:"},{"t":"para","text":"Với các động từ chuyển động có tiền tố об-, до-, у-."},{"t":"para","text":"Khi có sự phủ định (Мы пое́хали на такси́, что́бы не заблуди́ться — Chúng tôi đi taxi để không bị lạc)."},{"t":"para","text":"Khi có sự đối lập giữa các động từ nguyên thể, liên từ что́бы bị lược bỏ: Я пришёл не спо́рить, а мири́ться (Tôi đến không phải để tranh cãi, mà để làm hòa)."},{"t":"para","text":"Hầu hết các động từ chuyển động một chiều (thể hoàn thành) kết hợp với động từ nguyên thể thể hoàn thành mà không cần что́бы (вы́шел купи́ть). Tuy nhiên, các động từ với tiền tố у-, по-, при- có thể kết hợp với nguyên thể chưa hoàn thành (không có что́бы) hoặc nguyên thể hoàn thành (thường có что́бы)."},{"t":"para","text":"Он ушёл гото́виться (что́бы подгото́виться) к за́втрашнему докла́ду;"},{"t":"instruction","text":"Dịch: Anh ấy đã đi để chuẩn bị cho bài báo cáo ngày mai."},{"t":"para","text":"Giải thích: Động từ ушёл có tiền tố у-. Có thể dùng гото́виться (NSV - chỉ quá trình) không cần что́бы, hoặc что́бы подгото́виться (SV - chỉ kết quả)."},{"t":"para","text":"У́тром я пое́ду на вокза́л покупа́ть (что́бы купи́ть) биле́т;"},{"t":"para","text":"Dịch: Buổi sáng tôi sẽ đi ra nhà ga để mua vé."},{"t":"para","text":"Giải thích: Пое́ду có tiền tố по-. Dùng покупа́ть (NSV) không cần что́бы, hoặc что́бы купи́ть (SV) để nhấn mạnh kết quả."},{"t":"para","text":"Мы прие́хали проси́ть (попроси́ть) (что́бы попроси́ть) у вас проще́ния;"},{"t":"para","text":"Dịch: Chúng tôi đã đến để xin các bạn tha thứ."},{"t":"para","text":"Giải thích: Прие́хали có tiền tố при-. Có thể dùng проси́ть/попроси́ть không что́бы hoặc что́бы попроси́ть."},{"t":"para","text":"Он уе́хал на вокза́л провожа́ть (что́бы проводи́ть) дру́га;"},{"t":"para","text":"Dịch: Anh ấy đã đi ra nhà ga để tiễn bạn."},{"t":"para","text":"Giải thích: Уе́хал có tiền tố у-. Dùng провожа́ть (NSV) hoặc что́бы проводи́ть (SV)."},{"t":"para","text":"На́ши друзья́ пое́хали на юг отдыха́ть (отдохну́ть) (что́бы отдохну́ть);"},{"t":"para","text":"Dịch: Bạn bè của chúng tôi đã đi về phía nam để nghỉ ngơi."},{"t":"para","text":"Giải thích: Пое́хали (tiền tố по-) kết hợp với отдыха́ть (NSV) hoặc отдохну́ть (SV), có thể thêm что́бы với thể hoàn thành."},{"t":"para","text":"Они́ заходи́ли проща́ться (что́бы попроща́ться) сего́дня днём;"},{"t":"para","text":"Dịch: Họ đã ghé qua để tạm biệt chiều nay."},{"t":"para","text":"Giải thích: Заходи́ли là động từ chuyển động nhiều chiều (NSV). Có thể dùng проща́ться (NSV) hoặc что́бы попроща́ться (SV)."},{"t":"para","text":"Он уе́хал, что́бы забы́ть о про́шлом;"},{"t":"para","text":"Dịch: Anh ấy đã bỏ đi để quên đi quá khứ."},{"t":"para","text":"Giải thích: Trong trường hợp này, cấu trúc уе́хал забы́ть (không có что́бы) thực tế không được sử dụng, bắt buộc dùng что́бы."},{"t":"para","text":"Он заходи́л, что́бы отда́ть кни́гу;"},{"t":"para","text":"Dịch: Anh ấy đã ghé qua để trả sách."},{"t":"para","text":"Giải thích: Dùng что́бы отда́ть (SV) để chỉ mục đích cụ thể đã hoàn thành."},{"t":"para","text":"Они́ приходи́ли пока́зывать (показа́ть) (что́бы показа́ть) фотогра́фии;"},{"t":"para","text":"Dịch: Họ đã đến để cho xem ảnh."},{"t":"para","text":"Giải thích: Приходи́ли (NSV). Có thể dùng пока́зывать (NSV) hoặc что́бы показа́ть (SV)."},{"t":"para","text":"Уви́дев знако́мого, я перешёл на другу́ю сто́рону у́лицы, что́бы поприве́тствовать его́;"},{"t":"para","text":"Dịch: Nhìn thấy người quen, tôi đã sang bên kia đường để chào anh ấy."},{"t":"para","text":"Giải thích: Перешёл có tiền tố пере- (tương tự nhóm об-, до- chỉ giới hạn/kết quả chuyển động), thường dùng что́бы với động từ hoàn thành поприве́тствовать."},{"t":"para","text":"Я ненадо́лго выходи́л звони́ть (что́бы позвони́ть) по телефо́ну;"},{"t":"para","text":"Dịch: Tôi đã đi ra ngoài một lát để gọi điện thoại."},{"t":"para","text":"Giải thích: Выходи́л (NSV). Dùng звони́ть (NSV) hoặc что́бы позвони́ть (SV)."},{"t":"para","text":"Я прие́ду к вам за́втра помога́ть (помо́чь) (что́бы помо́чь) перевози́ть ве́щи на но́вую кварти́ру;"},{"t":"para","text":"Dịch: Ngày mai tôi sẽ đến chỗ các bạn để giúp chuyển đồ sang căn hộ mới."},{"t":"para","text":"Giải thích: Прие́ду (tiền tố при-). Dùng помога́ть hoặc помо́чь, có thể thêm что́бы."},{"t":"para","text":"Он отошёл от ка́ссы, что́бы посмотре́ть расписа́ние;"},{"t":"para","text":"Dịch: Anh ấy đã rời khỏi quầy vé để xem lịch trình."},{"t":"para","text":"Giải thích: Отошёл (tiền tố от- chỉ sự rời đi), thường dùng что́бы để chỉ mục đích tách biệt."},{"t":"para","text":"Они́ пое́хали сдава́ть (сдать) (что́бы сдать) маши́ну в ремо́нт;"},{"t":"para","text":"Dịch: Họ đã đi để gửi (giao) xe đi sửa."},{"t":"para","text":"Giải thích: Пое́хали (tiền tố по-). Các phương án: сдава́ть, сдать, что́бы сдать đều chấp nhận được."},{"t":"para","text":"Она́ ушла́ в институ́т принима́ть (что́бы приня́ть) экза́мен;"},{"t":"para","text":"Dịch: Cô ấy đã đi đến học viện để coi (nhận) thi."},{"t":"para","text":"Giải thích: Ушла́ (tiền tố у-). Dùng принима́ть (NSV) hoặc что́бы приня́ть (SV)."},{"t":"para","text":"Мы перее́хали в друго́й го́род, что́бы найти́ рабо́ту;"},{"t":"para","text":"Dịch: Chúng tôi đã chuyển đến thành phố khác để tìm việc làm."},{"t":"para","text":"Giải thích: Cấu trúc перее́хали найти́ (không có что́бы) thực tế không được sử dụng, bắt buộc dùng что́бы."}]},{"id":"gra-12-s009","type":"exercise","title":"Упражнение 133","num":133,"blocks":[{"t":"para","text":"Điền liên từ что́бы vào chỗ trống nếu cần thiết. Giải thích sự lựa chọn của bạn."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Trong các cấu trúc chỉ mục đích với động từ chuyển động везти́, вести́, нести́ (chở, dẫn, mang) có tiền tố và kết hợp với bổ ngữ trực tiếp (đối tượng bị tác động):"},{"t":"para","text":"Liên từ что́бы được sử dụng nếu hành động của động từ nguyên thể (mục đích) do chủ ngữ thực hiện."},{"t":"para","text":"Nếu không có liên từ что́бы, hành động của động từ nguyên thể do bổ ngữ (đối tượng) thực hiện."},{"t":"para","text":"Ví dụ: Роди́тели отвезли́ дете́й к ба́бушке отдохну́ть (Bố mẹ chở con cái đến bà để [con cái] nghỉ ngơi - không có чтобы). — Роди́тели отвезли́ дете́й к ба́бушке, что́бы отдохну́ть (Bố mẹ chở con cái đến bà để [bố mẹ] nghỉ ngơi - có чтобы)."},{"t":"para","text":"Я привёз тебе́ почита́ть но́вые журна́лы;"},{"t":"instruction","text":"Dịch: Tôi đã mang đến cho bạn tạp chí mới (để bạn) đọc."},{"t":"para","text":"Giải thích: Hành động đọc do bổ ngữ (bạn) thực hiện. Không cần что́бы."},{"t":"para","text":"На́до вы́вести соба́ку погуля́ть;"},{"t":"para","text":"Dịch: Cần dắt chó ra ngoài (để chó) đi dạo."},{"t":"para","text":"Giải thích: Chó (bổ ngữ) đi dạo. Không cần что́бы."},{"t":"para","text":"Я ду́маю, положе́ние серьёзное, нам сто́ит отвезти́ больно́го в го́род, что́бы показа́ть врачу́;"},{"t":"para","text":"Dịch: Tôi nghĩ tình hình nghiêm trọng, chúng ta nên chở bệnh nhân lên thành phố để (chúng ta) cho bác sĩ xem."},{"t":"para","text":"Giải thích: Chúng ta (chủ ngữ) thực hiện hành động \"cho xem/đưa đi khám\". Cần что́бы."},{"t":"para","text":"Я отнесу́ э́ту страни́цу к секретарю́ перепеча́тать;"},{"t":"para","text":"Dịch: Tôi sẽ mang trang này đến cho thư ký (để thư ký) đánh máy lại."},{"t":"para","text":"Giải thích: Thư ký (bổ ngữ gián tiếp) thực hiện hành động. Không cần что́бы."},{"t":"para","text":"Я слы́шал, ты е́дешь на да́чу, привези́ немно́го я́блок, что́бы свари́ть варе́нье;"},{"t":"para","text":"Dịch: Tôi nghe nói bạn đi dã ngoại, hãy mang về ít táo để (bạn/chúng ta) nấu mứt."},{"t":"para","text":"Giải thích: Táo không tự nấu. Người mang táo (chủ ngữ) sẽ nấu. Cần что́бы."},{"t":"para","text":"— Что у тебя́ в су́мке? — Да вот принёс журна́лы почита́ть на досу́ге;"},{"t":"para","text":"Dịch: — Trong túi bạn có gì thế? — À thì mang tạp chí đến để đọc lúc rảnh rỗi."},{"t":"para","text":"Giải thích: Mặc dù chủ ngữ đọc, nhưng cụm принёс почита́ть (mang đến để đọc) thường dùng không có что́бы trong khẩu ngữ khi mục đích gắn liền với vật thể. Đáp án sách không dùng что́бы."},{"t":"para","text":"За́втра я собира́юсь вы́везти роди́телей за́ город подыша́ть све́жим во́здухом;"},{"t":"para","text":"Dịch: Ngày mai tôi định chở bố mẹ ra ngoại ô (để bố mẹ) hít thở không khí trong lành."},{"t":"para","text":"Giải thích: Bố mẹ (bổ ngữ) hít thở. Không cần что́бы."},{"t":"para","text":"Пого́да прекра́сная, на́до вы́нести больно́го в сад погре́ться на со́лнышке;"},{"t":"para","text":"Dịch: Thời tiết tuyệt vời, cần đưa bệnh nhân ra vườn (để bệnh nhân) sưởi nắng."},{"t":"para","text":"Giải thích: Bệnh nhân (bổ ngữ) sưởi nắng. Không cần что́бы."},{"t":"para","text":"Два ра́за в неде́лю я отводи́л дете́й к учи́тельнице занима́ться му́зыкой;"},{"t":"para","text":"Dịch: Hai lần một tuần tôi dẫn bọn trẻ đến cô giáo (để bọn trẻ) học nhạc."},{"t":"para","text":"Giải thích: Bọn trẻ (bổ ngữ) học. Không cần что́бы."},{"t":"para","text":"Я привёз мя́со, что́бы пригото́вить шашлы́к;"},{"t":"para","text":"Dịch: Tôi đã mang thịt đến để (tôi/chúng ta) làm món thịt nướng."},{"t":"para","text":"Giải thích: Chủ ngữ thực hiện hành động nấu. Cần что́бы."},{"t":"para","text":"Бы́ло уже́ по́здно, и мать увела́ дете́й спать;"},{"t":"para","text":"Dịch: Trời đã muộn, và mẹ đã dẫn bọn trẻ đi (để bọn trẻ) ngủ."},{"t":"para","text":"Giải thích: Bọn trẻ (bổ ngữ) ngủ. Không cần что́бы."},{"t":"para","text":"За́втра я повезу́ госте́й в Пу́шкин показа́ть Екатери́нинский дворе́ц;"},{"t":"para","text":"Dịch: Ngày mai tôi sẽ chở khách đến Pushkin để cho (khách) xem cung điện Catherine."},{"t":"para","text":"Giải thích: Mặc dù chủ ngữ (tôi) là người \"cho xem\" (show), nhưng trong ngữ cảnh này повезу́ показа́ть thường được dùng liền mạch như một cụm động từ chỉ mục đích cho đối tượng trải nghiệm. Sách đáp án không dùng что́бы."},{"t":"para","text":"Снача́ла я отвезу́ их поу́жинать, а пото́м мы пойдём в кино́;"},{"t":"para","text":"Dịch: Trước tiên tôi sẽ chở họ đi (để họ) ăn tối, rồi sau đó chúng tôi sẽ đi xem phim."},{"t":"para","text":"Giải thích: Họ (bổ ngữ) ăn tối. Không cần что́бы."},{"t":"para","text":"Отнеси́ за́втра ве́щи в пра́чечную постира́ть;"},{"t":"para","text":"Dịch: Ngày mai hãy mang đồ đến tiệm giặt là để (người ta/tiệm) giặt."},{"t":"para","text":"Giải thích: Hành động giặt được thực hiện bởi dịch vụ (đối tượng gián tiếp/nơi chốn), không phải chủ ngữ. Không cần что́бы."},{"t":"para","text":"За́втра я хочу́ повести́ дете́й в го́род пое́сть моро́женого."},{"t":"para","text":"Dịch: Ngày mai tôi muốn dẫn bọn trẻ lên phố (để bọn trẻ) ăn kem."},{"t":"para","text":"Giải thích: Bọn trẻ (bổ ngữ) ăn. Không cần что́бы."}]},{"id":"gra-12-s010","type":"exercise","title":"Примыкание к глаголу (Sự tiếp hợp với động từ)","num":null,"blocks":[]},{"id":"gra-12-s011","type":"exercise","title":"Упражнение 134","num":134,"blocks":[{"t":"para","text":"Điền các liên từ что hoặc что́бы vào chỗ trống. Giải thích sự lựa chọn của bạn."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Trong các cấu trúc mang ý nghĩa mong muốn, ý định hoặc khuynh hướng, động từ nguyên thể được sử dụng nếu hành động của động từ chính và động từ nguyên thể thuộc về cùng một chủ thể: я хочу́ уйти́ (tôi muốn rời đi); và sử dụng các liên từ что (что́бы) nếu hành động của chúng thuộc về các chủ thể khác nhau: я хочу́, что́бы вы ушли́ (tôi muốn các bạn rời đi)."},{"t":"para","text":"Liên từ что được sử dụng với các глаголами наде́яться (hy vọng), мечта́ть (mơ ước), забы́ть (quên), рассчи́тывать (tính toán/dự định), реши́ть (quyết định), привы́кнуть (quen), согласи́ться (đồng ý) khi mang ý nghĩa chờ đợi thụ động, với nghĩa 'nghĩ rằng, tin rằng': мечта́ть, что всё нала́дится (mơ ước rằng mọi thứ sẽ ổn thỏa)."},{"t":"para","text":"Liên từ Что́бы được sử dụng với các động từ жела́ть (mong muốn), предпочита́ть (thích hơn/ưu tiên), люби́ть (yêu thích), согласи́ться (đồng ý - khi mang nghĩa đồng thuận để việc gì xảy ra), diễn đạt nỗ lực gây ảnh hưởng, với nghĩa 'muốn (không phản đối), để cho': жела́ть, что́бы всё нала́дилось (mong muốn để mọi thứ trở nên ổn thỏa)."},{"t":"para","text":"Я наде́юсь, что мы смо́жем с ва́ми ка́к-нибудь пообе́дать вме́сте;"},{"t":"instruction","text":"Dịch: Tôi hy vọng rằng chúng ta sẽ có thể cùng nhau ăn trưa vào lúc nào đó."},{"t":"para","text":"Giải thích: Động từ наде́яться (hy vọng) thường đi với что khi diễn tả niềm tin vào một sự việc sẽ xảy ra."},{"t":"para","text":"Он захоте́л, что́бы мы ушли́;"},{"t":"para","text":"Dịch: Anh ấy đã muốn để chúng tôi rời đi."},{"t":"para","text":"Giải thích: Động từ chỉ mong muốn (захоте́л) tác động lên chủ thể khác $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Мы мечта́ем, что́бы вы рабо́тали вме́сте с на́ми;"},{"t":"para","text":"Dịch: Chúng tôi mơ ước (để) bạn làm việc cùng với chúng tôi."},{"t":"para","text":"Giải thích: Mặc dù мечта́ть có thể đi với что, nhưng ở đây diễn tả một mong muốn/nguyện vọng tác động lên người khác (muốn điều đó xảy ra) nên dùng что́бы (động từ mệnh đề phụ ở quá khứ: работали)."},{"t":"para","text":"Я предпочита́ю, что́бы никто́ не вме́шивался в мои́ дела́;"},{"t":"para","text":"Dịch: Tôi thích (để) không ai can thiệp vào công việc của tôi hơn."},{"t":"para","text":"Giải thích: Предпочита́ть (thích hơn/ưu tiên) mang ý nghĩa ý chí/mong muốn $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Я не ожида́л, что он придёт;"},{"t":"para","text":"Dịch: Tôi đã không ngờ rằng anh ấy sẽ đến."},{"t":"para","text":"Giải thích: Ожида́ть (mong đợi/ngờ) chỉ sự nhận thức thực tế/dự đoán $\\rightarrow$ dùng что."},{"t":"para","text":"Он реши́л, что мы должны́ оста́ться и помо́чь вам;"},{"t":"para","text":"Dịch: Anh ấy đã quyết định rằng chúng tôi phải ở lại và giúp đỡ các bạn."},{"t":"para","text":"Giải thích: Реши́ть (quyết định/kết luận) về một sự việc thực tế/nhận định $\\rightarrow$ dùng что."},{"t":"para","text":"Я согласи́лся, что он неплохо́й челове́к;"},{"t":"para","text":"Dịch: Tôi đã đồng ý rằng anh ấy là một người không tồi."},{"t":"para","text":"Giải thích: Согласи́ться mang nghĩa \"thừa nhận nhận định này là đúng\" $\\rightarrow$ dùng что."},{"t":"para","text":"Я наде́юсь, что вы ещё мо́жете посла́ть зая́вку на уча́стие в конфере́нции;"},{"t":"para","text":"Dịch: Tôi hy vọng rằng bạn vẫn còn có thể gửi đơn đăng ký tham gia hội nghị."},{"t":"para","text":"Giải thích: Наде́яться + thông tin thực tế $\\rightarrow$ dùng что."},{"t":"para","text":"Он забы́л, что ты до́лжен позвони́ть;"},{"t":"para","text":"Dịch: Anh ấy đã quên rằng bạn phải gọi điện."},{"t":"para","text":"Giải thích: Забы́ть (quên) một sự kiện/thông tin thực tế $\\rightarrow$ dùng что."},{"t":"para","text":"Я не привы́к, что́бы со мно́й разгова́ривали таки́м то́ном;"},{"t":"para","text":"Dịch: Tôi không quen (việc) người ta nói chuyện với tôi bằng cái giọng điệu như thế."},{"t":"para","text":"Giải thích: Trong câu phủ định với привы́кнуть, khi diễn tả sự không chấp nhận một hành động xảy ra (mang sắc thái mong muốn ngược lại), thường dùng что́бы."},{"t":"para","text":"Мы постара́емся, что́бы вы здесь не чу́вствовали себя́ одино́ко;"},{"t":"para","text":"Dịch: Chúng tôi sẽ cố gắng để bạn không cảm thấy cô đơn ở đây."},{"t":"para","text":"Giải thích: Постара́ться (cố gắng) luôn hướng tới mục đích $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Я предпочита́ю, что́бы вы самостоя́тельно зако́нчили э́тот прое́кт;"},{"t":"para","text":"Dịch: Tôi muốn (thích hơn) để bạn tự mình hoàn thành dự án này."},{"t":"para","text":"Giải thích: Предпочита́ть + mong muốn $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Я наде́юсь, что ещё не по́здно всё испра́вить;"},{"t":"para","text":"Dịch: Tôi hy vọng rằng vẫn chưa muộn để sửa chữa mọi thứ."},{"t":"para","text":"Giải thích: Наде́яться + nhận định $\\rightarrow$ dùng что."},{"t":"para","text":"Он рассчи́тывал, что вы то́же при́мете уча́стие в экспеди́ции;"},{"t":"para","text":"Dịch: Anh ấy đã tính (dự định/mong) rằng bạn cũng sẽ tham gia vào đoàn thám hiểm."},{"t":"para","text":"Giải thích: Рассчи́тывать (tính toán/tin rằng) $\\rightarrow$ dùng что."},{"t":"para","text":"Он согласи́лся, что́бы друзья́ помогли́ ему́;"},{"t":"para","text":"Dịch: Anh ấy đã đồng ý để bạn bè giúp đỡ mình."},{"t":"para","text":"Giải thích: Согласи́ться ở đây mang nghĩa \"cho phép/chấp thuận để hành động xảy ra\" $\\rightarrow$ dùng что́бы. (Khác với câu 7 là thừa nhận sự thật)."},{"t":"para","text":"Я люблю́, что́бы вокру́г бы́ло мно́го наро́ду;"},{"t":"para","text":"Dịch: Tôi thích (việc) xung quanh có đông người."},{"t":"para","text":"Giải thích: Люби́ть diễn tả sở thích/mong muốn về một trạng thái $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Я предпочита́ю, что́бы лю́ди говори́ли мне пра́вду."},{"t":"para","text":"Dịch: Tôi thích (để) mọi người nói sự thật với tôi hơn."},{"t":"para","text":"Giải thích: Предпочита́ть + mong muốn $\\rightarrow$ dùng что́бы."}]},{"id":"gra-12-s012","type":"exercise","title":"Упражнение 135","num":135,"blocks":[{"t":"para","text":"Mở ngoặc đơn, sử dụng các câu với cấu trúc động từ nguyên thể (infinitive) hoặc với liên từ что hoặc что́бы. Giải thích sự lựa chọn của bạn."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Khi tiếp hợp với động từ nguyên thể mang ý nghĩa bổ ngữ (object infinitive), các liên từ что (что́бы) không được sử dụng: помо́г реши́ть пробле́му (đã giúp giải quyết vấn đề)."},{"t":"para","text":"Ngoại lệ là các động từ проси́ть (xin/yêu cầu), умоля́ть (van xin), позволя́ть (cho phép), прика́зывать (ra lệnh), распоряжа́ться (chỉ thị): умоля́л меня́ прости́ть его́ (van xin tôi tha thứ cho anh ấy) hoặc умоля́л, что́бы я прости́л его́ (van xin để tôi tha thứ cho anh ấy). (Cả hai cách đều được với nhóm động từ ngoại lệ này, nhưng cách dùng nguyên thể gọn hơn)."},{"t":"para","text":"Я не заставля́ю тебя́ дава́ть отве́т пря́мо сейча́с, у тебя́ есть вре́мя, что́бы поду́мать;"},{"t":"instruction","text":"Dịch: Tôi không ép bạn đưa ra câu trả lời ngay bây giờ, bạn có thời gian để suy nghĩ."},{"t":"para","text":"Giải thích: Động từ заставля́ть (ép buộc) đi trực tiếp với Bổ ngữ + Động từ nguyên thể (Accusative + Infinitive). Không dùng чтобы."},{"t":"para","text":"Я хочу́, что́бы вы приступи́ли к рабо́те неме́дленно;"},{"t":"para","text":"Dịch: Tôi muốn (để) các bạn bắt tay vào công việc ngay lập tức."},{"t":"para","text":"Giải thích: Động từ хоте́ть (muốn) với hai chủ thể khác nhau (Tôi muốn - Bạn làm) bắt buộc dùng что́бы."},{"t":"para","text":"Он предпочита́л, что́бы други́е за него́ рабо́тали;"},{"t":"para","text":"Dịch: Anh ấy thích để người khác làm việc thay cho mình hơn."},{"t":"para","text":"Giải thích: Предпочита́ть với hai chủ thể khác nhau $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Я наде́юсь, что вы смо́жете измени́ть расписа́ние;"},{"t":"para","text":"Dịch: Tôi hy vọng rằng các bạn sẽ có thể thay đổi lịch trình."},{"t":"para","text":"Giải thích: Наде́яться (hy vọng) thường đi với что + động từ ở thì tương lai/hiện tại."},{"t":"para","text":"Мы уговори́ли на́ших друзе́й подожда́ть с поку́пкой кварти́ры;"},{"t":"para","text":"Dịch: Chúng tôi đã thuyết phục bạn bè của mình chờ đợi việc mua căn hộ."},{"t":"para","text":"Giải thích: Уговори́ть (thuyết phục) + Bổ ngữ + Động từ nguyên thể."},{"t":"para","text":"Все помога́ли мне найти́ рабо́ту;"},{"t":"para","text":"Dịch: Mọi người đã giúp tôi tìm việc làm."},{"t":"para","text":"Giải thích: Помога́ть + Bổ ngữ (Cách 3) + Động từ nguyên thể. Không dùng чтобы."},{"t":"para","text":"Мои́ друзья́ хоте́ли, что́бы я пое́хал с ни́ми на Да́льний Восто́к;"},{"t":"para","text":"Dịch: Bạn bè tôi đã muốn (để) tôi đi cùng họ đến Viễn Đông."},{"t":"para","text":"Giải thích: Хоте́ть với hai chủ thể khác nhau $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Никто́ не мо́жет заста́вить меня́ измени́ть своё реше́ние;"},{"t":"para","text":"Dịch: Không ai có thể ép tôi thay đổi quyết định của mình."},{"t":"para","text":"Giải thích: Заста́вить + Bổ ngữ + Động từ nguyên thể."},{"t":"para","text":"Она́ попроси́ла меня́ переда́ть письмо́ её роди́телям (Она́ попроси́ла, что́бы я пе́редал письмо́ её роди́телям);"},{"t":"para","text":"Dịch: Cô ấy đã nhờ tôi chuyển thư cho bố mẹ cô ấy."},{"t":"para","text":"Giải thích: Проси́ть là động từ ngoại lệ, có thể dùng cấu trúc nguyên thể (phổ biến hơn) hoặc что́бы."},{"t":"para","text":"Суд обяза́л подсуди́мого заплати́ть штраф;"},{"t":"para","text":"Dịch: Tòa án đã buộc bị cáo phải nộp phạt."},{"t":"para","text":"Giải thích: Обяза́ть (buộc/bắt) + Bổ ngữ + Động từ nguyên thể."},{"t":"para","text":"Я хочу́, что́бы ме́жду на́ми не́ было никаки́х секре́тов;"},{"t":"para","text":"Dịch: Tôi muốn (để) giữa chúng ta không có bất kỳ bí mật nào."},{"t":"para","text":"Giải thích: Хоте́ть + tình huống/chủ thể khác $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Мы уговори́ли его́ помири́ться с колле́гами;"},{"t":"para","text":"Dịch: Chúng tôi đã thuyết phục anh ấy làm hòa với đồng nghiệp."},{"t":"para","text":"Giải thích: Уговори́ть + Bổ ngữ + Động từ nguyên thể."},{"t":"para","text":"Он без конца́ разгова́ривал и меша́л мне рабо́тать;"},{"t":"para","text":"Dịch: Anh ta nói chuyện không dứt và làm phiền tôi làm việc."},{"t":"para","text":"Giải thích: Меша́ть + Bổ ngữ (Cách 3) + Động từ nguyên thể."},{"t":"para","text":"Мы наде́емся, что вы смо́жете прие́хать к нам в октябре́;"},{"t":"para","text":"Dịch: Chúng tôi hy vọng rằng bạn sẽ có thể đến chỗ chúng tôi vào tháng Mười."},{"t":"para","text":"Giải thích: Наде́яться + что + tương lai."},{"t":"para","text":"Дире́ктор распоряди́лся нача́ть произво́дство но́вой проду́кции;"},{"t":"para","text":"Dịch: Giám đốc đã chỉ thị bắt đầu sản xuất sản phẩm mới."},{"t":"para","text":"Giải thích: Распоряди́ться (chỉ thị) thường đi với nguyên thể nếu không chỉ rõ đối tượng thực hiện cụ thể, hoặc dùng чтобы nếu muốn nhấn mạnh. Ở đây dùng nguyên thể là gọn nhất."},{"t":"para","text":"Он согласи́лся, что ситуа́ция в стране́ тяжёлая;"},{"t":"para","text":"Dịch: Ông ấy đã đồng ý (thừa nhận) rằng tình hình trong nước đang khó khăn."},{"t":"para","text":"Giải thích: Đồng ý với một nhận định thực tế $\\rightarrow$ dùng что."},{"t":"para","text":"Она́ не позволя́ла де́тям без разреше́ния уходи́ть из до́ма (Она́ не позволя́ла, что́бы де́ти без разреше́ния уходи́ли из до́ма);"},{"t":"para","text":"Dịch: Bà ấy không cho phép trẻ con ra khỏi nhà khi chưa xin phép."},{"t":"para","text":"Giải thích: Позволя́ть là ngoại lệ, dùng được cả hai, nhưng nguyên thể phổ biến hơn."},{"t":"para","text":"Я не могу́ заста́вить тебя́ пойти́ к врачу́, ты сам до́лжен понима́ть, что э́то необходи́мо;"},{"t":"para","text":"Dịch: Tôi không thể ép bạn đi bác sĩ, tự bạn phải hiểu rằng điều đó là cần thiết."},{"t":"para","text":"Giải thích: Заста́вить + Bổ ngữ + Động từ nguyên thể."},{"t":"para","text":"Мы все́й душо́й жела́ем, что́бы вы бы́ли сча́стливы;"},{"t":"para","text":"Dịch: Chúng tôi toàn tâm toàn ý mong muốn (để) các bạn được hạnh phúc."},{"t":"para","text":"Giải thích: Жела́ть (chúc/mong muốn cho người khác) $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Прошу́ тебя́ дать возмо́жность мне зако́нчить разгово́р по телефо́ну;"},{"t":"para","text":"Dịch: Tôi xin bạn hãy cho tôi cơ hội kết thúc cuộc nói chuyện điện thoại."},{"t":"para","text":"Giải thích: Проси́ть + Bổ ngữ + Động từ nguyên thể."}]},{"id":"gra-12-s013","type":"exercise","title":"Упражнение 136","num":136,"blocks":[{"t":"instruction","text":"Đọc các cụm từ động từ + trạng từ. Xác định tính chất liên kết giữa từ chính và từ phụ thuộc. Đặt câu với các cụm từ này."},{"t":"note","text":"! (Gợi ý ngữ pháp): Đây là dạng liên kết Примыкание (Sự tiếp hợp/Sự áp sát). Trong đó, từ phụ thuộc là từ không biến đổi hình thái (trạng từ, động từ nguyên thể, trạng động từ), nó gắn với từ chính chỉ bằng ý nghĩa."},{"t":"para","text":"Бежа́ть без огля́дки (Chạy thục mạng/chạy không ngoảnh lại)."},{"t":"para","text":"Câu: Испугавшись собаки, мальчик бежа́л без огля́дки до самого дома. (Sợ con chó, cậu bé chạy thục mạng về tận nhà)."},{"t":"para","text":"Прорабо́тать бок о́ бок (Làm việc sát cánh bên nhau)."},{"t":"para","text":"Câu: Мы прорабо́тали бок о́ бок двадцать лет и никогда не ссорились. (Chúng tôi đã làm việc sát cánh bên nhau 20 năm và chưa bao giờ cãi cọ)."},{"t":"para","text":"Посла́ть вдого́нку (Gửi đuổi theo/Gửi theo sau)."},{"t":"para","text":"Câu: Он забыл документы, и я посла́л их ему вдого́нку. (Anh ấy quên tài liệu, và tôi đã gửi chúng đuổi theo anh ấy)."},{"t":"para","text":"Сказа́ть в заключе́ние (Nói tóm lại/Nói phần kết luận)."},{"t":"para","text":"Câu: В заключе́ние докладчик сказа́л, что эксперимент прошел успешно. (Trong phần kết luận diễn giả đã nói rằng thí nghiệm diễn ra thành công)."},{"t":"para","text":"Разби́ть вдре́безги (Đập tan tành)."},{"t":"para","text":"Câu: Кот уронил вазу и разби́л её вдре́безги. (Con mèo làm rơi cái bình và đập nó tan tành)."},{"t":"para","text":"Получи́ть взаме́н (Nhận lại/Nhận để đổi lại)."},{"t":"para","text":"Câu: Я отдал ему свою книгу, а взаме́н получи́л редкий журнал. (Tôi đưa cho cậu ấy cuốn sách của mình, và đổi lại nhận được cuốn tạp chí hiếm)."},{"t":"para","text":"Уви́деть вдали́ (вблизи́) (Nhìn thấy đằng xa/ở gần)."},{"t":"para","text":"Câu: Мы уви́дели вдали́ очертания гор. (Chúng tôi nhìn thấy dáng núi ở đằng xa)."},{"t":"para","text":"Игра́ть в откры́тую (вслепу́ю) (Chơi bài ngửa/công khai - Chơi mò mẫm/mù quáng)."},{"t":"para","text":"Câu: Я предпочитаю игра́ть в откры́тую и сразу говорить о своих намерениях. (Tôi thích chơi bài ngửa và nói ngay về ý định của mình)."},{"t":"para","text":"Сде́лать вта́йне (Làm bí mật/lén lút)."},{"t":"para","text":"Câu: Он сде́лал это вта́йне от родителей. (Nó đã làm điều này giấu bố mẹ)."},{"t":"para","text":"Подде́рживать в це́лом (Ủng hộ nhìn chung/tổng thể)."},{"t":"para","text":"Câu: Я подде́рживаю ваш проект в це́лом, но есть замечания по деталям. (Nhìn chung tôi ủng hộ dự án của bạn, nhưng có vài nhận xét về chi tiết)."},{"t":"para","text":"Наби́ть (су́мку) до отка́за (Nhét (túi) đầy ắp/chật ních)."},{"t":"para","text":"Câu: Туристы наби́ли рюкзаки до отка́за. (Du khách đã nhét ba lô chật ních)."},{"t":"para","text":"Сжечь дотла́ (Đốt trụi/thiêu rụi hoàn toàn)."},{"t":"para","text":"Câu: Пожар сжёг деревню дотла́. (Đám cháy đã thiêu rụi ngôi làng)."},{"t":"para","text":"Быть заодно́ с кем? (Đồng lòng/cùng phe với ai)."},{"t":"para","text":"Câu: В этом споре я заодно́ с братом. (Trong cuộc tranh luận này tôi cùng phe với anh trai)."},{"t":"para","text":"Уви́деть и́здали (Nhìn thấy từ xa)."},{"t":"para","text":"Câu: Я уви́дел его и́здали и помахал рукой. (Tôi nhìn thấy anh ấy từ xa và vẫy tay)."},{"t":"para","text":"Уда́ться на сла́ву (Thành công mỹ mãn/rất tốt)."},{"t":"para","text":"Câu: Пирог уда́лся на сла́ву. (Cái bánh thành công mỹ mãn)."},{"t":"para","text":"Определи́ть на глаз (Xác định bằng mắt/ước lượng)."},{"t":"para","text":"Câu: Строитель определи́л расстояние на глаз. (Người thợ xây đã ước lượng khoảng cách bằng mắt)."},{"t":"para","text":"Бежа́ть наперегонки́ (Chạy thi)."},{"t":"para","text":"Câu: Дети бежа́ли к реке наперегонки́. (Lũ trẻ chạy thi ra sông)."},{"t":"para","text":"Вы́полнить наполови́ну (Hoàn thành một nửa)."},{"t":"para","text":"Câu: Задание вы́полнено только наполови́ну. (Nhiệm vụ mới chỉ được hoàn thành một nửa)."},{"t":"para","text":"Взять напрока́т (Thuê/mướn)."},{"t":"para","text":"Câu: Мы взя́ли машину напрока́т, чтобы осмотреть остров. (Chúng tôi đã thuê xe ô tô để ngắm đảo)."},{"t":"para","text":"Вы́прыгнуть на ходу́ (Nhảy ra khi đang chạy/di chuyển)."},{"t":"para","text":"Câu: Опасно выпры́гивать из поезда на ходу́. (Nhảy khỏi tàu khi đang chạy rất nguy hiểm)."},{"t":"para","text":"Быть побли́зости (Ở gần đó)."},{"t":"para","text":"Câu: Если вы бу́дете побли́зости, заходите в гости. (Nếu bạn ở gần đó, hãy ghé chơi)."},{"t":"para","text":"Руби́ть сплеча́ (Chém phăng/Hành động thiếu suy nghĩ, nóng vội)."},{"t":"para","text":"Câu: Не надо руби́ть сплеча́, сначала разберись в ситуации. (Đừng có hành động nóng vội, trước tiên hãy tìm hiểu tình hình đã)."}]},{"id":"gra-12-s014","type":"exercise","title":"Примыкание к существительному (Sự tiếp hợp dengan danh từ)","num":null,"blocks":[]},{"id":"gra-12-s015","type":"exercise","title":"Упражнение 137","num":137,"blocks":[{"t":"instruction","text":"Đọc các cụm từ. Hãy chú ý đến những từ có thể đóng vai trò là từ phụ thuộc đi kèm với danh từ trong trường hợp liên kết tiếp hợp."},{"t":"para","text":"1. Примыкание к существительному инфинитива (Sự tiếp hợp của động từ nguyên thể với danh từ):"},{"t":"para","text":"а) При наименовании, в сочетании с существительными, характеризующими субъект с точки зрения его мастерства, умения, склонности (Khi gọi tên, kết hợp với các danh từ mô tả chủ thể về mặt tay nghề, kỹ năng, khuynh hướng):"},{"t":"para","text":"ма́стер (мастери́ца) сочиня́ть: bậc thầy (nữ bậc thầy) sáng tác."},{"t":"para","text":"охо́тник (охо́тница) прихвастну́ть: kẻ thích (kẻ ham) khoác lác."},{"t":"para","text":"иску́сник (иску́сница) интригова́ть: người khéo léo (kẻ lão luyện) bày mưu tính kế/gây chuyện."},{"t":"para","text":"молоде́ц пляса́ть: người nhảy múa giỏi (người cừ khôi trong việc nhảy múa)."},{"t":"para","text":"люби́тель (люби́тельница) сове́товать: người thích (hay) đưa ra lời khuyên."},{"t":"para","text":"не дура́к (ду́ра) повесели́ться: người không ngại vui chơi (kẻ ham vui/biết cách vui chơi)."},{"t":"para","text":"б) При абстрактных существительных, обозначающих личностные качества субъекта, предмет мысли или состояние, связанное с осуществлением определённых целей (Với các danh từ trừu tượng chỉ phẩm chất cá nhân của chủ thể, đối tượng của suy nghĩ hoặc trạng thái liên quan đến việc thực hiện các mục tiêu nhất định):"},{"t":"para","text":"дар убежда́ть: khả năng (thiên bẩm) thuyết phục."},{"t":"para","text":"уме́ние руководи́ть: kỹ năng lãnh đạo."},{"t":"para","text":"привы́чка щу́риться: thói quen nheo mắt."},{"t":"para","text":"мане́ра держа́ться: phong thái (cách đi đứng/ứng xử)."},{"t":"para","text":"мысль верну́ться: ý nghĩ quay trở lại."},{"t":"para","text":"иде́я объедини́ться: ý tưởng hợp nhất/liên kết."},{"t":"para","text":"жела́ние рабо́тать: mong muốn làm việc."},{"t":"para","text":"охо́та почита́ть: hứng thú (mong muốn) đọc sách."},{"t":"para","text":"потре́бность говори́ть: nhu cầu được nói."},{"t":"para","text":"ра́дость твори́ть: niềm vui sáng tạo."},{"t":"para","text":"сча́стье ви́деть: hạnh phúc khi được nhìn thấy."},{"t":"para","text":"удово́льствие труди́ться: sự hài lòng (khoái cảm) khi lao động."},{"t":"para","text":"му́жество сопротивля́ться: lòng dũng cảm phản kháng/chống cự."},{"t":"para","text":"в) При абстрактных существительных, обозначающих обусловливающие действие условия или обстоятельства (Với các danh từ trừu tượng chỉ các điều kiện hoặc hoàn cảnh quy định hành động):"},{"t":"para","text":"свобо́да выбира́ть: tự do lựa chọn."},{"t":"para","text":"нау́ка побежда́ть: khoa học (nghệ thuật) chiến thắng."},{"t":"para","text":"судьба́ встре́титься: số phận (định mệnh) được gặp gỡ."},{"t":"para","text":"причи́на быть недово́льным: lý do để không hài lòng."},{"t":"para","text":"по́вод оста́ться: cớ (lý do) để ở lại."},{"t":"para","text":"основа́ние беспоко́иться: căn cứ (cơ sở) để lo lắng."},{"t":"para","text":"возмо́жность позвони́ть: cơ hội (khả năng) gọi điện."},{"t":"para","text":"необходи́мость задержа́ться: sự cần thiết phải nán lại (ở lại trễ)."},{"t":"para","text":"шанс вы́играть: cơ hội chiến thắng."},{"t":"para","text":"2. Примыкание к существительному неизменяемых форм прилагательного и наречия (Sự tiếp hợp của các dạng tính từ không biến đổi và trạng từ với danh từ):"},{"t":"para","text":"а) примыкание сравнительной степени прилагательного и неизменяемых прилагательных (sự tiếp hợp của tính từ so sánh hơn và tính từ không biến đổi):"},{"t":"para","text":"биле́т подеше́вле: vé rẻ hơn một chút."},{"t":"para","text":"гости́ница полу́чше: khách sạn tốt hơn một chút."},{"t":"para","text":"зада́ча поважне́е: nhiệm vụ quan trọng hơn một chút."},{"t":"para","text":"дом побо́льше: ngôi nhà lớn hơn một chút."},{"t":"para","text":"глаза́ вырази́тельнее: đôi mắt biểu cảm hơn."},{"t":"para","text":"рабо́та интере́снее: công việc thú vị hơn."},{"t":"para","text":"но́мер люкс: phòng hạng sang (phòng suite)."},{"t":"para","text":"цвет ха́ки: màu kaki."},{"t":"para","text":"пальто́ регла́н: áo khoác tay raglan."},{"t":"para","text":"брю́ки клёш: quần ống loe."},{"t":"para","text":"ю́бка ми́ни: váy ngắn (váy mini)."},{"t":"para","text":"час пик: giờ cao điểm."},{"t":"para","text":"б) примыкание наречия с определяющим обстоятельственным значением (sự tiếp hợp của trạng từ với ý nghĩa định ngữ chỉ hoàn cảnh):"},{"t":"para","text":"яйцо́ всмя́тку: trứng lòng đào."},{"t":"para","text":"взгляд исподло́бья: cái nhìn lầm lì (nhìn từ dưới trán lên)."},{"t":"para","text":"вопро́с ребро́м: câu hỏi đặt thẳng thừng (dứt khoát)."},{"t":"para","text":"во́лосы ёжиком: tóc cắt cua (tóc dựng như lông nhím)."},{"t":"para","text":"пельме́ни по-сиби́рски: món sủi cảo kiểu Siberia."},{"t":"para","text":"в) примыкание наречия со значением времени, места, меры или степени (sự tiếp hợp của trạng từ chỉ thời gian, địa điểm, mức độ hoặc cấp độ):"},{"t":"para","text":"лес зимо́й: rừng vào mùa đông."},{"t":"para","text":"пейза́ж но́чью: phong cảnh về đêm."},{"t":"para","text":"стол посереди́не: cái bàn ở chính giữa."},{"t":"para","text":"прика́з све́рху: mệnh lệnh từ cấp trên (từ phía trên)."},{"t":"para","text":"магази́н напро́тив: cửa hàng ở đối diện."},{"t":"para","text":"немно́жко зану́да: hơi (một chút) là kẻ nhạt nhẽo/lải nhải."},{"t":"para","text":"почти́ ге́ний: gần như là thiên tài."},{"t":"para","text":"совсе́м ребёнoк: hoàn toàn là một đứa trẻ (quá trẻ con)."},{"t":"para","text":"чересчу́р рома́нтик: quá là người lãng mạn."},{"t":"para","text":"о́чень не дура́к: rất không phải là kẻ ngốc (rất khôn ngoan)."},{"t":"para","text":"далеко́ не а́нгел: còn lâu mới là thiên thần (không hề hiền lành/tốt đẹp)."}]},{"id":"gra-12-s016","type":"exercise","title":"Упражнение 138","num":138,"blocks":[{"t":"instruction","text":"Hãy tìm trong các câu sau những danh từ mô tả đối tượng về mặt tay nghề, kỹ năng, khuynh hướng. Thay thế các cụm từ với những danh từ này bằng các cấu trúc đồng nghĩa \"danh từ + động từ nguyên thể\" ở những nơi có thể."},{"t":"para","text":"Он был геро́ем войны́, но в жи́зни ниче́м не отлича́лся от други́х люде́й его́ во́зраста;"},{"t":"para","text":"Dịch: Ông ấy là anh hùng chiến tranh, nhưng trong đời thường chẳng khác gì những người khác cùng trang lứa."},{"t":"para","text":"Phân tích: Từ геро́ем (anh hùng) chỉ danh hiệu/vị thế, không phải kỹ năng hay khuynh hướng để kết hợp với động từ nguyên thể trong ngữ cảnh này. Không thay thế."},{"t":"para","text":"Я никогда́ не́ был охо́тником до спле́тен;"},{"t":"para","text":"Dịch: Tôi chưa bao giờ là kẻ ham mê những lời ngồi lê đôi mách."},{"t":"para","text":"Thay thế: ... охо́тником спле́тничать (kẻ ham mê mách lẻo/ngồi lê đôi mách)."},{"t":"para","text":"В любо́м де́ле он заводи́ла, всегда́ впереди́ всех, наве́рное, хара́ктер у него́ тако́й;"},{"t":"para","text":"Dịch: Trong bất cứ việc gì cậu ấy cũng là người đầu têu (kẻ khởi xướng), luôn đi trước mọi người, chắc là tính cách cậu ấy như vậy."},{"t":"para","text":"Phân tích: Заводи́ла (người cầm đầu/khởi xướng) thường dùng độc lập hoặc với danh từ bổ nghĩa (в любом деле), ít khi dùng trực tiếp với động từ nguyên thể trong cấu trúc này. Không thay thế phổ biến."},{"t":"para","text":"Он ге́ний в нау́ке, но в жи́зни — совсе́м ребёнoк, не мо́жет ни пригото́вить ничего́ для себя́, ни убра́ть за собо́й;"},{"t":"para","text":"Dịch: Cậu ta là thiên tài trong khoa học, nhưng trong đời sống thì hoàn toàn là một đứa trẻ, không thể tự nấu nướng gì cho mình, cũng không thể tự dọn dẹp."},{"t":"para","text":"Phân tích: Ге́ний (thiên tài). Không thay thế bằng động từ nguyên thể."},{"t":"para","text":"Она́ больша́я иску́сница в приготовле́нии ра́зных блюд, ни у кого́ друго́го вам не уда́стся попро́бовать таки́х вку́сных пирого́в, блино́в и пельме́ней;"},{"t":"para","text":"Dịch: Cô ấy là một người rất khéo tay trong việc chế biến các món ăn khác nhau, bạn sẽ không thể nếm thử được các món bánh, bánh xèo và sủi cảo ngon như thế ở bất kỳ ai khác."},{"t":"para","text":"Thay thế: ... иску́сница гото́вить ра́зные блю́да (người khéo tay nấu các món ăn khác nhau)."},{"t":"para","text":"Ду́маю, ничего́ у него́ не полу́чится, иде́й у него́ хвата́ет, но он никогда́ не́ был охо́тником до их воплоще́ния в жизнь;"},{"t":"para","text":"Dịch: Tôi nghĩ cậu ta sẽ chẳng làm nên trò trống gì đâu, ý tưởng thì cậu ta có đủ, nhưng cậu ta chưa bao giờ là người ham mê việc hiện thực hóa chúng vào cuộc sống."},{"t":"para","text":"Thay thế: ... охо́тником воплоща́ть их в жизнь (người ham mê hiện thực hóa chúng vào cuộc sống)."},{"t":"para","text":"Он не дура́к по ча́сти хоро́шей еды́, лю́бит гото́вить и про́бовать но́вые блю́да;"},{"t":"para","text":"Dịch: Cậu ta không phải kẻ ngốc trong khoản đồ ăn ngon (rất sành ăn), cậu ta thích nấu nướng và thử các món mới."},{"t":"para","text":"Thay thế: ... не дура́к пое́сть (вку́сно пое́сть) (không phải kẻ ngốc trong việc ăn uống/biết cách ăn ngon)."},{"t":"para","text":"Я знако́м с одни́м специали́стом по э́тому вопро́су. Мо́жет быть, обрати́мся к нему́ за сове́том?"},{"t":"para","text":"Dịch: Tôi có quen một chuyên gia về vấn đề này. Hay là chúng ta tìm đến ông ấy xin lời khuyên?"},{"t":"para","text":"Phân tích: Специали́стом (chuyên gia). Cấu trúc специалист + инфинитив không phổ biến trong ngữ cảnh chuẩn mực (thường dùng специалист в чем/по чему). Không thay thế."},{"t":"para","text":"Не сто́ит ему́ ве́рить, он всегда́ был охо́тником по ча́сти выду́мывания ра́зных фантасти́ческих исто́рий;"},{"t":"para","text":"Dịch: Không nên tin cậu ta, cậu ta luôn là kẻ ham mê khoản bịa đặt ra những câu chuyện hoang đường khác nhau."},{"t":"para","text":"Thay thế: ... охо́тником выду́мывать ра́зные фантасти́ческие исто́рии (kẻ ham mê bịa đặt các câu chuyện hoang đường)."},{"t":"para","text":"Она́ больша́я люби́тельница худо́жественной литерату́ры, мно́го чита́ет и обожа́ет обсужда́ть прочи́танное;"},{"t":"para","text":"Dịch: Cô ấy là một người rất yêu thích văn học nghệ thuật, cô ấy đọc nhiều và rất thích thảo luận về những gì đã đọc."},{"t":"para","text":"Thay thế: ... люби́тельница чита́ть худо́жественную литерату́ру (người thích đọc văn học nghệ thuật). (Lưu ý: cần thêm động từ \"đọc\" vì danh từ gốc là \"văn học\", không phải hành động, nhưng ý nghĩa là thích đọc)."},{"t":"para","text":"Че́хов в ру́сской литерату́ре счита́ется ма́стером коро́ткого расска́за, никто́ друго́й не мог бы так то́чно и вырази́тельно в не́скольких слова́х переда́ть мысль и́ли обрисова́ть ситуа́цию;"},{"t":"para","text":"Dịch: Trong văn học Nga, Chekhov được coi là bậc thầy của truyện ngắn, không ai khác có thể truyền tải tư tưởng hoặc phác họa tình huống một cách chính xác và biểu cảm chỉ trong vài từ như vậy."},{"t":"para","text":"Thay thế: ... ма́стером пи са́ть (сочиня́ть) коро́ткие расска́зы (bậc thầy viết/sáng tác truyện ngắn)."},{"t":"para","text":"Она́ специали́ст в своём де́ле, к её мне́нию мно́гие прислу́шиваются;"},{"t":"para","text":"Dịch: Cô ấy là chuyên gia trong lĩnh vực của mình, nhiều người lắng nghe ý kiến của cô ấy."},{"t":"para","text":"Phân tích: Специали́ст (chuyên gia). Không thay thế bằng động từ nguyên thể."},{"t":"para","text":"Я не люби́тель спорти́вных переда́ч, когда́ есть свобо́дное вре́мя, предпочита́ю смотре́ть но́вости или слу́шать класси́ческую му́зыку."},{"t":"para","text":"Dịch: Tôi không phải là người thích các chương trình thể thao, khi có thời gian rảnh, tôi thích xem tin tức hoặc nghe nhạc cổ điển hơn."},{"t":"para","text":"Thay thế: ... не люби́тель смотре́ть спорти́вные переда́чи (người không thích xem các chương trình thể thao)."}]},{"id":"gra-12-s017","type":"exercise","title":"Примыкание к существительному (Sự tiếp hợp với danh từ)","num":null,"blocks":[]},{"id":"gra-12-s018","type":"exercise","title":"Упражнение 139","num":139,"blocks":[{"t":"para","text":"Mở ngoặc đơn, sử dụng động từ nguyên thể với liên từ что́бы hoặc không có liên từ. Giải thích sự lựa chọn của bạn."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Trong các cấu trúc \"danh từ + động từ nguyên thể\", liên từ что́бы được sử dụng nếu danh từ mang ý nghĩa cụ thể (vật thể): стол, что́бы занима́ться (cái bàn để học)."},{"t":"para","text":"Với các danh từ mang ý nghĩa trừu tượng, động từ nguyên thể được tiếp hợp (gắn liền) mà không cần liên từ: возмо́жность отдохну́ть (cơ hội nghỉ ngơi), свобо́да выбира́ть (tự do lựa chọn)."},{"t":"para","text":"Возьми́ зонт, что́бы не промо́кнуть под дождём;"},{"t":"instruction","text":"Dịch: Hãy cầm lấy ô để không bị ướt dưới mưa."},{"t":"para","text":"Giải thích: Зонт (cái ô) là danh từ cụ thể $\\rightarrow$ dùng что́бы."},{"t":"para","text":"У него́ о́чень стра́нная мане́ра обща́ться с людьми́;"},{"t":"para","text":"Dịch: Anh ấy có một phong thái giao tiếp với mọi người rất lạ."},{"t":"para","text":"Giải thích: Мане́ра (phong thái/cách thức) là danh từ trừu tượng $\\rightarrow$ không dùng liên từ."},{"t":"para","text":"У вас нет причи́н беспоко́иться, всё бу́дет в поря́дке;"},{"t":"para","text":"Dịch: Bạn không có lý do gì để lo lắng, mọi thứ sẽ ổn thôi."},{"t":"para","text":"Giải thích: Причи́на (nguyên nhân/lý do) là danh từ trừu tượng $\\rightarrow$ không dùng liên từ."},{"t":"para","text":"Я не собира́юсь игра́ть в компью́терные и́гры, мне ну́жен компью́тер, что́бы рабо́тать (для рабо́ты);"},{"t":"para","text":"Dịch: Tôi không định chơi điện tử, tôi cần máy tính để làm việc."},{"t":"para","text":"Giải thích: Компью́тер (máy vi tính) là danh từ cụ thể $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Нам ну́жно освободи́ть ко́мнату, что́бы размести́ть госте́й;"},{"t":"para","text":"Dịch: Chúng ta cần dọn trống căn phòng để sắp xếp chỗ (đón) khách."},{"t":"para","text":"Giải thích: Ко́мната (căn phòng) là danh từ cụ thể $\\rightarrow$ dùng что́бы."},{"t":"para","text":"У неё есть тала́нт убежда́ть люде́й в свое́й правоте́;"},{"t":"para","text":"Dịch: Cô ấy có tài năng thuyết phục mọi người về sự đúng đắn của mình."},{"t":"para","text":"Giải thích: Тала́нт (tài năng) là danh từ trừu tượng $\\rightarrow$ không dùng liên từ."},{"t":"para","text":"Э́то раке́тка, что́бы игра́ть в те́ннис, а не в бадминто́н;"},{"t":"para","text":"Dịch: Đây là cái vợt để chơi tennis, chứ không phải cầu lông."},{"t":"para","text":"Giải thích: Раке́тка (cái vợt) là danh từ cụ thể $\\rightarrow$ dùng что́бы."},{"t":"para","text":"В Би́блии ска́зано: есть вре́мя разбра́сывать ка́мни и вре́мя их собира́ть;"},{"t":"para","text":"Dịch: Trong Kinh Thánh có nói: có thời điểm để ném đá và có thời điểm để nhặt chúng lại."},{"t":"para","text":"Giải thích: Вре́мя (thời gian/thời điểm) ở đây mang nghĩa trừu tượng chỉ một giai đoạn/cơ hội $\\rightarrow$ không dùng liên từ."},{"t":"para","text":"Мне никогда́ не нра́вилась его́ привы́чка кома́ндовать;"},{"t":"para","text":"Dịch: Tôi chưa bao giờ thích thói quen ra lệnh (chỉ huy) của anh ấy."},{"t":"para","text":"Giải thích: Привы́чка (thói quen) là danh từ trừu tượng $\\rightarrow$ không dùng liên từ."},{"t":"para","text":"Сего́дня отли́чная пого́да, что́бы пое́хать за́ город (для пое́здки);"},{"t":"para","text":"Dịch: Hôm nay thời tiết tuyệt vời để đi về ngoại ô."},{"t":"para","text":"Giải thích: Пого́да (thời tiết) trong ngữ cảnh này được coi như một điều kiện cụ thể/hoàn cảnh thuận lợi (tương tự các danh từ cụ thể trong cấu trúc mục đích) $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Бою́сь, у меня́ не бу́дет возмо́жности зае́хать к вам по доро́ге домо́й;"},{"t":"para","text":"Dịch: E rằng tôi sẽ không có cơ hội ghé qua chỗ bạn trên đường về nhà."},{"t":"para","text":"Giải thích: Возмо́жность (cơ hội/khả năng) là danh từ trừu tượng $\\rightarrow$ không dùng liên từ."},{"t":"para","text":"Тебе́ ну́жно взять о́тпуск, что́бы отдохну́ть (для о́тдыха);"},{"t":"para","text":"Dịch: Bạn cần xin nghỉ phép để nghỉ ngơi."},{"t":"para","text":"Giải thích: О́тпуск (kỳ nghỉ phép) được coi như một khoảng thời gian/sự kiện cụ thể dành cho mục đích gì đó $\\rightarrow$ dùng что́бы."},{"t":"para","text":"В на́шей лаборато́рии есть тради́ция отмеча́ть дни рожде́ния сотру́дников;"},{"t":"para","text":"Dịch: Ở phòng thí nghiệm của chúng tôi có truyền thống tổ chức mừng sinh nhật các nhân viên."},{"t":"para","text":"Giải thích: Тради́ция (truyền thống) là danh từ trừu tượng $\\rightarrow$ không dùng liên từ."},{"t":"para","text":"С ча́су до двух у вас бу́дет переры́в, что́бы пообе́дать (на обе́д);"},{"t":"para","text":"Dịch: Từ một đến hai giờ các bạn sẽ có giờ nghỉ để ăn trưa."},{"t":"para","text":"Giải thích: Переры́в (giờ nghỉ) là khoảng thời gian cụ thể dành cho mục đích gì $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Я не теря́ю наде́жды встре́титься с ва́ми в сле́дующем году́;"},{"t":"para","text":"Dịch: Tôi không mất hy vọng được gặp các bạn vào năm sau."},{"t":"para","text":"Giải thích: Наде́жда (hy vọng) là danh từ trừu tượng $\\rightarrow$ không dùng liên từ."},{"t":"para","text":"Како́й смысл остава́ться здесь ещё на не́сколько дней?"},{"t":"para","text":"Dịch: Có ý nghĩa gì khi ở lại đây thêm vài ngày nữa?"},{"t":"para","text":"Giải thích: Смысл (ý nghĩa) là danh từ trừu tượng $\\rightarrow$ không dùng liên từ."},{"t":"para","text":"На́до посла́ть телегра́мму, что́бы предупреди́ть их о на́шем прие́зде;"},{"t":"para","text":"Dịch: Cần gửi một bức điện tín để báo trước cho họ về việc chúng ta đến."},{"t":"para","text":"Giải thích: Телегра́мма (bức điện) là danh từ cụ thể $\\rightarrow$ dùng что́бы."},{"t":"para","text":"У тебя́ есть лист бума́ги, что́бы записа́ть но́мер телефо́на?"},{"t":"para","text":"Dịch: Bạn có tờ giấy để ghi số điện thoại không?"},{"t":"para","text":"Giải thích: Лист бума́ги (tờ giấy) là vật thể cụ thể $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Нет необходи́мости прису́тствовать на всех официа́льных мероприя́тиях, доста́точно вы́брать не́сколько из них;"},{"t":"para","text":"Dịch: Không cần thiết (không có sự cần thiết) phải có mặt ở tất cả các sự kiện chính thức, chỉ cần chọn một vài trong số đó là đủ."},{"t":"para","text":"Giải thích: Необходи́мость (sự cần thiết) là danh từ trừu tượng $\\rightarrow$ không dùng liên từ."},{"t":"para","text":"Он при́нял реше́ние уе́хать сра́зу по́сле конфере́нции;"},{"t":"para","text":"Dịch: Anh ấy đã ra quyết định rời đi ngay sau hội nghị."},{"t":"para","text":"Giải thích: Реше́ние (quyết định) là danh từ trừu tượng $\\rightarrow$ không dùng liên từ."},{"t":"para","text":"Вам ну́жно офо́рмить про́пуск, что́бы пройти́ на террито́рию заво́да;"},{"t":"para","text":"Dịch: Bạn cần làm giấy thông hành để đi vào lãnh thổ nhà máy."},{"t":"para","text":"Giải thích: Про́пуск (giấy thông hành/giấy phép ra vào) là vật thể cụ thể $\\rightarrow$ dùng что́бы."},{"t":"para","text":"У нас есть все усло́вия, что́бы рабо́тать (для рабо́ты)."},{"t":"para","text":"Dịch: Chúng tôi có mọi điều kiện để làm việc."},{"t":"para","text":"Giải thích: Усло́вия (điều kiện/cơ sở vật chất) ở đây hàm ý các phương tiện/hoàn cảnh cụ thể cần thiết cho mục đích $\\rightarrow$ dùng что́бы."}]},{"id":"gra-12-s019","type":"exercise","title":"Упражнение 140","num":140,"blocks":[{"t":"para","text":"Mở ngoặc đơn, sử dụng trong câu các động từ nguyên thể hoặc các cấu trúc câu phức với các từ tình thái мочь (có thể), до́лжен (phải), на́до (cần). Giải thích sự lựa chọn của bạn."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Với các danh từ chỉ trạng thái không phụ thuộc vào hoàn cảnh bên ngoài và được quy định bởi phẩm chất cá nhân của chủ thể, động từ nguyên thể được sử dụng (tiếp hợp): жела́ние рабо́тать (mong muốn làm việc)."},{"t":"para","text":"Với các danh từ chỉ cảm xúc gây ra bởi nguyên nhân bên ngoài, các cấu trúc câu phức được sử dụng: недово́льство тем, что... (bất bình với việc...); сомне́ние в том, что... (nghi ngờ về việc...); уве́ренность в том, что... (tin chắc vào việc...); отвраще́ние к тому́, что... (ghê tởm đối với việc...); удивле́ние по по́воду того́, что... (ngạc nhiên về việc...); страх оттого́, что... (sợ hãi vì...); трево́га оттого́, что... (lo âu vì...); ра́дость оттого́, что... (vui mừng vì...)."},{"t":"para","text":"Nếu hành động của các vị ngữ (trong mệnh đề chính và phụ) thuộc về các chủ thể khác nhau, thì với danh từ chỉ trạng thái cũng sử dụng cấu trúc câu phức: У нас одно́ жела́ние — что́бы всё зако́нчилось благополу́чно (Chúng tôi có một mong muốn là mọi việc kết thúc tốt đẹp)."},{"t":"para","text":"Я зна́ю, мой долг оста́ться вме́сте с ним и помо́чь ему́;"},{"t":"instruction","text":"Dịch: Tôi biết, bổn phận của tôi là ở lại cùng anh ấy và giúp đỡ anh ấy."},{"t":"para","text":"Giải thích: Долг (bổn phận/nghĩa vụ) là phẩm chất/trách nhiệm cá nhân $\\rightarrow$ dùng nguyên thể."},{"t":"para","text":"В э́ту ночь страх оттого́, что я могу́ провали́ться на экза́мене, не дава́л мне ни мину́ты поко́я;"},{"t":"para","text":"Dịch: Đêm hôm đó nỗi sợ hãi vì việc tôi có thể thi trượt đã không để tôi yên phút nào."},{"t":"para","text":"Giải thích: Страх (nỗi sợ) là cảm xúc do nguyên nhân bên ngoài (khả năng thi trượt) $\\rightarrow$ câu phức (страх оттого́, что...)."},{"t":"para","text":"И хотя́ связь с гео́логами была́ поте́ряна, нас не покида́ла наде́жда спасти́ их;"},{"t":"para","text":"Dịch: Và mặc dù liên lạc với các nhà địa chất đã mất, hy vọng cứu họ vẫn không rời bỏ chúng tôi."},{"t":"para","text":"Giải thích: Наде́жда (hy vọng) ở đây là trạng thái nội tâm/mong muốn thực hiện hành động $\\rightarrow$ dùng nguyên thể."},{"t":"para","text":"То́лько в конце́ рабо́ты у меня́ появи́лась уве́ренность в том, что я смогу́ дости́чь результа́тов;"},{"t":"para","text":"Dịch: Chỉ đến cuối công việc tôi mới có sự tin chắc rằng tôi sẽ có thể đạt được kết quả."},{"t":"para","text":"Giải thích: Уве́ренность (sự tin chắc) vào một kết quả/sự kiện $\\rightarrow$ câu phức (уве́ренность в том, что...)."},{"t":"para","text":"У меня́ не́ было сомне́ний в том, что на́до продо́лжить на́чатые иссле́дования;"},{"t":"para","text":"Dịch: Tôi không có nghi ngờ gì về việc cần phải tiếp tục các nghiên cứu đã bắt đầu."},{"t":"para","text":"Giải thích: Сомне́ние (sự nghi ngờ) về tính đúng đắn/cần thiết của hành động $\\rightarrow$ câu phức (сомне́ний в том, что...)."},{"t":"para","text":"Я име́ю удово́льствие предста́вить вам своего́ лу́чшего дру́га;"},{"t":"para","text":"Dịch: Tôi hân hạnh (có niềm hân hạnh) được giới thiệu với các bạn người bạn thân nhất của tôi."},{"t":"para","text":"Giải thích: Удово́льствие (hân hạnh/khoái cảm) là trạng thái cá nhân khi thực hiện hành động $\\rightarrow$ dùng nguyên thể."},{"t":"para","text":"Да́же при са́мом си́льном отвраще́нии к тому́, что он до́лжен сде́лать, он никогда́ не демонстри́ровал свои́х эмо́ций;"},{"t":"para","text":"Dịch: Ngay cả khi có sự ghê tởm mạnh mẽ nhất đối với việc anh ta phải làm, anh ta cũng không bao giờ thể hiện cảm xúc của mình."},{"t":"para","text":"Giải thích: Отвраще́ние (sự ghê tởm/ác cảm) đối với một sự việc bắt buộc bên ngoài $\\rightarrow$ câu phức (отвраще́нии к тому́, что...)."},{"t":"para","text":"Обя́занность ста́росты гру́ппы вести́ журна́л и отмеча́ть в нём всех прису́тствующих и отсу́тствующих на заня́тиях дово́льно обремени́тельна;"},{"t":"para","text":"Dịch: Nhiệm vụ của lớp trưởng là giữ sổ đầu bài và ghi lại trong đó tất cả những người có mặt và vắng mặt trong buổi học khá là phiền toái."},{"t":"para","text":"Giải thích: Обя́занность (nhiệm vụ/nghĩa vụ) là chức năng/trách nhiệm cá nhân $\\rightarrow$ dùng nguyên thể."},{"t":"para","text":"И хотя́ всё шло норма́льно, меня́ не покида́ло чу́вство трево́ги оттого́, что я могу́ ошиби́ться и́ли пропусти́ть что́-то са́мое ва́жное;"},{"t":"para","text":"Dịch: Và mặc dù mọi thứ diễn ra bình thường, cảm giác lo âu vì việc tôi có thể mắc sai lầm hoặc bỏ sót điều gì đó quan trọng nhất vẫn không rời bỏ tôi."},{"t":"para","text":"Giải thích: Трево́га (sự lo âu) do nguyên nhân/nguy cơ bên ngoài $\\rightarrow$ câu phức (трево́ги оттого́, что...)."},{"t":"para","text":"У неё не́ было твёрдой уве́ренности ула́дить э́то де́ло без посторо́нней по́мощи;"},{"t":"para","text":"Dịch: Cô ấy không có sự tự tin vững chắc (để) giải quyết vụ việc này mà không cần sự giúp đỡ bên ngoài."},{"t":"para","text":"Giải thích: Ở đây уве́ренность (sự tự tin) được coi như một phẩm chất/năng lực cá nhân để thực hiện hành động $\\rightarrow$ dùng nguyên thể (theo đáp án sách). (Lưu ý: Cũng có thể dùng câu phức \"уверенности в том, что она сможет уладить\", nhưng sách chọn nguyên thể cho trường hợp này để nhấn mạnh năng lực chủ quan)."},{"t":"para","text":"Возни́кшая необходи́мость прерва́ть на́чатую рабо́ту и заня́ться други́ми неотло́жными дела́ми о́чень меня́ расстро́ила;"},{"t":"para","text":"Dịch: Sự cần thiết nảy sinh phải ngắt quãng công việc đang làm dở và bắt tay vào những việc khẩn cấp khác đã làm tôi rất buồn."},{"t":"para","text":"Giải thích: Необходи́мость (sự cần thiết) là tình thế bắt buộc/yêu cầu khách quan $\\rightarrow$ dùng nguyên thể."},{"t":"para","text":"Ра́дость оттого́, что он смо́жет встре́титься и говори́ть с э́тим челове́ком, переполня́ла его́ се́рдце;"},{"t":"para","text":"Dịch: Niềm vui vì việc anh ấy sẽ có thể gặp và nói chuyện với người này tràn ngập trái tim anh."},{"t":"para","text":"Giải thích: Ра́дость (niềm vui) do một sự kiện/nguyên nhân $\\rightarrow$ câu phức (ра́дость оттого́, что...)."},{"t":"para","text":"Рабо́та ему́ надое́ла, и вре́мя от вре́мени у него́ начала́ появля́ться мысль бро́сить всё и уе́хать;"},{"t":"para","text":"Dịch: Anh ấy đã chán công việc, và thỉnh thoảng anh ấy bắt đầu xuất hiện ý nghĩ bỏ tất cả và ra đi."},{"t":"para","text":"Giải thích: Мысль (ý nghĩ/ý định) thuộc về chủ thể $\\rightarrow$ dùng nguyên thể."},{"t":"para","text":"Он не раз выража́л недово́льство тем, что он до́лжен рабо́тать в ночну́ю сме́ну;"},{"t":"para","text":"Dịch: Anh ấy đã không ít lần bày tỏ sự bất mãn về việc anh ấy phải làm việc ca đêm."},{"t":"para","text":"Giải thích: Недово́льство (sự bất mãn) đối với hoàn cảnh bên ngoài $\\rightarrow$ câu phức (недово́льство тем, что...)."},{"t":"para","text":"В разгово́ре со мно́й он вы́сказал удивле́ние по по́воду того́, что он до́лжен занима́ться тако́й неквалифици́рованной рабо́той."},{"t":"para","text":"Dịch: Trong cuộc nói chuyện với tôi, anh ấy đã bày tỏ sự ngạc nhiên về việc anh ấy phải làm công việc không cần chuyên môn như vậy."},{"t":"para","text":"Giải thích: Удивле́ние (sự ngạc nhiên) đối với sự việc bên ngoài $\\rightarrow$ câu phức (удивле́ние по по́воду того́, что...)."}]},{"id":"gra-12-s020","type":"exercise","title":"Примыкание к существительному (Sự tiếp hợp với danh từ)","num":null,"blocks":[]},{"id":"gra-12-s021","type":"exercise","title":"Упражнение 141","num":141,"blocks":[{"t":"para","text":"Sử dụng các cấu trúc với động từ nguyên thể hoặc các câu phức với liên từ что hoặc что́бы, hãy kết hợp hai câu thành một."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Với các danh từ chỉ trạng thái không phụ thuộc vào hoàn cảnh bên ngoài và được quy định bởi phẩm chất cá nhân của chủ thể, động từ nguyên thể được sử dụng (tiếp hợp): жела́ние рабо́тать (mong muốn làm việc)."},{"t":"para","text":"Với các danh từ chỉ cảm xúc gây ra bởi nguyên nhân bên ngoài, các cấu trúc câu phức được sử dụng: недово́льство тем, что... (bất bình với việc...); сомне́ние в том, что... (nghi ngờ về việc...); уве́ренность в том, что... (tin chắc vào việc...); отвраще́ние к тому́, что... (ghê tởm đối với việc...); удивле́ние по по́воду того́, что... (ngạc nhiên về việc...); опасе́ние по по́воду того́, что... (lo ngại về việc...); страх оттого́, что... (sợ hãi vì...); трево́га оттого́, что... (lo âu vì...); ра́дость оттого́, что... (vui mừng vì...)."},{"t":"para","text":"Nếu hành động của các vị ngữ (trong mệnh đề chính và phụ) thuộc về các chủ thể khác nhau, thì với danh từ chỉ trạng thái cũng sử dụng cấu trúc câu phức: У нас одно́ жела́ние — что́бы всё зако́нчилось благополу́чно (Chúng tôi có một mong muốn là mọi việc kết thúc tốt đẹp)."},{"t":"para","text":"У меня́ есть наде́жда, что они́ пойму́т меня́ пра́вильно;"},{"t":"instruction","text":"Dịch: Tôi có hy vọng rằng họ sẽ hiểu tôi đúng."},{"t":"para","text":"Giải thích: Chủ ngữ của hai mệnh đề khác nhau (Tôi hy vọng - Họ hiểu) $\\rightarrow$ Dùng câu phức với liên từ что (diễn tả niềm tin/hy vọng vào sự việc)."},{"t":"para","text":"Он вы́сказал предложе́ние зако́нчить (что́бы мы зако́нчили) рабо́ту на час ра́ньше сро́ка;"},{"t":"para","text":"Dịch: Anh ấy đã đưa ra đề nghị kết thúc (để chúng ta kết thúc) công việc sớm hơn thời hạn một tiếng."},{"t":"para","text":"Giải thích: Đề nghị thực hiện hành động chung $\\rightarrow$ Dùng động từ nguyên thể зако́нчить hoặc liên từ что́бы."},{"t":"para","text":"Иногда́ у меня́ появля́ется потре́бность в том, что́бы меня́ вы́слушали;"},{"t":"para","text":"Dịch: Thỉnh thoảng tôi nảy sinh nhu cầu được người ta lắng nghe."},{"t":"para","text":"Giải thích: Hành động \"nghe\" do người khác thực hiện (câu thụ động/vô nhân), khác chủ thể \"tôi\" $\\rightarrow$ Dùng câu phức với что́бы (mong muốn điều đó xảy ra)."},{"t":"para","text":"У них нет причи́н беспоко́иться;"},{"t":"para","text":"Dịch: Họ không có lý do gì để lo lắng."},{"t":"para","text":"Giải thích: Chủ thể là \"họ\" trong cả hai vế, причи́на (lý do) thường đi với nguyên thể $\\rightarrow$ Dùng động từ nguyên thể беспоко́иться."},{"t":"para","text":"На́до найти́ по́вод, что́бы они́ оста́лись;"},{"t":"para","text":"Dịch: Cần tìm cái cớ để họ ở lại."},{"t":"para","text":"Giải thích: Chủ thể khác nhau (Chúng ta tìm cớ - Họ ở lại) $\\rightarrow$ Dùng liên từ что́бы."},{"t":"para","text":"У нас появи́лась наде́жда найти́ доро́гу;"},{"t":"para","text":"Dịch: Chúng tôi đã xuất hiện hy vọng tìm thấy đường."},{"t":"para","text":"Giải thích: Cùng chủ thể (chúng tôi), trạng thái nội tâm $\\rightarrow$ Dùng động từ nguyên thể найти́."},{"t":"para","text":"Уча́стники конфере́нции вы́сказали пожела́ние прие́хать сюда́ в сле́дующем году́;"},{"t":"para","text":"Dịch: Các thành viên tham gia hội nghị đã bày tỏ nguyện vọng sẽ đến đây vào năm sau."},{"t":"para","text":"Giải thích: Cùng chủ thể, mong muốn thực hiện hành động $\\rightarrow$ Dùng động từ nguyên thể прие́хать."},{"t":"para","text":"Кто́-то вы́сказал иде́ю объедини́ть на́ши уси́лия;"},{"t":"para","text":"Dịch: Ai đó đã đưa ra ý tưởng hợp nhất nỗ lực của chúng ta."},{"t":"para","text":"Giải thích: Ý tưởng thực hiện hành động $\\rightarrow$ Dùng động từ nguyên thể объедини́ть."},{"t":"para","text":"Нет никако́й наде́жды (на то), что они́ изме́нят своё реше́ние;"},{"t":"para","text":"Dịch: Không có hy vọng gì về việc họ sẽ thay đổi quyết định của mình."},{"t":"para","text":"Giải thích: Hy vọng về một sự kiện khách quan (người khác làm) $\\rightarrow$ Dùng câu phức với что."},{"t":"para","text":"Он вы́сказал пожела́ние, что́бы мы встре́тились че́рез ме́сяц;"},{"t":"para","text":"Dịch: Anh ấy đã bày tỏ mong muốn (để) chúng tôi gặp nhau sau một tháng."},{"t":"para","text":"Giải thích: Chủ thể khác nhau (Anh ấy muốn - Chúng tôi gặp) $\\rightarrow$ Dùng liên từ что́бы."},{"t":"para","text":"По́сле о́тпуска ко мне́ верну́лось жела́ние продолжа́ть рабо́ту;"},{"t":"para","text":"Dịch: Sau kỳ nghỉ, mong muốn tiếp tục công việc đã quay lại với tôi."},{"t":"para","text":"Giải thích: Trạng thái nội tâm của chủ thể $\\rightarrow$ Dùng động từ nguyên thể продолжа́ть."},{"t":"para","text":"Како́е сча́стье, что мы вновь вме́сте!"},{"t":"para","text":"Dịch: Thật hạnh phúc (rằng) chúng ta lại ở bên nhau!"},{"t":"para","text":"Giải thích: Cảm xúc về một sự việc thực tế đã xảy ra $\\rightarrow$ Dùng liên từ что."},{"t":"para","text":"Мне не дава́ла поко́я мысль, что он мо́жет опозда́ть на по́езд."},{"t":"para","text":"Dịch: Ý nghĩ rằng cậu ấy có thể bị trễ tàu đã làm tôi không yên."},{"t":"para","text":"Giải thích: Suy nghĩ về một sự kiện (có thể) xảy ra $\\rightarrow$ Dùng liên từ что."}]},{"id":"gra-12-s022","type":"exercise","title":"Упражнение 142","num":142,"blocks":[{"t":"para","text":"Thay thế vào chỗ trống các danh từ được tạo từ động từ ở cách cần thiết. Hãy chú ý đến cách mà các danh từ nhóm a) yêu cầu, và các giới từ được sử dụng với các danh từ nhóm б)."},{"t":"subhead","text":"а) (Sự tiếp hợp với danh từ không giới từ - Cách 2)"},{"t":"para","text":"Свобо́да выбира́ть — свобо́да вы́бора; (Tự do lựa chọn)"},{"t":"para","text":"Ра́дость твори́ть — ра́дость тво́рчества; (Niềm vui sáng tạo)"},{"t":"para","text":"Тала́нт убежда́ть — тала́нт убежде́ния; (Tài năng thuyết phục)"},{"t":"para","text":"Дар предви́деть — дар предви́дения; (Món quà/khả năng tiên đoán)"},{"t":"para","text":"Мане́ра обща́ться — мане́ра обще́ния; (Phong thái giao tiếp)"},{"t":"para","text":"Вре́мя рабо́тать — вре́мя рабо́ты (hoặc вре́мя на рабо́ту); (Thời gian làm việc)"},{"t":"para","text":"Смысл разгова́ривать — смысл разгово́ра; (Ý nghĩa cuộc trò chuyện)"},{"t":"para","text":"Тради́ция крести́ть — тради́ция креще́ния. (Truyền thống rửa tội)"},{"t":"subhead","text":"б) (Sự điều khiển với giới từ)"},{"t":"para","text":"Наде́жда победи́ть — наде́жда на побе́ду; (Hy vọng chiến thắng - giới từ на + Cách 4)"},{"t":"para","text":"Шанс вы́играть — шанс на вы́игрыш; (Cơ hội thắng - giới từ на + Cách 4)"},{"t":"para","text":"Пра́во отдыха́ть — пра́во на о́тдых; (Quyền nghỉ ngơi - giới từ на + Cách 4)"},{"t":"para","text":"Реше́ние измени́ть — реше́ние об измене́нии; (Quyết định thay đổi - giới từ о/об + Cách 6)"},{"t":"para","text":"Мысль возврати́ться — мысль о возвраще́нии; (Suy nghĩ về việc trở về - giới từ о + Cách 6)"},{"t":"para","text":"Иде́я объедини́ться — иде́я об объедине́нии (hoặc иде́я объедине́ния); (Ý tưởng hợp nhất - giới từ о + Cách 6)"},{"t":"para","text":"Удово́льствие труди́ться — удово́льствие от труда́; (Sự hài lòng từ lao động - giới từ от + Cách 2)"},{"t":"para","text":"Сча́стье встре́титься — сча́стье от встре́чи; (Hạnh phúc vì cuộc gặp - giới từ от + Cách 2)"},{"t":"para","text":"Основа́ние беспоко́иться — основа́ния для беспоко́йства; (Cơ sở để lo lắng - giới từ для + Cách 2)"},{"t":"para","text":"Му́жество сопротивля́ться — му́жество для сопротивле́ния; (Dũng khí để phản kháng - giới từ для + Cách 2)"},{"t":"para","text":"Страх потеря́ть — страх пе́ред поте́рей; (Nỗi sợ mất mát - giới từ перед + Cách 5)"},{"t":"para","text":"Потре́бность обсужда́ть — потре́бность в обсужде́нии. (Nhu cầu thảo luận - giới từ в + Cách 6)"}]},{"id":"gra-12-s023","type":"exercise","title":"Упражнение 143","num":143,"blocks":[{"t":"instruction","text":"Thay thế vào chỗ trống động từ nguyên thể hoặc danh từ với các giới từ cần thiết theo ngữ nghĩa. Giải thích sự lựa chọn của bạn, chỉ ra các phương án."},{"t":"para","text":"Я не ви́жу смы́сла спо́рить (в спо́ре) с тобо́й по э́тому вопро́су. О́чень ча́сто смысл спо́ра заключа́ется в само́м спо́ре;"},{"t":"para","text":"Dịch: Tôi không thấy ý nghĩa của việc tranh luận (trong cuộc tranh luận) với bạn về vấn đề này. Rất thường xuyên, ý nghĩa của cuộc tranh luận nằm ở chính cuộc tranh luận đó."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: не вижу смысла (в чём?) $\\rightarrow$ в споре hoặc dùng động từ nguyên thể спорить (làm gì)."},{"t":"para","text":"Vế 2: смысл (чего?) $\\rightarrow$ спора (Cách 2 - danh từ bổ nghĩa)."},{"t":"para","text":"Мы рабо́тали су́тки напролёт, у нас не́ было вре́мени отдыха́ть (на о́тдых). Когда́ рабо́таешь день и ночь, совсе́м не остаётся вре́мени на о́тдых (для о́тдыха);"},{"t":"para","text":"Dịch: Chúng tôi đã làm việc suốt ngày đêm, chúng tôi không có thời gian nghỉ ngơi (cho việc nghỉ ngơi). Khi làm việc ngày đêm, hoàn toàn không còn thời gian cho việc nghỉ ngơi."},{"t":"para","text":"Giải thích: Время có thể đi với nguyên thể (отдыхать) hoặc giới từ chỉ mục đích на/для + danh từ (на отдых)."},{"t":"para","text":"В любо́й ситуа́ции всегда́ остаётся возмо́жность помири́ться (примире́ния). Я предоста́вил вам возмо́жность для примире́ния (помири́ться), жаль, что вы е́ю так не воспо́льзовались;"},{"t":"para","text":"Dịch: Trong bất kỳ tình huống nào luôn còn khả năng làm hòa (sự hòa giải). Tôi đã cho các bạn cơ hội để hòa giải (làm hòa), tiếc là các bạn đã không tận dụng nó."},{"t":"para","text":"Giải thích: Возможность kết hợp với nguyên thể hoặc danh từ (thường ở Cách 2 không giới từ hoặc với для)."},{"t":"para","text":"Цель всегда́ одна́, но спо́собы её осуществле́ния мо́гут быть ра́зными. Я не ви́жу спо́соба осуществи́ть э́тот прое́кт;"},{"t":"para","text":"Dịch: Mục tiêu luôn là một, nhưng các cách thức thực hiện nó có thể khác nhau. Tôi không thấy cách nào để thực hiện dự án này."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: Có từ её (của nó - giống cái, thay cho цель) nên cần danh từ осуществления (Cách 2)."},{"t":"para","text":"Vế 2: способа (что сделать?) $\\rightarrow$ осуществить (nguyên thể)."},{"t":"para","text":"Мне пришла́ в го́лову иде́я объедини́ть на́ши уси́лия в совме́стной рабо́те. Иде́я объедине́ния (об объедине́нии) Росси́и и Белору́ссии обсужда́лась в тече́ние мно́гих лет на госуда́рственном у́ровне;"},{"t":"para","text":"Dịch: Tôi nảy ra ý tưởng hợp nhất những nỗ lực của chúng ta trong công việc chung. Ý tưởng về sự hợp nhất (sự hợp nhất) của Nga và Belarus đã được thảo luận trong nhiều năm ở cấp nhà nước."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: Ý tưởng làm gì $\\rightarrow$ объединить."},{"t":"para","text":"Vế 2: Ý tưởng về cái gì/của cái gì $\\rightarrow$ объединения / об объединении."},{"t":"para","text":"Твоё реше́ние уво́литься с рабо́ты ка́жется мне необду́манным. Е́сли челове́к принима́ет реше́ние об увольне́нии (уво́литься), зна́чит у него́ не оста́лось друго́го спо́соба реши́ть свои́ пробле́мы;"},{"t":"para","text":"Dịch: Quyết định thôi việc của bạn có vẻ thiếu suy nghĩ đối với tôi. Nếu một người đưa ra quyết định về việc sa thải (thôi việc), có nghĩa là anh ta không còn cách nào khác để giải quyết vấn đề của mình."},{"t":"para","text":"Giải thích: Решение thường đi với nguyên thể hoặc giới từ о + Cách 6 (об увольнении)."},{"t":"para","text":"Я ду́маю, нет необходи́мости обсужда́ть э́тот вопро́с ещё раз. Необходи́мость в обсужде́нии (обсужде́ния) всегда́ прису́тствует."},{"t":"para","text":"Dịch: Tôi nghĩ không cần thiết (không có sự cần thiết) phải thảo luận vấn đề này thêm lần nữa. Sự cần thiết trong việc thảo luận (của sự thảo luận) luôn hiện hữu."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: Нет необходимости + nguyên thể (обсуждать)."},{"t":"para","text":"Vế 2: Необходимость (như chủ ngữ) + в + Cách 6 (в обсуждении) hoặc Cách 2 (обсуждения)."}]},{"id":"gra-12-s024","type":"exercise","title":"Примыкание к существительному (Sự tiếp hợp với danh từ)","num":null,"blocks":[]},{"id":"gra-12-s025","type":"exercise","title":"Упражнение 144","num":144,"blocks":[{"t":"instruction","text":"Mở ngoặc đơn, sử dụng động từ nguyên thể hoặc danh từ ở dạng cần thiết theo ngữ nghĩa. Giải thích sự lựa chọn của bạn."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Việc sử dụng động từ nguyên thể hay danh từ khi kết hợp với các danh từ mang ý nghĩa trừu tượng phụ thuộc vào cấu trúc câu."},{"t":"para","text":"Khi diễn đạt một hành động cụ thể, động từ nguyên thể thường được sử dụng: У нас остава́лась после́дняя наде́жда спасти́ их (Chúng tôi còn lại hy vọng cuối cùng là cứu được họ)."},{"t":"para","text":"Khi diễn đạt một hành động có khả năng xảy ra (tiềm năng), danh từ được sử dụng: В любо́й ситуа́ции всегда́ остаётся наде́жда на спасе́ние (Trong bất kỳ tình huống nào luôn còn hy vọng vào sự giải cứu)."},{"t":"para","text":"Nếu không thể tạo danh từ từ động từ, động từ nguyên thể được sử dụng: Твоя́ мане́ра перебива́ть собесе́дника меня́ раздража́ет (Thói quen ngắt lời người đối thoại của bạn làm tôi khó chịu)."},{"t":"para","text":"Trong vai trò định ngữ (bổ nghĩa), các danh từ thường được sử dụng nhất: Уве́ренность в побе́де не покида́ла нас ни на мину́ту (Niềm tin vào chiến thắng không rời bỏ chúng tôi phút nào) — niềm tin nào? niềm tin vào chiến thắng,."},{"t":"para","text":"Ра́дость встре́чи (встре́титься, встре́ча) была́ омрачена́ изве́стием о вчера́шнем траги́ческом происше́ствии;"},{"t":"para","text":"Dịch: Niềm vui của cuộc gặp gỡ đã bị lu mờ bởi tin tức về sự kiện bi thảm hôm qua."},{"t":"para","text":"Giải thích: Sử dụng danh từ встре́чи (Cách 2 - Sinh cách) vì nó diễn tả một sự kiện/trạng thái đã được định danh, đóng vai trò định ngữ cho \"niềm vui\"."},{"t":"para","text":"Немно́гие взро́слые облада́ют тала́нтом обще́ния (обща́ться, обще́ние) с детьми́;"},{"t":"para","text":"Dịch: Không nhiều người lớn sở hữu tài năng giao tiếp với trẻ em."},{"t":"para","text":"Giải thích: Sử dụng danh từ обще́ния (Cách 2) vì nó chỉ một kỹ năng tổng quát, một khái niệm trừu tượng (tài năng của việc giao tiếp)."},{"t":"para","text":"Мысль верну́ться (верну́ться, возвраще́ние) и нача́ть всё снача́ла не дава́ла ему́ поко́я;"},{"t":"para","text":"Dịch: Ý nghĩ quay trở lại và bắt đầu mọi thứ lại từ đầu đã không để cho anh ấy yên."},{"t":"para","text":"Giải thích: Sử dụng động từ nguyên thể верну́ться vì nó diễn tả một ý định hành động cụ thể của chủ thể (ý nghĩ làm gì?)."},{"t":"para","text":"Я зна́ю, как нелегко́ бы́ло тебе́ приня́ть реше́ние уе́хать (уе́хать, отъе́зд);"},{"t":"para","text":"Dịch: Tôi biết thật không dễ dàng cho bạn khi đưa ra quyết định ra đi (rời đi)."},{"t":"para","text":"Giải thích: Sử dụng động từ nguyên thể уе́хать để chỉ hành động cụ thể được quyết định (quyết định làm gì?)."},{"t":"para","text":"Мы говори́м на одно́м языке́, но в ка́ждом регио́не есть свои́ осо́бенности произноше́ния (произноси́ть, произноше́ние);"},{"t":"para","text":"Dịch: Chúng ta nói cùng một ngôn ngữ, nhưng ở mỗi vùng đều có những đặc điểm phát âm riêng."},{"t":"para","text":"Giải thích: Sử dụng danh từ произноше́ния (Cách 2) vì nó chỉ một đặc điểm, khái niệm (đặc điểm của cái gì? của sự phát âm)."},{"t":"para","text":"Возмо́жность переме́н (перемени́ть, переме́ны) в жи́зни одновре́менно ра́довала и пуга́ла его́;"},{"t":"para","text":"Dịch: Khả năng (về những) thay đổi trong cuộc sống đồng thời vừa làm anh ấy vui vừa làm anh ấy sợ."},{"t":"para","text":"Giải thích: Sử dụng danh từ переме́н (Cách 2 số nhiều) vì nó chỉ sự việc tiềm năng, trạng thái thay đổi nói chung."},{"t":"para","text":"Мне не нра́вится его́ привы́чка спо́рить (спо́рить, спор) по любо́му по́воду;"},{"t":"para","text":"Dịch: Tôi không thích thói quen tranh luận về bất cứ cớ gì của anh ấy."},{"t":"para","text":"Giải thích: Sử dụng động từ nguyên thể спо́рить vì nó chỉ một hành động lặp đi lặp lại tạo thành thói quen (thói quen làm gì?)."},{"t":"para","text":"Мы мо́жем измени́ть вре́мя рабо́ты (рабо́тать, рабо́та) по ва́шему усмотре́нию;"},{"t":"para","text":"Dịch: Chúng tôi có thể thay đổi thời gian làm việc theo ý muốn của bạn."},{"t":"para","text":"Giải thích: Sử dụng danh từ рабо́ты (Cách 2) để chỉ khoảng thời gian dành cho một hoạt động/khái niệm (giờ làm việc)."},{"t":"para","text":"По-мо́ему, ей здесь непло́хо и нет смы́сла иска́ть (иска́ть, по́иски) но́вое ме́сто рабо́ты;"},{"t":"para","text":"Dịch: Theo tôi, cô ấy ở đây không tệ và không có ý nghĩa gì để tìm kiếm một chỗ làm mới."},{"t":"para","text":"Giải thích: Sử dụng động từ nguyên thể иска́ть vì trong cấu trúc phủ định \"нет смысла\" thường đi kèm với động từ chỉ hành động không cần thiết phải thực hiện."},{"t":"para","text":"Не ка́ждый мо́жет возрази́ть нача́льству, ну́жно име́ть му́жество сопротивля́ться (сопротивля́ться, сопротивле́ние);"},{"t":"para","text":"Dịch: Không phải ai cũng có thể phản đối ban lãnh đạo, cần phải có lòng dũng cảm để phản kháng."},{"t":"para","text":"Giải thích: Sử dụng động từ nguyên thể сопротивля́ться để chỉ hành động cụ thể đòi hỏi phẩm chất (dũng khí để làm gì?)."},{"t":"para","text":"Како́й смысл разгово́ра (разгова́ривать, разгово́р) на э́ту те́му в его́ отсу́тствие?"},{"t":"para","text":"Dịch: Ý nghĩa của cuộc trò chuyện về chủ đề này khi anh ấy vắng mặt là gì?"},{"t":"para","text":"Giải thích: Sử dụng danh từ разгово́ра (Cách 2) vì câu hỏi hướng vào bản chất/sự tồn tại của sự việc (cuộc nói chuyện). (Lưu ý: Cũng có thể dùng \"смысл разговаривать\" nhưng đáp án sách chọn danh từ)."},{"t":"para","text":"У любо́го из нас всегда́ есть свобо́да вы́бора (выбира́ть, вы́бора), по э́тому реше́ние остаётся за ва́ми;"},{"t":"para","text":"Dịch: Bất kỳ ai trong chúng ta cũng luôn có tự do lựa chọn, vì thế quyết định thuộc về các bạn."},{"t":"para","text":"Giải thích: Sử dụng danh từ вы́бора (Cách 2) vì \"свобода выбора\" là một cụm từ cố định chỉ khái niệm."},{"t":"para","text":"На́до призна́ть, что в э́том турни́ре твои́ ша́нсы на побе́ду (победи́ть, побе́да) невелики́;"},{"t":"para","text":"Dịch: Phải thừa nhận rằng trong giải đấu này cơ hội chiến thắng (vào chiến thắng) của bạn là không lớn."},{"t":"para","text":"Giải thích: Sử dụng danh từ với giới từ на побе́ду (Cách 4) vì từ \"шанс\" thường đi với cấu trúc \"на что?\" để chỉ khả năng đạt được điều gì."},{"t":"para","text":"Тепе́рь ему́ бы́ло знако́мо сча́стье возвраще́ния (верну́ться, возвраще́ние) домо́й по́сле сто́льких лет разлу́ки;"},{"t":"para","text":"Dịch: Giờ đây anh ấy đã biết đến niềm hạnh phúc của sự trở về nhà sau bấy nhiêu năm xa cách."},{"t":"para","text":"Giải thích: Sử dụng danh từ возвраще́ния (Cách 2) để chỉ khái niệm/trạng thái hạnh phúc do sự kiện đó mang lại."},{"t":"para","text":"Положе́ние бы́ло крити́ческим, но остава́лась наде́жда на исцеле́ние (исцели́ться, исцеле́ние);"},{"t":"para","text":"Dịch: Tình hình rất nguy kịch, nhưng vẫn còn hy vọng vào sự bình phục."},{"t":"para","text":"Giải thích: Sử dụng danh từ với giới từ на исцеле́ние (Cách 4) vì diễn tả niềm hy vọng vào một kết quả tiềm năng (như gợi ý ngữ pháp đã nêu)."},{"t":"para","text":"Пра́во избира́ть (избира́ть, избра́ние) явля́ется неотъе́млемым пра́вом гра́ждан;"},{"t":"para","text":"Dịch: Quyền bầu cử là quyền không thể tách rời của công dân."},{"t":"para","text":"Giải thích: Sử dụng động từ nguyên thể избира́ть vì đây là quyền thực hiện hành động."},{"t":"para","text":"Мысль о жени́тьбе (жени́ться, жени́тьба) не раз приходи́ла ему́ в го́лову."},{"t":"para","text":"Dịch: Suy nghĩ về việc kết hôn đã không ít lần xuất hiện trong đầu anh ấy."},{"t":"para","text":"Giải thích: Sử dụng danh từ với giới từ о жени́тьбе (Cách 6) vì từ \"мысль\" thường đi với giới từ \"о\" khi nói về đề tài suy nghĩ."}]},{"id":"gra-12-s026","type":"exercise","title":"Примыкание к местоимению, прилагательному, наречию (Sự tiếp hợp với đại từ, tính từ, trạng từ)","num":null,"blocks":[]},{"id":"gra-12-s027","type":"exercise","title":"Упражнение 145","num":145,"blocks":[{"t":"instruction","text":"Đọc các cụm từ. Hãy chú ý đến các từ phụ thuộc đi kèm với đại từ, tính từ và trạng từ trong trường hợp liên kết tiếp hợp."},{"t":"para","text":"1. Примыкание к местоимению (Sự tiếp hợp với đại từ)"},{"t":"subhead","text":"а) наречия (trạng từ):"},{"t":"para","text":"абсолю́тно никто́: hoàn toàn không ai cả."},{"t":"para","text":"совсе́м ничто́: hoàn toàn không có gì."},{"t":"para","text":"соверше́нно ничего́: hoàn toàn không gì cả."},{"t":"para","text":"почти́ ничего́: hầu như không có gì."},{"t":"subhead","text":"б) сравнительной степени прилагательного (tính từ so sánh hơn):"},{"t":"para","text":"кто́-то поста́рше: ai đó lớn tuổi hơn."},{"t":"para","text":"кто́-нибудь поо́пытнее: ai đó có kinh nghiệm hơn."},{"t":"para","text":"не́что полу́чше: cái gì đó tốt hơn."},{"t":"para","text":"2. Примыкание к прилагательному (причастию) (Sự tiếp hợp với tính từ / động tính từ)"},{"t":"subhead","text":"а) наречия (trạng từ):"},{"t":"para","text":"о́чень вы́годный: rất có lợi."},{"t":"para","text":"весьма́ опа́сный: rất nguy hiểm."},{"t":"para","text":"экономи́чески незави́симый: độc lập về kinh tế."},{"t":"para","text":"необыча́йно ревни́вый: ghen tuông lạ thường."},{"t":"para","text":"абсолю́тно здоро́вый: hoàn toàn khỏe mạnh."},{"t":"para","text":"по-де́тски откры́тый: cởi mở như trẻ con."},{"t":"para","text":"совсе́м ти́хий: hoàn toàn yên tĩnh."},{"t":"para","text":"доста́точно у́мный: đủ thông minh."},{"t":"para","text":"соверше́нно избало́ванный: hoàn toàn bị nuông chiều."},{"t":"para","text":"почти́ чёрный: gần như màu đen."},{"t":"para","text":"чуть-чу́ть не́рвный: hơi nóng nảy một chút."},{"t":"para","text":"немно́го (немно́жко) помя́тый: hơi nhàu một chút."},{"t":"para","text":"сли́шком гро́мкий: quá ồn ào/to."},{"t":"subhead","text":"б) инфинитива (động từ nguyên thể):"},{"t":"para","text":"сча́стлив ви́деть: hạnh phúc khi được thấy."},{"t":"para","text":"до́лжен уе́хать: phải rời đi."},{"t":"para","text":"наме́рен договори́ться: có ý định thỏa thuận."},{"t":"para","text":"рад познако́миться: vui mừng được làm quen."},{"t":"para","text":"гото́в отвеча́ть: sẵn sàng trả lời."},{"t":"para","text":"спосо́бен вы́полнить: có khả năng thực hiện."},{"t":"para","text":"свобо́ден выбира́ть: tự do lựa chọn."},{"t":"para","text":"обя́зан зако́нчить: có nghĩa vụ hoàn thành."},{"t":"para","text":"приу́чен убира́ть: được dạy (quen với việc) dọn dẹp."},{"t":"para","text":"3. Примыкание к наречию (Sự tiếp hợp với trạng từ)"},{"t":"subhead","text":"а) наречия (trạng từ):"},{"t":"para","text":"недопусти́мо ма́ло: ít đến mức không thể chấp nhận được."},{"t":"para","text":"необыча́йно ве́село: vui vẻ lạ thường."},{"t":"para","text":"по-вече́рнему ти́хо: yên tĩnh như buổi chiều."},{"t":"para","text":"а́дски тру́дно: khó kinh khủng (khó như địa ngục)."},{"t":"para","text":"сли́шком сло́жно: quá phức tạp."},{"t":"para","text":"немно́го хо́лодно: hơi lạnh."},{"t":"para","text":"почти́ темно́: gần như tối."},{"t":"para","text":"соверше́нно великоле́пно: hoàn toàn tuyệt vời."}]},{"id":"gra-12-s028","type":"exercise","title":"Примыкание к местоимению, прилагательному, наречию (Sự tiếp hợp với đại từ, tính từ, trạng từ)","num":null,"blocks":[]},{"id":"gra-12-s029","type":"exercise","title":"Упражнение 146","num":146,"blocks":[{"t":"para","text":"Trong các câu, ở những chỗ có thể, hãy điền trạng từ о́чень (rất) kết hợp với các tính từ, động tính từ và trạng từ được in đậm. Giải thích quyết định của bạn."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"О́чень (rất) kết hợp với các tính từ chỉ tính chất và các trạng từ được tạo ra từ chúng mang ý nghĩa cụ thể: о́чень ти́хо (rất yên tĩnh), хо́лодно (lạnh), бо́льно (đau), ме́дленно (chậm) v.v."},{"t":"para","text":"Nó không kết hợp với các tính từ (động tính từ, trạng từ) mà ý nghĩa của chúng đã chỉ ra mức độ cao nhất của biểu hiện đặc điểm: потряса́ющий (gây chấn động/tuyệt vời), жу́ткий (khủng khiếp/ghê rợn), великоле́пный (lộng lẫy/tuyệt diệu) và các từ khác."},{"t":"para","text":"На у́лице (о́чень) жа́рко;"},{"t":"instruction","text":"Dịch: Ngoài đường (rất) nóng."},{"t":"para","text":"Giải thích: Жа́рко là trạng từ chỉ tính chất cụ thể, có thể dùng о́чень."},{"t":"para","text":"Вчера́ мы ходи́ли в кино́ и смотре́ли замеча́тельный фильм;"},{"t":"para","text":"Dịch: Hôm qua chúng tôi đã đi xem phim và xem một bộ phim tuyệt vời."},{"t":"para","text":"Giải thích: Замеча́тельный (xuất sắc/tuyệt vời) đã mang nghĩa mức độ cao, không dùng о́чень."},{"t":"para","text":"Сего́дня у тебя́ (о́чень) краси́вая причёска;"},{"t":"para","text":"Dịch: Hôm nay bạn có kiểu tóc (rất) đẹp."},{"t":"para","text":"Giải thích: Краси́вая (đẹp) là tính từ chỉ tính chất, có thể dùng о́чень."},{"t":"para","text":"Ты идёшь (о́чень) ме́дленно, поторопи́сь! Мы опа́здываем;"},{"t":"para","text":"Dịch: Bạn đi (rất) chậm, nhanh lên! Chúng ta đang muộn đấy."},{"t":"para","text":"Giải thích: Ме́дленно (chậm) là trạng từ chỉ tính chất, có thể dùng о́чень."},{"t":"para","text":"Он (о́чень) о́пытный специали́ст и сам зна́ет, что де́лать;"},{"t":"para","text":"Dịch: Anh ấy là một chuyên gia (rất) giàu kinh nghiệm và tự biết phải làm gì."},{"t":"para","text":"Giải thích: О́пытный (có kinh nghiệm) là tính từ chỉ tính chất, có thể dùng о́чень."},{"t":"para","text":"Она́ говори́т (о́чень) ти́хим го́лосом;"},{"t":"para","text":"Dịch: Cô ấy nói bằng giọng (rất) nhỏ."},{"t":"para","text":"Giải thích: Ти́хим (nhỏ/yên tĩnh) là tính từ chỉ tính chất, có thể dùng о́чень."},{"t":"para","text":"Э́то отврати́тельно! Никогда́ так бо́льше не де́лай;"},{"t":"para","text":"Dịch: Điều này thật ghê tởm/đáng ghét! Đừng bao giờ làm thế nữa."},{"t":"para","text":"Giải thích: Отврати́тельно mang nghĩa mức độ mạnh (cực kỳ xấu/ghê tởm), thường không đi với о́чень."},{"t":"para","text":"На про́шлой неде́ле со мно́й произошла́ удиви́тельная исто́рия;"},{"t":"para","text":"Dịch: Tuần trước đã xảy ra với tôi một câu chuyện đáng ngạc nhiên (kỳ lạ)."},{"t":"para","text":"Giải thích: Удиви́тельная mang sắc thái mức độ cao của sự ngạc nhiên, thường dùng поистине (thực sự) hoặc совершенно (hoàn toàn) hơn là очень, nhưng trong khẩu ngữ đôi khi vẫn dùng очень. Tuy nhiên, theo quy tắc \"mức độ cao\", sách không khuyến khích dùng."},{"t":"para","text":"Не дикту́й (о́чень) бы́стро! Я не успева́ю за тобо́й запи́сывать;"},{"t":"para","text":"Dịch: Đừng đọc chính tả (rất/quá) nhanh! Tôi không kịp viết theo bạn."},{"t":"para","text":"Giải thích: Бы́стро (nhanh) là trạng từ chỉ tính chất, có thể dùng о́чень."},{"t":"para","text":"В тот моме́нт мне бы́ло (о́чень) стра́шно;"},{"t":"para","text":"Dịch: Vào khoảnh khắc đó tôi đã (rất) sợ hãi."},{"t":"para","text":"Giải thích: Стра́шно (sợ) là trạng từ chỉ trạng thái, có thể dùng о́чень."},{"t":"para","text":"Я ду́маю, он поступи́л (о́чень) справедли́во;"},{"t":"para","text":"Dịch: Tôi nghĩ anh ấy đã hành động (rất) công bằng."},{"t":"para","text":"Giải thích: Справедли́во (công bằng) là trạng từ, có thể dùng о́чень."},{"t":"para","text":"Неприя́тно получа́ть таки́е изве́стия;"},{"t":"para","text":"Dịch: (Rất) Khó chịu/không vui khi nhận được những tin tức như vậy."},{"t":"para","text":"Giải thích: Неприя́тно có thể dùng với о́чень."},{"t":"para","text":"Ты (о́чень) невнима́телен, постара́йся сконцентри́роваться;"},{"t":"para","text":"Dịch: Bạn (rất) thiếu tập trung, hãy cố gắng tập trung lại."},{"t":"para","text":"Giải thích: Невнима́телен (thiếu tập trung) là tính từ ngắn đuôi, có thể dùng о́чень."},{"t":"para","text":"Потряса́ющий челове́к! Мне он сра́зу понра́вился;"},{"t":"para","text":"Dịch: Một người tuyệt vời (gây chấn động/ấn tượng mạnh)! Tôi thích anh ấy ngay lập tức."},{"t":"para","text":"Giải thích: Потряса́ющий mang nghĩa mức độ cao nhất, không dùng о́чень."},{"t":"para","text":"Маши́на впереди́ нас останови́лась с жу́тким скре́жетом;"},{"t":"para","text":"Dịch: Chiếc xe phía trước chúng tôi dừng lại với tiếng kít khủng khiếp (rợn người)."},{"t":"para","text":"Giải thích: Жу́тким mang nghĩa mức độ cao, không dùng о́чень."},{"t":"para","text":"Интере́сная иде́я! На́до над ней поду́мать;"},{"t":"para","text":"Dịch: Một ý tưởng (rất) thú vị! Cần phải suy nghĩ về nó."},{"t":"para","text":"Giải thích: Интере́сная (thú vị) có thể dùng о́чень."},{"t":"para","text":"Вчера́ во вре́мя трениро́вки он показа́л отли́чные результа́ты."},{"t":"para","text":"Dịch: Hôm qua trong buổi tập luyện anh ấy đã thể hiện những kết quả xuất sắc."},{"t":"para","text":"Giải thích: Отли́чные (xuất sắc/điểm 10) mang nghĩa mức độ cao nhất, không dùng о́чень."}]},{"id":"gra-12-s030","type":"exercise","title":"Упражнение 147","num":147,"blocks":[{"t":"para","text":"Thay dấu ba chấm bằng các trạng từ о́чень (rất) hoặc соверше́нно (hoàn toàn) sao cho phù hợp về ý nghĩa. Giải thích sự lựa chọn của bạn, chỉ ra các phương án (nếu có)."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Соверше́нно (hoàn toàn) kết hợp với các tính từ (động tính từ) và trạng từ chỉ mức độ cao nhất của biểu hiện đặc điểm (великоле́пный - lộng lẫy, ужа́сный - khủng khiếp, потряса́ющий - tuyệt vời) hoặc bao gồm các tiền tố без- (бес-) (không/vô) và не- (không/bất): безо́блачный (không mây/trong vắt), бесшу́мный (không tiếng động), недо́лго (không lâu)."},{"t":"para","text":"Nó không kết hợp với tính từ отли́чный (xuất sắc) và các tính từ ở cấp so sánh cao nhất. Trong các trường hợp còn lại, nó được sử dụng khi chỉ mức độ cao nhất của biểu hiện đặc điểm."},{"t":"para","text":"So sánh: Мы пришли́ соверше́нно (о́чень) во́время (Chúng tôi đến hoàn toàn (rất) đúng giờ - chính xác vào lúc cần đến). — Мы пришли́ о́чень по́здно (Chúng tôi đến rất muộn - không thể dùng соверше́нно, vì trong trường hợp này có thể muộn ở bất kỳ mức thời gian nào)."},{"t":"para","text":"Будь (о́чень / соверше́нно) внима́тельным! Э́то (о́чень / соверше́нно) тру́дный текст;"},{"t":"para","text":"Điền: о́чень, о́чень (đôi khi соверше́нно cũng dùng được để nhấn mạnh tuyệt đối, nhưng о́чень phổ biến hơn với tính từ gốc)."},{"t":"instruction","text":"Dịch: Hãy (rất) cẩn thận/chú ý! Đây là một văn bản (rất) khó."},{"t":"para","text":"Giải thích: Внима́тельным và тру́дный là tính từ chỉ tính chất thông thường."},{"t":"para","text":"Ты отве́тил на вопро́с (соверше́нно) пра́вильно;"},{"t":"para","text":"Điền: соверше́нно"},{"t":"para","text":"Dịch: Bạn đã trả lời câu hỏi hoàn toàn chính xác."},{"t":"para","text":"Giải thích: Пра́вильно (đúng/chính xác) thường đi với соверше́нно để chỉ sự chính xác tuyệt đối (không sai chút nào)."},{"t":"para","text":"У него́ в дикта́нте (о́чень) мно́го оши́бок;"},{"t":"para","text":"Điền: о́чень"},{"t":"para","text":"Dịch: Trong bài chính tả của cậu ấy có rất nhiều lỗi."},{"t":"para","text":"Giải thích: Мно́го (nhiều) là trạng từ chỉ lượng, dùng о́чень."},{"t":"para","text":"У неё (соверше́нно) неве́рное представле́ние об э́той исто́рии;"},{"t":"para","text":"Điền: соверше́нно (hoặc о́чень)."},{"t":"para","text":"Dịch: Cô ấy có quan niệm hoàn toàn sai lầm về câu chuyện này."},{"t":"para","text":"Giải thích: Неве́рное có tiền tố не-, ưu tiên dùng соверше́нно."},{"t":"para","text":"Соверше́нно потряса́ющие но́вости! Я то́лько вчера́ узна́л об э́том;"},{"t":"para","text":"Điền: Соверше́нно"},{"t":"para","text":"Dịch: Tin tức thật sự/hoàn toàn chấn động! Tôi mới biết về điều này hôm qua."},{"t":"para","text":"Giải thích: Потряса́ющие chỉ mức độ cao nhất, dùng соверше́нно."},{"t":"para","text":"Я ду́маю, в э́том слу́чае он поступи́л (соверше́нно) бескоры́стно;"},{"t":"para","text":"Điền: соверше́нно"},{"t":"para","text":"Dịch: Tôi nghĩ trong trường hợp này anh ấy đã hành động hoàn toàn vô tư (không vụ lợi)."},{"t":"para","text":"Giải thích: Бескоры́стно có tiền tố бес-, dùng соверше́нно."},{"t":"para","text":"Он (соверше́нно) свобо́ден и мо́жет принима́ть любы́е реше́ния;"},{"t":"para","text":"Điền: соверше́нно"},{"t":"para","text":"Dịch: Anh ấy hoàn toàn tự do và có thể đưa ra bất kỳ quyết định nào."},{"t":"para","text":"Giải thích: Свобо́ден chỉ trạng thái tuyệt đối, thường dùng соверше́нно."},{"t":"para","text":"Мы е́хали (о́чень) до́лго, и все, коне́чно, уста́ли;"},{"t":"para","text":"Điền: о́чень"},{"t":"para","text":"Dịch: Chúng tôi đã đi rất lâu, và tất nhiên mọi người đều mệt."},{"t":"para","text":"Giải thích: До́лго là trạng từ chỉ tính chất, dùng о́чень."},{"t":"para","text":"Посмотри́: бато́н (о́чень) мя́гкий, дава́й его́ ку́пим!"},{"t":"para","text":"Điền: о́чень (hoặc соверше́нно nếu muốn nhấn mạnh độ tươi tuyệt đối)."},{"t":"para","text":"Dịch: Nhìn kìa: ổ bánh mì rất mềm, hãy mua nó đi!"},{"t":"para","text":"Giải thích: Мя́гкий thường dùng với о́чень."},{"t":"para","text":"Мне (соверше́нно) неинтере́сно об э́том говори́ть;"},{"t":"para","text":"Điền: соверше́нно"},{"t":"para","text":"Dịch: Tôi hoàn toàn không hứng thú nói về chuyện này."},{"t":"para","text":"Giải thích: Неинтере́сно có tiền tố не-, dùng соверше́нно."},{"t":"para","text":"Я оказа́лся здесь (соверше́нно) случа́йно;"},{"t":"para","text":"Điền: соверше́нно"},{"t":"para","text":"Dịch: Tôi có mặt ở đây hoàn toàn tình cờ."},{"t":"para","text":"Giải thích: Случа́йно trong ngữ cảnh này mang nghĩa \"tình cờ tuyệt đối\", dùng соверше́нно."},{"t":"para","text":"Он объясня́ет (соверше́нно / о́чень) непоня́тно;"},{"t":"para","text":"Điền: соверше́нно (hoặc о́чень)."},{"t":"para","text":"Dịch: Anh ấy giải thích hoàn toàn khó hiểu."},{"t":"para","text":"Giải thích: Непоня́тно có tiền tố не-, dùng соверше́нно để nhấn mạnh sự không hiểu gì cả."},{"t":"para","text":"Э́тот ма́льчик (о́чень) высо́кий для своего́ во́зраста;"},{"t":"para","text":"Điền: о́чень"},{"t":"para","text":"Dịch: Cậu bé này rất cao so với tuổi."},{"t":"para","text":"Giải thích: Высо́кий là tính từ chỉ tính chất, dùng о́чень."},{"t":"para","text":"Ремни́ безопа́сности у маши́ны ка́жутся мне (соверше́нно) ненадёжными;"},{"t":"para","text":"Điền: соверше́нно (hoặc о́чень)."},{"t":"para","text":"Dịch: Dây an toàn của xe ô tô có vẻ hoàn toàn không đáng tin cậy đối với tôi."},{"t":"para","text":"Giải thích: Ненадёжными có tiền tố не-, dùng соверше́нно."},{"t":"para","text":"Она́ говори́ла (о́чень) взволно́ванным го́лосом;"},{"t":"para","text":"Điền: о́чень"},{"t":"para","text":"Dịch: Cô ấy nói với giọng rất xúc động/lo lắng."},{"t":"para","text":"Giải thích: Взволно́ванным là động tính từ chỉ trạng thái, dùng о́чень."},{"t":"para","text":"Мне ка́жется, он (соверше́нно / о́чень) сча́стлив и ничего́ не хо́чет меня́ть в свое́й жи́зни;"},{"t":"para","text":"Điền: соверше́нно (hoặc о́чень)."},{"t":"para","text":"Dịch: Tôi thấy dường như anh ấy hoàn toàn hạnh phúc và không muốn thay đổi gì trong cuộc sống của mình."},{"t":"para","text":"Giải thích: Сча́стлив có thể đi với cả hai, соверше́нно nhấn mạnh sự trọn vẹn."},{"t":"para","text":"Соверше́нно великоле́пная пого́да! Нельзя́ в тако́й день сиде́ть до́ма;"},{"t":"para","text":"Điền: Соверше́нно"},{"t":"para","text":"Dịch: Thời tiết thật sự/hoàn toàn tuyệt diệu! Không thể ngồi nhà vào ngày như thế này."},{"t":"para","text":"Giải thích: Великоле́пная chỉ mức độ cao nhất, dùng соверше́нно."},{"t":"para","text":"С его́ стороны́ (о́чень / соверше́нно) глу́по не воспо́льзоваться э́тим предложе́нием;"},{"t":"para","text":"Điền: о́чень (hoặc соверше́нно)."},{"t":"para","text":"Dịch: Về phía anh ấy thì thật (rất) ngu ngốc khi không tận dụng lời đề nghị này."},{"t":"para","text":"Giải thích: Глу́по là trạng từ chỉ tính chất."},{"t":"para","text":"Он (о́чень) аккура́тный челове́к, на него́ мо́жно рассчи́тывать;"},{"t":"para","text":"Điền: о́чень"},{"t":"para","text":"Dịch: Anh ấy là người rất cẩn thận/ngăn nắp, có thể trông cậy vào anh ấy."},{"t":"para","text":"Giải thích: Аккура́тный là tính từ chỉ tính chất, dùng о́чень."},{"t":"para","text":"Он (соверше́нно / о́чень) невоспи́танный челове́к, с ним тру́дно обща́ться."},{"t":"para","text":"Điền: соверше́нно (hoặc о́чень)."},{"t":"para","text":"Dịch: Hắn ta là kẻ hoàn toàn vô giáo dục, rất khó giao tiếp với hắn."},{"t":"para","text":"Giải thích: Невоспи́танный có tiền tố не-, dùng соверше́нно."}]},{"id":"gra-12-s031","type":"exercise","title":"Примыкание к местоимению, прилагательному, наречию (Sự tiếp hợp với đại từ, tính từ, trạng từ)","num":null,"blocks":[]},{"id":"gra-12-s032","type":"exercise","title":"Упражнение 148","num":148,"blocks":[{"t":"para","text":"Thay dấu ba chấm bằng các tính từ hoặc trạng từ trong ngoặc đơn ở dạng cần thiết cùng với các từ соверше́нно (hoàn toàn) hoặc совсе́м (hoàn toàn/hẳn/quá) sao cho phù hợp về ý nghĩa. Giải thích sự lựa chọn của bạn, chỉ ra các phương án."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Соверше́нно (hoàn toàn) kết hợp với các từ chỉ đặc điểm, biểu thị những phẩm chất bên trong của sự vật;"},{"t":"para","text":"Совсе́м (hoàn toàn/hẳn/quá) kết hợp với các từ chỉ các phương diện bên ngoài của biểu hiện đặc điểm."},{"t":"para","text":"So sánh: Соверше́нно (совсе́м) безобра́зный пёс. (Con chó hoàn toàn xấu xí [về hành vi/tính cách] — Con chó hoàn toàn xấu xí [về ngoại hình]). — Соверше́нно безобра́зный пёс, он не уме́ет себя́ вести́. (Con chó hoàn toàn hư đốn [phẩm chất], nó không biết cách cư xử); Совсе́м безобра́зный пёс, весь гря́зный и обо́дранный. (Con chó quá xấu xí [ngoại hình], toàn thân bẩn thỉu và rách rưới)."},{"t":"para","text":"Với các từ chỉ các chỉ số cấu trúc bên ngoài, có thể có các phương án thay thế: совсе́м (соверше́нно) прямы́е во́лосы (tóc hoàn toàn thẳng)."},{"t":"para","text":"Потоло́к в э́той ко́мнате был совсе́м ни́зкий (ни́зким), и мо́жно бы́ло, встав на цы́почки, дотяну́ться до него́ руко́й. Мо́жет быть, для кого́-то э́то назначе́ние счита́лось бы продвиже́нием по слу́жбе, но для него́ э́то был соверше́нно ни́зкий у́ровень (ни́зкий);"},{"t":"instruction","text":"Dịch: Trần nhà trong căn phòng này rất (quá) thấp, và có thể kiễng chân chạm tay tới nó. Có lẽ đối với ai đó sự bổ nhiệm này được coi là thăng chức, nhưng đối với anh ấy đây là một đẳng cấp hoàn toàn thấp kém."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: низкий chỉ chiều cao vật lý (bên ngoài) $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"Vế 2: низкий уровень chỉ đẳng cấp/trình độ (trừu tượng/bên trong) $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"Ме́бель в кварти́ре была́ ста́рая и совсе́м дешёвая. Как мо́жно быть таки́м дове́рчивым? Ты попа́лся на соверше́нно дешёвый трюк како́го-то ме́лкого жу́лика (дешёвый);"},{"t":"para","text":"Dịch: Đồ đạc trong căn hộ cũ và quá rẻ tiền. Sao có thể cả tin như vậy? Bạn đã mắc bẫy một mánh khóe hoàn toàn rẻ tiền (tầm thường) của một tên lừa đảo vặt nào đó."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: дешёвая chỉ giá cả cụ thể (bên ngoài) $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"Vế 2: дешёвый трюк chỉ tính chất lừa lọc/tầm thường (bên trong/trừu tượng) $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"По-мо́ему, э́то бы́ло соверше́нно глу́пое реше́ние, я бы поступи́л ина́че. Когда́ он заду́мывался о чём-то, вид у него́ станови́лся совсе́м глу́пый (глу́пым) (глу́пый);"},{"t":"para","text":"Dịch: Theo tôi, đó là một quyết định hoàn toàn ngu ngốc, tôi sẽ hành động khác. Khi anh ấy trầm ngâm về điều gì đó, vẻ mặt anh ấy trở nên ngu ngơ hẳn."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: глупое решение đánh giá tính chất của quyết định (bên trong) $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"Vế 2: вид (vẻ mặt) là biểu hiện bên ngoài $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"Во́лосы у него́ бы́ли совсе́м ре́дкие с седино́й. Уме́ние сопережива́ть друго́му челове́ку — соверше́нно ре́дкое ка́чество в совреме́нных лю́дях (ре́дкий);"},{"t":"para","text":"Dịch: Tóc ông ấy rất thưa và có sợi bạc. Khả năng đồng cảm với người khác là một phẩm chất hoàn toàn hiếm có ở con người hiện đại."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: редкие chỉ mật độ tóc (bên ngoài) $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"Vế 2: редкое качество chỉ tính chất (bên trong/trừu tượng) $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"На́до призна́ться, пишу́ я пло́хо, по́черк у меня́ совсе́м некраси́вый. И́з-за тебя́ мы оказа́лись в соверше́нно некраси́вой ситуа́ции, ума́ не приложу́, что тепе́рь де́лать (некраси́вый);"},{"t":"para","text":"Dịch: Phải thú nhận là tôi viết xấu, chữ viết của tôi quá xấu (hoàn toàn không đẹp). Vì bạn mà chúng ta rơi vào một tình huống hoàn toàn tồi tệ (không đẹp mặt), tôi không thể nghĩ ra giờ phải làm gì."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: некрасивый почерк chỉ vẻ ngoài của chữ viết $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"Vế 2: некрасивая ситуация chỉ tính chất sự việc (trừu tượng) $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"Костю́м соверше́нно но́вый, я почти́ его́ не носи́л. — Я не по́мню у тебя́ э́той маши́ны. — Да, маши́на совсе́м но́вая, я е́зжу на ней всего́ три ме́сяца (но́вый);"},{"t":"para","text":"Dịch: Bộ vest mới toanh (hoàn toàn mới), tôi hầu như chưa mặc nó. — Tôi không nhớ bạn có chiếc xe này. — Ừ, chiếc xe mới tinh, tôi mới lái nó được ba tháng thôi."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: совершенно новый thường dùng để nhấn mạnh trạng thái nguyên vẹn, chưa sử dụng (phẩm chất)."},{"t":"para","text":"Vế 2: совсем новая nhấn mạnh tính thời gian (mới mua/xuất hiện gần đây - bên ngoài)."},{"t":"para","text":"Когда́ на у́лице ста́ло совсе́м хо́лодно, мы переста́ли ходи́ть на като́к. Он пыта́лся меня́ заде́ть, но я соверше́нно хо́лодно реаги́ровал на его́ замеча́ния (хо́лодно);"},{"t":"para","text":"Dịch: Khi ngoài đường trở nên lạnh hẳn (quá lạnh), chúng tôi ngừng đi trượt băng. Anh ta cố chọc tức tôi, nhưng tôi phản ứng hoàn toàn lạnh lùng với những nhận xét của anh ta."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: холодно chỉ nhiệt độ vật lý (bên ngoài) $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"Vế 2: холодно chỉ thái độ/cảm xúc (bên trong) $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"Да, вид у него́ сего́дня совсе́м гру́стный, да́же не зна́ю, чем его́ развесели́ть. В э́том расска́зе опи́сывается соверше́нно гру́стная исто́рия о челове́ке, кото́рый потеря́л интере́с к жи́зни (гру́стный);"},{"t":"para","text":"Dịch: Ừ, vẻ mặt anh ấy hôm nay buồn thiu (quá buồn), thậm chí không biết làm gì để anh ấy vui lên. Trong truyện này mô tả một câu chuyện hoàn toàn buồn bã về một người đã mất hứng thú với cuộc sống."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: вид (vẻ mặt) là biểu hiện bên ngoài $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"Vế 2: история (câu chuyện) mang tính chất nội dung (bên trong) $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"Посмотри́, совсе́м (соверше́нно) просто́й рису́нок, а ткань смо́трится великоле́пно. Отсю́да сле́дует соверше́нно просто́й вы́вод: не сто́ит спеши́ть, всегда́ на́до поду́мать, пре́жде чем что́-то предпринима́ть (просто́й)."},{"t":"para","text":"Dịch: Nhìn kìa, hình vẽ hoàn toàn đơn giản, mà vải trông thật tuyệt. Từ đó rút ra một kết luận hoàn toàn đơn giản: không nên vội vàng, luôn cần suy nghĩ trước khi làm bất cứ điều gì."},{"t":"para","text":"Giải thích:"},{"t":"para","text":"Vế 1: рисунок (hình vẽ) là cấu trúc bên ngoài, có thể dùng cả hai, nhưng совсем phổ biến hơn cho sự đơn giản về hình thức."},{"t":"para","text":"Vế 2: вывод (kết luận) là tư duy logic (bên trong) $\\rightarrow$ dùng соверше́нно."}]},{"id":"gra-12-s033","type":"exercise","title":"Упражнение 149","num":149,"blocks":[{"t":"para","text":"Thay dấu ba chấm bằng các trạng từ соверше́нно hoặc совсе́м phù hợp về ý nghĩa. Giải thích sự lựa chọn của bạn, chỉ ra các phương án."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Совсе́м (hoàn toàn/hẳn/quá) không kết hợp với các tính từ (động tính từ) và trạng từ chỉ mức độ cao nhất của biểu hiện đặc điểm (отли́чный - xuất sắc, великоле́пный - lộng lẫy, ужа́сный - kinh khủng, потряса́ющий - chấn động và các từ khác)."},{"t":"para","text":"Nếu tính từ biểu thị đặc điểm không thể đánh giá bằng thị giác (bên trong/trừu tượng), thì chỉ sử dụng trạng từ соверше́нно: Э́то реше́ние соверше́нно справедли́во. (Quyết định này hoàn toàn công bằng); Ты соверше́нно пра́вильно реши́л зада́чу. (Bạn đã giải bài toán hoàn toàn đúng)."},{"t":"para","text":"Trong các câu đã hoàn thành, ở những chỗ có thể, hãy thay thế các trạng từ соверше́нно và совсе́м bằng trạng từ абсолю́тно (tuyệt đối). Hãy lưu ý rằng абсолю́тно là từ đồng nghĩa của trạng từ соверше́нно, nhưng khác ở chỗ nó không được dùng với các từ chỉ mức độ cao nhất của biểu hiện đặc điểm."},{"t":"para","text":"На у́лице ста́ло совсе́м темно́;"},{"t":"para","text":"Thay thế: абсолю́тно (có thể dùng được: абсолютно темно)."},{"t":"instruction","text":"Dịch: Ngoài đường trời đã trở nên tối hẳn (hoàn toàn tối)."},{"t":"para","text":"Giải thích: Темно chỉ trạng thái vật lý bên ngoài $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"Я за́дал тебе́ соверше́нно просто́й вопро́с и хочу́ получи́ть на него́ тако́й же просто́й отве́т;"},{"t":"para","text":"Thay thế: абсолю́тно."},{"t":"para","text":"Dịch: Tôi đã đặt cho bạn một câu hỏi hoàn toàn đơn giản và muốn nhận được một câu trả lời đơn giản như vậy."},{"t":"para","text":"Giải thích: Простой вопрос là đánh giá tính chất nội dung $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"У неё совсе́м све́тлые во́лосы;"},{"t":"para","text":"Thay thế: Không dùng абсолютно."},{"t":"para","text":"Dịch: Cô ấy có mái tóc rất (quá/hoàn toàn) sáng màu."},{"t":"para","text":"Giải thích: Màu tóc là đặc điểm bên ngoài $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"Мне нужна́ совсе́м (соверше́нно) ро́вная пове́рхность, что́бы продемонстри́ровать э́тот о́пыт;"},{"t":"para","text":"Thay thế: абсолю́тно."},{"t":"para","text":"Dịch: Tôi cần một bề mặt hoàn toàn phẳng để thực hiện thí nghiệm này."},{"t":"para","text":"Giải thích: Ровная поверхность là đặc điểm cấu trúc, có thể dùng cả hai, nhưng абсолютно rất hợp ở đây."},{"t":"para","text":"Мне соверше́нно непоня́тна его́ роль в э́той исто́рии;"},{"t":"para","text":"Thay thế: абсолю́тно."},{"t":"para","text":"Dịch: Tôi hoàn toàn không hiểu vai trò của anh ấy trong câu chuyện này."},{"t":"para","text":"Giải thích: Непонятна là quá trình nhận thức (bên trong) $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"В то вре́мя я был совсе́м молоды́м, мне не́ было и двадцати́ лет;"},{"t":"para","text":"Thay thế: Không dùng абсолютно (không nói абсолютно молодой)."},{"t":"para","text":"Dịch: Vào thời gian đó tôi còn rất (quá) trẻ, tôi chưa đến hai mươi tuổi."},{"t":"para","text":"Giải thích: Tuổi tác/trạng thái vật lý $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"Он вёл соверше́нно за́мкнутый о́браз жи́зни, ре́дко выходи́л из до́ма и никого́ не приглаша́л к себе́ в го́сти;"},{"t":"para","text":"Thay thế: абсолю́тно."},{"t":"para","text":"Dịch: Ông ấy có lối sống hoàn toàn khép kín, hiếm khi ra khỏi nhà và không mời ai đến chơi."},{"t":"para","text":"Giải thích: Lối sống là đặc điểm trừu tượng/nội tại $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"Кварти́ра у неё совсе́м ма́ленькая, но ую́тная;"},{"t":"para","text":"Thay thế: Không dùng абсолютно."},{"t":"para","text":"Dịch: Căn hộ của cô ấy rất (quá) nhỏ, nhưng ấm cúng."},{"t":"para","text":"Giải thích: Kích thước vật lý $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"Коне́чно, вы соверше́нно пра́вы;"},{"t":"para","text":"Thay thế: абсолю́тно."},{"t":"para","text":"Dịch: Tất nhiên, bạn hoàn toàn đúng."},{"t":"para","text":"Giải thích: Sự đúng đắn là đánh giá logic (bên trong) $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"Сего́дня соверше́нно удиви́тельная пого́да, на не́бе — ни о́блачка;"},{"t":"para","text":"Thay thế: Không dùng абсолютно (vì удивительная đã mang nghĩa mức độ cao)."},{"t":"para","text":"Dịch: Hôm nay thời tiết thật sự tuyệt vời (đáng ngạc nhiên), trên trời không một gợn mây."},{"t":"para","text":"Giải thích: Удивительная mang sắc thái đánh giá cảm xúc mạnh/bên trong $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"К сожале́нию, у меня́ совсе́м ма́ло свобо́дного вре́мени;"},{"t":"para","text":"Thay thế: Không dùng абсолютно."},{"t":"para","text":"Dịch: Rất tiếc, tôi có quá (rất) ít thời gian rảnh."},{"t":"para","text":"Giải thích: Chỉ số lượng $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"За́втра я бу́ду соверше́нно за́нят и не смогу́ с ва́ми встре́титься;"},{"t":"para","text":"Thay thế: абсолю́тно."},{"t":"para","text":"Dịch: Ngày mai tôi sẽ hoàn toàn bận rộn và không thể gặp bạn."},{"t":"para","text":"Giải thích: Занят chỉ trạng thái bận rộn (tình huống) $\\rightarrow$ dùng соверше́нно (để nhấn mạnh mức độ tuyệt đối)."},{"t":"para","text":"Внеза́пно я по́нял, что я здесь соверше́нно (совсе́м) ли́шний;"},{"t":"para","text":"Thay thế: абсолю́тно."},{"t":"para","text":"Dịch: Bất chợt tôi nhận ra rằng tôi ở đây là người hoàn toàn thừa thãi."},{"t":"para","text":"Giải thích: Лишний là cảm giác/đánh giá tình huống (bên trong) $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"Да, э́та ку́ртка совсе́м ма́ленькая, мне она́ не годи́тся;"},{"t":"para","text":"Thay thế: Không dùng абсолютно."},{"t":"para","text":"Dịch: Vâng, cái áo khoác này quá nhỏ, nó không vừa với tôi."},{"t":"para","text":"Giải thích: Kích thước vật lý $\\rightarrow$ dùng совсе́м."},{"t":"para","text":"Э́то мероприя́тие мне ка́жется соверше́нно сомни́тельным;"},{"t":"para","text":"Thay thế: абсолю́тно."},{"t":"para","text":"Dịch: Sự kiện này đối với tôi có vẻ hoàn toàn đáng ngờ."},{"t":"para","text":"Giải thích: Сомнительный là đánh giá trừu tượng $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"Зна́ешь, он челове́к соверше́нно ненадёжный, не сто́ит на него́ рассчи́тывать;"},{"t":"para","text":"Thay thế: абсолю́тно."},{"t":"para","text":"Dịch: Bạn biết không, anh ta là người hoàn toàn không đáng tin cậy, không nên trông cậy vào anh ta."},{"t":"para","text":"Giải thích: Tính cách (bên trong) $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"Он соверше́нно (совсе́м) тёмный челове́к, е́сли не зна́ет таки́х элемента́рных веще́й;"},{"t":"para","text":"Thay thế: абсолю́тно."},{"t":"para","text":"Dịch: Hắn ta là kẻ hoàn toàn tăm tối (ngu dốt), nếu không biết những điều cơ bản như vậy."},{"t":"para","text":"Giải thích: Тёмный (ngu dốt) là nghĩa bóng chỉ phẩm chất $\\rightarrow$ dùng соверше́нно (hoặc совсем với nghĩa nhấn mạnh mức độ)."},{"t":"para","text":"Всё, что ты мне рассказа́л, соверше́нно ужа́сно;"},{"t":"para","text":"Thay thế: Không dùng абсолютно (vì ужасно chỉ mức độ cao nhất)."},{"t":"para","text":"Dịch: Tất cả những gì bạn kể cho tôi thật sự (hoàn toàn) kinh khủng."},{"t":"para","text":"Giải thích: Ужасно là mức độ cao nhất của đặc điểm $\\rightarrow$ dùng соверше́нно."},{"t":"para","text":"Посо́бия, по кото́рым мы занима́лись ра́ньше, не соотве́тствуют програ́мме, нам нужны́ соверше́нно но́вые методи́ческие разрабо́тки."},{"t":"para","text":"Thay thế: абсолю́тно."},{"t":"para","text":"Dịch: Các giáo trình mà chúng tôi học trước đây không phù hợp với chương trình, chúng tôi cần những tài liệu phương pháp hoàn toàn mới."},{"t":"para","text":"Giải thích: Новые ở đây chỉ sự khác biệt về chất lượng/nội dung (bên trong) $\\rightarrow$ dùng соверше́нно."}]},{"id":"gra-12-s034","type":"exercise","title":"Упражнение 150","num":150,"blocks":[{"t":"para","text":"Thay dấu ba chấm bằng các trạng từ о́чень (rất), соверше́нно (hoàn toàn) hoặc сли́шком (quá) sao cho phù hợp về ý nghĩa. Giải thích sự lựa chọn của bạn, chỉ ra các phương án."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Сли́шком (quá) khác với các trạng từ о́чень (rất) và соверше́нно (hoàn toàn) ở chỗ nó diễn đạt sự đánh giá tương đối (luôn mang tính tiêu cực) về đặc điểm, tức là chỉ ra sự vượt quá mức độ biểu hiện của đặc điểm đó mà không phù hợp với mục đích của người nói hoặc cản trở việc thực hiện các hành động liên quan đến đặc điểm này."},{"t":"para","text":"So sánh: Он о́чень общи́тельный челове́к (Anh ấy là người rất hòa đồng) — nói chung. — Он сли́шком общи́тельный челове́к (Anh ấy là người quá hòa đồng) — nói chuyện với anh ấy nhanh bị mệt."},{"t":"para","text":"Trong các câu đã hoàn thành, ở những chỗ có thể, hãy thay thế trạng từ сли́шком bằng trạng từ кра́йне (cực kỳ). Hãy lưu ý rằng кра́йне, như một quy luật, được sử dụng với các từ chỉ đặc điểm thể hiện thái độ của chủ thể đối với thế giới xung quanh."},{"t":"para","text":"Сего́дня я чу́вствую (себя́) сли́шком (о́чень) уста́вшим, что́бы принима́ть реше́ния;"},{"t":"instruction","text":"Dịch: Hôm nay tôi cảm thấy quá mệt để đưa ra các quyết định."},{"t":"para","text":"Điền: сли́шком."},{"t":"para","text":"Giải thích: Mức độ mệt mỏi cản trở hành động (ra quyết định)."},{"t":"para","text":"Thay thế: Có thể dùng кра́йне (cực kỳ) để nhấn mạnh mức độ cao của trạng thái."},{"t":"para","text":"Он ведёт себя́ сли́шком (о́чень, соверше́нно) незави́симо и не мо́жет рабо́тать в коллекти́ве;"},{"t":"para","text":"Dịch: Anh ấy cư xử quá độc lập và không thể làm việc trong tập thể."},{"t":"para","text":"Điền: сли́шком."},{"t":"para","text":"Giải thích: Sự độc lập vượt quá mức cần thiết, gây cản trở công việc chung."},{"t":"para","text":"Thay thế: кра́йне (cực kỳ độc lập - thái độ)."},{"t":"para","text":"Не ду́май, что он всегда́ тако́й лени́вый, он о́чень (сли́шком) акти́вен, когда́ де́ло каса́ется его́ ли́чных интере́сов;"},{"t":"para","text":"Dịch: Đừng nghĩ rằng nó lúc nào cũng lười như vậy, nó rất tích cực khi việc đó liên quan đến lợi ích cá nhân của nó."},{"t":"para","text":"Điền: о́чень."},{"t":"para","text":"Giải thích: Diễn tả mức độ tích cực cao (nói chung), không mang nghĩa cản trở tiêu cực trong ngữ cảnh này."},{"t":"para","text":"Thay thế: кра́йне (cực kỳ tích cực)."},{"t":"para","text":"Ты положи́ла мне сли́шком (о́чень) большо́й кусо́к то́рта, я не смогу́ его́ съесть;"},{"t":"para","text":"Dịch: Bạn đã lấy cho tôi miếng bánh quá to, tôi sẽ không thể ăn hết nó."},{"t":"para","text":"Điền: сли́шком."},{"t":"para","text":"Giải thích: Mức độ to vượt quá khả năng ăn hết."},{"t":"para","text":"— Ско́лько вре́мени? — Ещё о́чень ра́но, шесть часо́в утра́;"},{"t":"para","text":"Dịch: — Mấy giờ rồi? — Vẫn còn rất sớm, sáu giờ sáng."},{"t":"para","text":"Điền: о́чень (hoặc сли́шком nếu hàm ý \"quá sớm để làm gì đó\")."},{"t":"para","text":"Giải thích: Chỉ mức độ thời gian."},{"t":"para","text":"Она́ сли́шком (о́чень) легкомы́сленна, что́бы серьёзно относи́ться к рабо́те;"},{"t":"para","text":"Dịch: Cô ấy quá nông nổi/hời hợt để có thể nghiêm túc với công việc."},{"t":"para","text":"Điền: сли́шком."},{"t":"para","text":"Giải thích: Cấu trúc слишком... чтобы (quá... để mà...), chỉ sự cản trở."},{"t":"para","text":"Thay thế: кра́йне (cực kỳ nông nổi)."},{"t":"para","text":"Мне ка́жется, что э́та ситуа́ция соверше́нно безнадёжна, я не ви́жу из неё ни еди́ного вы́хода;"},{"t":"para","text":"Dịch: Tôi cảm thấy tình huống này hoàn toàn vô vọng, tôi không thấy bất kỳ lối thoát nào."},{"t":"para","text":"Điền: соверше́нно."},{"t":"para","text":"Giải thích: Безнадёжна (vô vọng) là tính từ chỉ mức độ tuyệt đối."},{"t":"para","text":"Ты о́чень (сли́шком) ча́сто пропуска́л заня́тия, я не ду́маю, что ты смо́жешь без труда́ получи́ть зачёт;"},{"t":"para","text":"Dịch: Bạn đã nghỉ học quá (rất) thường xuyên, tôi không nghĩ bạn có thể nhận điểm đạt một cách dễ dàng."},{"t":"para","text":"Điền: о́чень (hoặc сли́шком)."},{"t":"para","text":"Giải thích: Mức độ thường xuyên dẫn đến hậu quả tiêu cực."},{"t":"para","text":"Ты идёшь о́чень (сли́шком) бы́стро, я не успева́ю за тобо́й;"},{"t":"para","text":"Dịch: Bạn đi quá (rất) nhanh, tôi không theo kịp bạn."},{"t":"para","text":"Điền: о́чень (hoặc сли́шком)."},{"t":"para","text":"Giải thích: Tốc độ cao gây khó khăn cho người khác."},{"t":"para","text":"Он взвали́л на себя́ соверше́нно (сли́шком) непоси́льную рабо́ту, я не зна́ю, как он с ней спра́вится;"},{"t":"para","text":"Dịch: Anh ấy đã gánh vác công việc hoàn toàn quá sức, tôi không biết anh ấy sẽ xoay xở thế nào."},{"t":"para","text":"Điền: соверше́нно."},{"t":"para","text":"Giải thích: Непосильную (quá sức) đã mang nghĩa tột độ, dùng совершенно để nhấn mạnh."},{"t":"para","text":"Тепе́рь поезжа́й о́чень ме́дленно, что́бы я не пропусти́л но́мер его́ до́ма;"},{"t":"para","text":"Dịch: Bây giờ hãy lái xe thật (rất) chậm, để tôi không bỏ lỡ số nhà của anh ấy."},{"t":"para","text":"Điền: о́чень."},{"t":"para","text":"Giải thích: Yêu cầu mức độ cao của hành động để đạt mục đích."},{"t":"para","text":"Вчера́ со мно́й произошла́ соверше́нно необъясни́мая исто́рия, да́же не зна́ю, как э́то могло́ случи́ться;"},{"t":"para","text":"Dịch: Hôm qua đã xảy ra với tôi một câu chuyện hoàn toàn không thể giải thích nổi, thậm chí tôi không biết sao chuyện đó có thể xảy ra."},{"t":"para","text":"Điền: соверше́нно."},{"t":"para","text":"Giải thích: Необъяснимая (không thể giải thích) là tính từ chỉ tính chất tuyệt đối."},{"t":"para","text":"Мне он ка́жется сли́шком ро́бким челове́ком, что́бы реши́ться приня́ть уча́стие в вы́борах;"},{"t":"para","text":"Dịch: Với tôi anh ta có vẻ là người quá rụt rè để có thể quyết định tham gia bầu cử."},{"t":"para","text":"Điền: сли́шком."},{"t":"para","text":"Giải thích: Cấu trúc слишком... чтобы, tính chất rụt rè cản trở hành động."},{"t":"para","text":"Мы сли́шком (о́чень) ра́но разочарова́лись в э́том де́ле, всё не так безнадёжно;"},{"t":"para","text":"Dịch: Chúng ta đã thất vọng về việc này quá sớm, mọi thứ không vô vọng đến thế."},{"t":"para","text":"Điền: сли́шком (hoặc очень)."},{"t":"para","text":"Giải thích: Đánh giá việc thất vọng là sớm hơn mức cần thiết/hợp lý."},{"t":"para","text":"Я соверше́нно бесси́лен в э́той ситуа́ции, бою́сь, я не смогу́ тебе́ помо́чь;"},{"t":"para","text":"Dịch: Tôi hoàn toàn bất lực trong tình huống này, e rằng tôi không thể giúp bạn."},{"t":"para","text":"Điền: соверше́нно."},{"t":"para","text":"Giải thích: Бессилен (bất lực) là tính từ chỉ trạng thái tuyệt đối."},{"t":"para","text":"Уже́ о́чень (сли́шком) по́здно, пора́ идти́ спать;"},{"t":"para","text":"Dịch: Đã rất (quá) muộn rồi, đến lúc đi ngủ."},{"t":"para","text":"Điền: о́чень (hoặc сли́шком)."},{"t":"para","text":"Э́то о́чень (сли́шком) сло́жный вопро́с, дава́йте отло́жим его́ до за́втра;"},{"t":"para","text":"Dịch: Đây là một câu hỏi rất (quá) phức tạp, hãy để nó đến ngày mai."},{"t":"para","text":"Điền: о́чень (hoặc сли́шком)."},{"t":"para","text":"Thay thế: кра́йне (cực kỳ phức tạp)."}]},{"id":"gra-12-s035","type":"exercise","title":"Упражнение 151","num":151,"blocks":[{"t":"para","text":"Đặt câu, sử dụng các tính từ và động tính từ dưới đây kết hợp với trạng từ кра́йне (cực kỳ)."},{"t":"para","text":"Жесто́кий (tàn nhẫn): Уби́йство бы́ло совершено́ с кра́йне жесто́кой це́лью. (Vụ giết người được thực hiện với mục đích cực kỳ tàn nhẫn.)"},{"t":"para","text":"Примити́вный (đơn giản/sơ khai/thô sơ): Э́тот механи́зм устро́ен кра́йне примити́вно. (Cơ chế này được cấu tạo cực kỳ thô sơ.)"},{"t":"para","text":"Любопы́тный (tò mò): Мой сосе́д — кра́йне любопы́тный челове́к. (Hàng xóm của tôi là một người cực kỳ tò mò.)"},{"t":"para","text":"Эмоциона́льный (dễ xúc động/giàu cảm xúc): Она́ кра́йне эмоциона́льна и принима́ет всё бли́зко к се́рдцу. (Cô ấy cực kỳ dễ xúc động và để mọi thứ trong lòng.)"},{"t":"para","text":"Восто́рженный (nhiệt tình/phấn khích): Пу́блика встре́тила арти́ста кра́йне восто́рженно. (Khán giả đã đón tiếp nghệ sĩ cực kỳ nồng nhiệt.)"},{"t":"para","text":"Оби́дчивый (hay tự ái/dễ bị xúc phạm): С ним тру́дно обща́ться, он кра́йне оби́дчивый челове́к. (Rất khó giao tiếp với anh ta, anh ta là người cực kỳ hay tự ái.)"},{"t":"para","text":"Запу́танный (rắc rối/phức tạp): Э́то кра́йне запу́танная исто́рия. (Đây là một câu chuyện cực kỳ rắc rối.)"},{"t":"para","text":"За́мкнутый (khép kín/thu mình): Он ведёт кра́йне за́мкнутый о́браз жи́зни. (Anh ấy có lối sống cực kỳ khép kín.)"},{"t":"para","text":"Предприи́мчивый (tháo vát/biết kinh doanh): Он кра́йне предприи́мчивый бизнесме́н. (Ông ấy là một doanh nhân cực kỳ tháo vát.)"},{"t":"para","text":"Затрудни́тельный (khó khăn/nan giải): Мы оказа́лись в кра́йне затрудни́тельном положе́нии. (Chúng tôi đã rơi vào tình thế cực kỳ nan giải.)"},{"t":"para","text":"Обма́нчивый (dối trá/lừa lọc/dễ nhầm lẫn): Пе́рвое впечатле́ние быва́ет кра́йне обма́нчиво. (Ấn tượng ban đầu thường cực kỳ dễ gây nhầm lẫn.)"},{"t":"para","text":"Нахо́дчивый (nhanh trí): Студе́нт да́л кра́йне нахо́дчивый отве́т. (Cậu sinh viên đã đưa ra câu trả lời cực kỳ nhanh trí.)"},{"t":"para","text":"Иску́сный (khéo léo/tinh xảo): Э́то кра́йне иску́сная рабо́та. (Đây là một tác phẩm cực kỳ tinh xảo.)"},{"t":"para","text":"Ненадёжный (không đáng tin cậy): Э́тот банк счита́ется кра́йне ненадёжным. (Ngân hàng này bị coi là cực kỳ không đáng tin cậy.)"},{"t":"para","text":"Холо́дный (lạnh lùng/lạnh): Нас встре́тили кра́йне холо́дно. (Họ đã đón tiếp chúng tôi cực kỳ lạnh nhạt.)"}]},{"id":"gra-12-s036","type":"exercise","title":"Упражнение 152","num":152,"blocks":[{"t":"para","text":"Thay dấu ba chấm bằng các trạng từ немно́го (một chút/hơi) hoặc почти́ (hầu như/gần như) sao cho phù hợp về ý nghĩa. Giải thích sự lựa chọn của bạn. Trong các câu, ở những nơi có thể, hãy thay thế trạng từ немно́го bằng trạng từ чуть-чу́ть (một tí/một chút xíu)."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Немно́го (một chút/hơi) diễn đạt mức độ biểu hiện không đáng kể của đặc điểm; почти́ (hầu như/gần như) diễn đạt mức độ tiệm cận cao với đặc điểm đó."},{"t":"para","text":"Немно́го kết hợp với các tính từ và trạng từ chỉ tính chất mang ý nghĩa tiêu cực; почти́ tạo liên kết với các tính từ và trạng từ mang ý nghĩa tích cực hoặc tính từ quan hệ (trạng thái tuyệt đối)."},{"t":"para","text":"So sánh: немно́го гря́зный (тру́дный) (hơi bẩn/khó) — почти́ чи́стый (лёгкий) (gần như sạch/dễ)."},{"t":"para","text":"Với các tính từ quan hệ, почти́ kết hợp mà không có sự khác biệt về ý nghĩa ngữ nghĩa: Он почти́ слепо́й (Anh ấy gần như mù). — Бе́лка почти́ ручна́я (Con sóc gần như đã thuần hóa)."},{"t":"para","text":"Чуть-чу́ть có nghĩa là \"hoàn toàn ít/rất ít\" (gần nghĩa với немно́го)."},{"t":"para","text":"Он немно́го (чуть-чу́ть) засте́нчив, но е́сли с ним разговори́ться, то он о́чень интере́сный собесе́дник;"},{"t":"instruction","text":"Dịch: Anh ấy hơi nhút nhát, nhưng nếu bắt chuyện với anh ấy thì anh ấy là người đối thoại rất thú vị."},{"t":"para","text":"Điền: немно́го."},{"t":"para","text":"Giải thích: Застенчив (nhút nhát) mang sắc thái tiêu cực/hạn chế."},{"t":"para","text":"Thay thế: чуть-чу́ть."},{"t":"para","text":"Маши́на почти́ но́вая, он купи́л её полго́да наза́д;"},{"t":"para","text":"Dịch: Chiếc xe gần như mới, anh ấy mua nó nửa năm trước."},{"t":"para","text":"Điền: почти́."},{"t":"para","text":"Giải thích: Новая (mới) mang sắc thái tích cực/trạng thái tuyệt đối."},{"t":"para","text":"Мо́жет быть, лу́чше отдохну́ть, у тебя́ вид немно́го (чуть-чу́ть) уста́лый;"},{"t":"para","text":"Dịch: Có lẽ tốt hơn là nên nghỉ ngơi, trông bạn có vẻ hơi mệt mỏi."},{"t":"para","text":"Điền: немно́го."},{"t":"para","text":"Giải thích: Усталый (mệt) mang sắc thái tiêu cực."},{"t":"para","text":"Thay thế: чуть-чу́ть."},{"t":"para","text":"Мне твой сосе́д показа́лся немно́го (чуть-чу́ть) стра́нным: весь ве́чер он провёл, ни с кем не разгова́ривая;"},{"t":"para","text":"Dịch: Với tôi người hàng xóm của bạn có vẻ hơi kỳ lạ: anh ta dành cả buổi tối không nói chuyện với ai."},{"t":"para","text":"Điền: немно́го."},{"t":"para","text":"Giải thích: Странным (kỳ lạ) mang sắc thái tiêu cực/khó hiểu."},{"t":"para","text":"Thay thế: чуть-чу́ть."},{"t":"para","text":"Сади́тесь к столу́, обе́д почти́ гото́в;"},{"t":"para","text":"Dịch: Mời ngồi vào bàn, bữa trưa gần như đã xong."},{"t":"para","text":"Điền: почти́."},{"t":"para","text":"Giải thích: Готов (sẵn sàng/xong) chỉ kết quả/trạng thái tuyệt đối."},{"t":"para","text":"Все мы немно́го (чуть-чу́ть) не́рвные, потому́ что жизнь у нас непроста́я;"},{"t":"para","text":"Dịch: Tất cả chúng ta đều hơi nóng nảy, bởi vì cuộc sống của chúng ta không đơn giản."},{"t":"para","text":"Điền: немно́го."},{"t":"para","text":"Giải thích: Нервные (nóng nảy/thần kinh) mang sắc thái tiêu cực."},{"t":"para","text":"Thay thế: чуть-чу́ть."},{"t":"para","text":"Для меня́ бы́ло немно́го (чуть-чу́ть) непривы́чно выступа́ть пе́ред тако́й большо́й аудито́рией;"},{"t":"para","text":"Dịch: Đối với tôi việc phát biểu trước một thính giả lớn như vậy là hơi không quen."},{"t":"para","text":"Điền: немно́го."},{"t":"para","text":"Giải thích: Непривычно (không quen) mang sắc thái tiêu cực/khó khăn."},{"t":"para","text":"Thay thế: чуть-чу́ть."},{"t":"para","text":"Посмотри́: во́лосы почти́ сухи́е, мо́жно не включа́ть фен;"},{"t":"para","text":"Dịch: Nhìn kìa: tóc gần như khô rồi, có thể không cần bật máy sấy."},{"t":"para","text":"Điền: почти́."},{"t":"para","text":"Giải thích: Сухие (khô) chỉ kết quả/trạng thái đạt được."},{"t":"para","text":"Вчера́ по́сле экза́мена он вы́шел немно́го (чуть-чу́ть) расстро́енным, поэ́тому я не стал его́ ни о чём спра́шивать;"},{"t":"para","text":"Dịch: Hôm qua sau kỳ thi cậu ấy bước ra có vẻ hơi buồn bã, vì thế tôi đã không hỏi cậu ấy điều gì."},{"t":"para","text":"Điền: немно́го."},{"t":"para","text":"Giải thích: Расстроенным (buồn bã/thất vọng) mang sắc thái tiêu cực."},{"t":"para","text":"Thay thế: чуть-чу́ть."},{"t":"para","text":"Ты написа́л почти́ пра́вильно, то́лько в э́том предложе́нии ты немно́го (чуть-чу́ть) нето́чно вы́разил свою́ мысль;"},{"t":"para","text":"Dịch: Bạn viết gần như đúng, chỉ có trong câu này bạn diễn đạt ý của mình hơi không chính xác."},{"t":"para","text":"Điền: почти́ (với правильно - tích cực/kết quả), немно́го (với неточно - tiêu cực)."},{"t":"para","text":"Thay thế: чуть-чу́ть (thay cho немного)."},{"t":"para","text":"Боти́нки мне немно́го (чуть-чу́ть) теснова́ты, мо́жет быть, поме́рить други́е?"},{"t":"para","text":"Dịch: Đôi giày này với tôi hơi chật một chút, hay là thử đôi khác nhé?"},{"t":"para","text":"Điền: немно́го."},{"t":"para","text":"Giải thích: Тесноваты (hơi chật) mang sắc thái tiêu cực."},{"t":"para","text":"Thay thế: чуть-чу́ть."},{"t":"para","text":"Вчера́ я пришёл почти́ во́время, мо́жет быть, опозда́л на не́сколько мину́т;"},{"t":"para","text":"Dịch: Hôm qua tôi đã đến gần như đúng giờ, có lẽ bị muộn vài phút."},{"t":"para","text":"Điền: почти́."},{"t":"para","text":"Giải thích: Вовремя (đúng giờ) chỉ sự chính xác/kết quả tích cực."},{"t":"para","text":"В темноте́ мы дви́гались почти́ вслепу́ю, с трудо́м различа́я тропи́нку впереди́ нас;"},{"t":"para","text":"Dịch: Trong bóng tối chúng tôi di chuyển gần như mù quáng (mò mẫm), khó khăn lắm mới phân biệt được lối mòn phía trước."},{"t":"para","text":"Điền: почти́."},{"t":"para","text":"Giải thích: Вслепую (mù quáng/không nhìn thấy gì) chỉ trạng thái tuyệt đối (như người mù)."},{"t":"para","text":"Мне блю́да та́йской ку́хни ка́жутся немно́го (чуть-чу́ть) о́стрыми, наве́рное, я к ним не привы́к;"},{"t":"para","text":"Dịch: Các món ăn Thái đối với tôi có vẻ hơi cay, chắc là tôi chưa quen với chúng."},{"t":"para","text":"Điền: немно́го."},{"t":"para","text":"Giải thích: Острыми (cay) ở đây gây cảm giác khó chịu/tiêu cực nhẹ."},{"t":"para","text":"Thay thế: чуть-чу́ть."},{"t":"para","text":"Я так и поду́мал, что он заболе́л, на ле́кции он вы́глядел немно́го (чуть-чу́ть) вя́лым;"},{"t":"para","text":"Dịch: Tôi cũng nghĩ là cậu ấy bị ốm, trong giờ giảng cậu ấy trông có vẻ hơi uể oải."},{"t":"para","text":"Điền: немно́го."},{"t":"para","text":"Giải thích: Вялым (uể oải/lờ đờ) mang sắc thái tiêu cực."},{"t":"para","text":"Thay thế: чуть-чу́ть."},{"t":"para","text":"Говори́ гро́мче, он почти́ глухо́й."},{"t":"para","text":"Dịch: Hãy nói to hơn, ông ấy gần như bị điếc."},{"t":"para","text":"Điền: почти́."},{"t":"para","text":"Giải thích: Глухой (điếc) là tính từ chỉ trạng thái tuyệt đối."}]},{"id":"gra-12-s037","type":"exercise","title":"Упражнение 153","num":153,"blocks":[{"t":"para","text":"Thay dấu ba chấm bằng các trạng từ доста́точно (đủ/khá) hoặc дово́льно (khá/tương đối) sao cho phù hợp về ý nghĩa. Giải thích sự lựa chọn của bạn, chỉ ra các phương án."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Доста́точно (đủ/khá) chỉ ra rằng mức độ biểu hiện của đặc điểm là phù hợp cho những mục đích nhất định hoặc gây nghi ngờ về khả năng thực hiện chúng (sự đánh giá tương đối)."},{"t":"para","text":"Дово́льно (khá/tương đối) diễn đạt sự đánh giá tuyệt đối và chỉ ra mức độ trung bình của biểu hiện đặc điểm."},{"t":"para","text":"So sánh: сли́шком ску́чный (quá tẻ nhạt) — о́чень ску́чный (rất tẻ nhạt) — дово́льно ску́чный (khá tẻ nhạt) — немно́го ску́чный (hơi tẻ nhạt)."},{"t":"para","text":"Chỉ có một trạng từ kết hợp được với tiểu từ phủ định не: (не)доста́точно ((không) đủ)."},{"t":"para","text":"Мне понра́вилась вчера́шняя вечери́нка: бы́ло дово́льно ве́село;"},{"t":"instruction","text":"Dịch: Tôi thích bữa tiệc hôm qua: nó khá vui."},{"t":"para","text":"Giải thích: Đánh giá mức độ vui vẻ ở mức trung bình khá (tuyệt đối)."},{"t":"para","text":"Đáp án sách: дово́льно."},{"t":"para","text":"По-мо́ему, у нас доста́точно (дово́льно) большо́й вы́бор проду́ктов, мо́жно пригото́вить что́-нибудь вку́сное;"},{"t":"para","text":"Dịch: Theo tôi, chúng ta có sự lựa chọn thực phẩm đủ lớn (khá lớn), có thể nấu món gì đó ngon."},{"t":"para","text":"Giải thích: Доста́точно nhấn mạnh là \"đủ để nấu ăn\". Дово́льно nhấn mạnh mức độ \"khá lớn\"."},{"t":"para","text":"Đáp án sách: доста́точно (дово́льно)."},{"t":"para","text":"— Что ты ду́маешь об э́той кни́ге? — Дово́льно интере́сная кни́га, почита́й, е́сли бу́дет свобо́дное вре́мя;"},{"t":"para","text":"Dịch: — Bạn nghĩ gì về cuốn sách này? — Cuốn sách khá thú vị, hãy đọc nếu có thời gian rảnh."},{"t":"para","text":"Giải thích: Đánh giá phẩm chất cuốn sách."},{"t":"para","text":"Đáp án sách: Дово́льно."},{"t":"para","text":"Ты доста́точно взро́слый, что́бы самому́ отвеча́ть за свои́ посту́пки;"},{"t":"para","text":"Dịch: Bạn đủ lớn để tự chịu trách nhiệm về hành động của mình."},{"t":"para","text":"Giải thích: Có cấu trúc chỉ mục đích/hệ quả что́бы (để mà...), yêu cầu dùng доста́точно (đủ ... để)."},{"t":"para","text":"Đáp án sách: доста́точно."},{"t":"para","text":"На у́лице дово́льно (доста́точно) хо́лодно, наде́нь ку́ртку;"},{"t":"para","text":"Dịch: Ngoài trời khá lạnh, hãy mặc áo khoác vào."},{"t":"para","text":"Giải thích: Дово́льно chỉ mức độ lạnh. Доста́точно hàm ý \"đủ lạnh để phải mặc áo\"."},{"t":"para","text":"Đáp án sách: дово́льно (доста́точно)."},{"t":"para","text":"Иди́ ко мне, не бо́йся! Здесь доста́точно (дово́льно) ме́лко, ты не уто́нешь;"},{"t":"para","text":"Dịch: Lại đây với tôi, đừng sợ! Ở đây đủ nông (khá nông), bạn sẽ không chết đuối đâu."},{"t":"para","text":"Giải thích: Доста́точно nhấn mạnh điều kiện an toàn (đủ nông để không chìm)."},{"t":"para","text":"Đáp án sách: доста́точно (дово́льно)."},{"t":"para","text":"Он доста́точно серьёзный молодо́й челове́к и спра́вится с э́той рабо́той;"},{"t":"para","text":"Dịch: Cậu ấy là một chàng trai đủ nghiêm túc và sẽ hoàn thành công việc này."},{"t":"para","text":"Giải thích: Đủ phẩm chất để làm việc."},{"t":"para","text":"Đáp án sách: доста́точно."},{"t":"para","text":"Я ду́маю, ра́но сажа́ть расте́ния, земля́ ещё не доста́точно тёплая;"},{"t":"para","text":"Dịch: Tôi nghĩ còn sớm để trồng cây, đất vẫn chưa đủ ấm."},{"t":"para","text":"Giải thích: Có từ phủ định не. Chỉ có доста́точно kết hợp được với не."},{"t":"para","text":"Đáp án sách: доста́точно."},{"t":"para","text":"Э́та зада́ча доста́точно (дово́льно) сло́жная, ду́маю, тебе́ не уда́стся реши́ть её с пе́рвого ра́за;"},{"t":"para","text":"Dịch: Bài toán này đủ phức tạp (khá phức tạp), tôi nghĩ bạn sẽ không thể giải nó ngay lần đầu."},{"t":"para","text":"Giải thích: Доста́точно hàm ý mức độ khó gây cản trở."},{"t":"para","text":"Đáp án sách: доста́точно (дово́льно)."},{"t":"para","text":"— Мне кто́-нибудь звони́л? — Был дово́льно стра́нный звоно́к: когда́ я подошёл к телефо́ну, на том конце́ пове́сили тру́бку;"},{"t":"para","text":"Dịch: — Có ai gọi cho tôi không? — Có một cuộc gọi khá lạ: khi tôi đến bên điện thoại, đầu dây bên kia đã cúp máy."},{"t":"para","text":"Giải thích: Đánh giá mức độ lạ lùng."},{"t":"para","text":"Đáp án sách: дово́льно."},{"t":"para","text":"Он дово́льно высо́кий: метр се́мьдесят пять — метр во́семьдесят;"},{"t":"para","text":"Dịch: Anh ấy khá cao: một mét bảy lăm - một mét tám mươi."},{"t":"para","text":"Giải thích: Đánh giá chiều cao tuyệt đối."},{"t":"para","text":"Đáp án sách: дово́льно."},{"t":"para","text":"Здесь доста́точно (дово́льно) ти́хое ме́сто, я уве́рен, что вам понра́вится;"},{"t":"para","text":"Dịch: Ở đây là một nơi đủ yên tĩnh (khá yên tĩnh), tôi tin là bạn sẽ thích."},{"t":"para","text":"Giải thích: Đủ yên tĩnh để làm hài lòng."},{"t":"para","text":"Đáp án sách: доста́точно (дово́льно)."},{"t":"para","text":"Попро́буй суп. Он доста́точно солёный?"},{"t":"para","text":"Dịch: Nếm thử súp đi. Nó có đủ mặn không?"},{"t":"para","text":"Giải thích: Hỏi về mức độ phù hợp/đủ của muối."},{"t":"para","text":"Đáp án sách: доста́точно."},{"t":"para","text":"Она́ дово́льно до́лго говори́ла по телефо́ну, но я не зна́ю с кем;"},{"t":"para","text":"Dịch: Cô ấy đã nói chuyện điện thoại khá lâu, nhưng tôi không biết là với ai."},{"t":"para","text":"Giải thích: Chỉ khoảng thời gian kéo dài."},{"t":"para","text":"Đáp án sách: дово́льно."},{"t":"para","text":"Ду́маю, я доста́точно хорошо́ его́ разгляде́ла и смогу́ описа́ть его́ вне́шность;"},{"t":"para","text":"Dịch: Tôi nghĩ tôi đã nhìn anh ta đủ kỹ và có thể mô tả ngoại hình của anh ta."},{"t":"para","text":"Giải thích: Mức độ kỹ càng đủ để thực hiện hành động mô tả."},{"t":"para","text":"Đáp án sách: доста́точно."},{"t":"para","text":"Бою́сь, я не доста́точно бли́зко знако́м с э́тими людьми́ и не смогу́ вам помо́чь в э́том вопро́се."},{"t":"para","text":"Dịch: E rằng tôi không quen biết đủ thân thiết với những người này và sẽ không thể giúp bạn trong vấn đề này."},{"t":"para","text":"Giải thích: Có từ phủ định не (không đủ thân)."},{"t":"para","text":"Đáp án sách: доста́точно."}]},{"id":"gra-12-s038","type":"exercise","title":"Упражнение 154","num":154,"blocks":[{"t":"para","text":"Điền liên từ что́бы vào chỗ trống, ở những nơi cần thiết. Giải thích sự lựa chọn của bạn."},{"t":"note","text":"! (Gợi ý ngữ pháp):"},{"t":"para","text":"Trong cụm từ \"đặc điểm (tính từ/trạng từ) — động từ nguyên thể\", cấu trúc với liên từ что́бы chỉ ra rằng đặc điểm và hành động được diễn đạt bởi động từ nguyên thể thuộc về các chủ thể khác nhau: прост, что́бы реши́ть (nhiệm vụ đơn giản, để [ai đó/mọi người] giải quyết nó - задача проста, и все смогут решить её)."},{"t":"para","text":"Với một chủ thể (cùng chủ ngữ), liên từ что́бы được lược bỏ, nếu đặc điểm mang ý nghĩa tạm thời, chỉ liên quan đến hành động này: Я сча́стлив вас ви́деть (Tôi hạnh phúc [khi] được gặp bạn - hạnh phúc chính vì tôi đang gặp bạn)."},{"t":"para","text":"Nếu đặc điểm mang ý nghĩa thường xuyên hoặc tương quan với một tình huống (thường đi kèm сли́шком - quá, доста́точно - đủ, hoặc các từ chỉ trạng thái cần thiết), thì liên từ что́бы được sử dụng: Я взял отчёт, что́бы познако́миться с ва́шей рабо́той (Tôi đã lấy báo cáo để làm quen với công việc của bạn - tôi lấy báo cáo và tôi sẽ làm quen...)."},{"t":"para","text":"Ду́маю, он ещё мо́лод, что́бы жени́ться;"},{"t":"instruction","text":"Dịch: Tôi nghĩ cậu ấy còn (quá) trẻ để kết hôn."},{"t":"para","text":"Giải thích: Tính từ молод (trẻ) ở đây hàm ý mức độ \"chưa đủ tuổi/quá trẻ\" so với tình huống kết hôn. Cần что́бы."},{"t":"para","text":"Đáp án sách: что́бы."},{"t":"para","text":"Наде́юсь, он спосо́бен вы́полнить э́ту рабо́ту;"},{"t":"para","text":"Dịch: Tôi hy vọng anh ấy có khả năng thực hiện công việc này."},{"t":"para","text":"Giải thích: Tính từ способен (có khả năng) đi trực tiếp với động từ nguyên thể. Cùng chủ ngữ."},{"t":"para","text":"Đáp án sách: không điền."},{"t":"para","text":"Ты обя́зан во́время сдать все экза́мены;"},{"t":"para","text":"Dịch: Bạn có nghĩa vụ nộp/thi tất cả các bài thi đúng hạn."},{"t":"para","text":"Giải thích: Обязан (có nghĩa vụ) đi trực tiếp với nguyên thể."},{"t":"para","text":"Đáp án sách: không điền."},{"t":"para","text":"Он сли́шком одино́к, что́бы быть счастли́вым;"},{"t":"para","text":"Dịch: Anh ấy quá cô đơn để (có thể) hạnh phúc."},{"t":"para","text":"Giải thích: Có từ сли́шком (quá) chỉ mức độ cản trở, bắt buộc dùng что́бы."},{"t":"para","text":"Đáp án sách: что́бы."},{"t":"para","text":"Роди́тели ушли́, а я был оста́влен присма́тривать за мла́дшими бра́тьями и сёстрами;"},{"t":"para","text":"Dịch: Bố mẹ đã đi vắng, còn tôi bị để lại trông coi các em trai và em gái."},{"t":"para","text":"Giải thích: Оставлен (bị để lại) + mục đích hành động của chủ thể. Không cần что́бы (tương tự các động từ chỉ vị trí/tình trạng)."},{"t":"para","text":"Đáp án sách: không điền."},{"t":"para","text":"Слова́рь мне ну́жен, что́бы прове́рить значе́ние э́того сло́ва;"},{"t":"para","text":"Dịch: Tôi cần từ điển để kiểm tra nghĩa của từ này."},{"t":"para","text":"Giải thích: Нужен (cần thiết) gắn với vật thể (từ điển), mục đích là hành động kiểm tra. Dùng что́бы để chỉ mục đích sử dụng vật đó."},{"t":"para","text":"Đáp án sách: что́бы."},{"t":"para","text":"В три́дцать лет он был назна́чен руководи́ть предприя́тием и прекра́сно спра́вился с э́той рабо́той;"},{"t":"para","text":"Dịch: Năm 30 tuổi ông ấy đã được bổ nhiệm lãnh đạo xí nghiệp và đã hoàn thành xuất sắc công việc này."},{"t":"para","text":"Giải thích: Назначен (được bổ nhiệm) làm gì. Đi trực tiếp với nguyên thể."},{"t":"para","text":"Đáp án sách: không điền."},{"t":"para","text":"К сожале́нию, в э́том слу́чае я бесси́лен помо́чь тебе́;"},{"t":"para","text":"Dịch: Rất tiếc, trong trường hợp này tôi bất lực (không thể) giúp bạn."},{"t":"para","text":"Giải thích: Бессилен (bất lực) đi trực tiếp với nguyên thể."},{"t":"para","text":"Đáp án sách: không điền."},{"t":"para","text":"Ду́маю, тебе́ не уда́стся его́ уговори́ть пое́хать с на́ми, он уже́ стар, что́бы меня́ть свои́ привы́чки;"},{"t":"para","text":"Dịch: Tôi nghĩ bạn sẽ không thuyết phục được ông ấy đi cùng chúng ta đâu, ông ấy đã già (quá già) để thay đổi thói quen của mình."},{"t":"para","text":"Giải thích: Стар (già) ở đây hàm ý \"quá già\" (слишком стар) so với hành động. Cần что́бы."},{"t":"para","text":"Đáp án sách: что́бы."},{"t":"para","text":"Он не привы́к отступа́ть, ду́маю, он ещё пока́жет себя́ в э́том де́ле;"},{"t":"para","text":"Dịch: Anh ấy không quen lùi bước, tôi nghĩ anh ấy sẽ còn thể hiện mình trong việc này."},{"t":"para","text":"Giải thích: Привык (quen) đi trực tiếp với nguyên thể."},{"t":"para","text":"Đáp án sách: không điền."},{"t":"para","text":"Он сли́шком беспо́мощен, что́бы спра́виться с э́той пробле́мой в одино́чку;"},{"t":"para","text":"Dịch: Anh ấy quá bất lực để (có thể) giải quyết vấn đề này một mình."},{"t":"para","text":"Giải thích: Có từ сли́шком (quá), bắt buộc dùng что́бы."},{"t":"para","text":"Đáp án sách: что́бы."},{"t":"para","text":"Я не наме́рен терпе́ть все э́ти гру́бости;"},{"t":"para","text":"Dịch: Tôi không có ý định chịu đựng tất cả những sự thô lỗ này."},{"t":"para","text":"Giải thích: Намерен (có ý định) đi trực tiếp với nguyên thể."},{"t":"para","text":"Đáp án sách: không điền."},{"t":"para","text":"Не сто́ит ждать от него́ оправда́ний, он сли́шком горд, что́бы опра́вдываться;"},{"t":"para","text":"Dịch: Không nên chờ đợi những lời bào chữa từ anh ta, anh ta quá kiêu hãnh để đi bào chữa."},{"t":"para","text":"Giải thích: Có từ сли́шком (quá), bắt buộc dùng что́бы."},{"t":"para","text":"Đáp án sách: что́бы."},{"t":"para","text":"Ты не обя́зан выполня́ть э́ту рабо́ту;"},{"t":"para","text":"Dịch: Bạn không có nghĩa vụ thực hiện công việc này."},{"t":"para","text":"Giải thích: Обязан (có nghĩa vụ) đi trực tiếp với nguyên thể."},{"t":"para","text":"Đáp án sách: không điền."},{"t":"para","text":"Он никогда́ не спра́шивал о положе́нии дел, он привы́к, что́бы ему́ об э́том докла́дывали подчинённые;"},{"t":"para","text":"Dịch: Ông ấy chưa bao giờ hỏi về tình hình công việc, ông ấy quen việc cấp dưới báo cáo cho mình về điều đó."},{"t":"para","text":"Giải thích: Привык (quen) ở đây kết hợp với hành động của chủ thể khác (cấp dưới báo cáo). Hai chủ thể khác nhau $\\rightarrow$ dùng что́бы."},{"t":"para","text":"Đáp án sách: что́бы."},{"t":"para","text":"К сожале́нию, в э́той ситуа́ции мы вы́нуждены обрати́ться за по́мощью;"},{"t":"para","text":"Dịch: Rất tiếc, trong tình huống này chúng tôi buộc phải tìm sự giúp đỡ."},{"t":"para","text":"Giải thích: Вынуждены (buộc phải) đi trực tiếp với nguyên thể."},{"t":"para","text":"Đáp án sách: không điền."},{"t":"para","text":"Он предпочита́ет жить за счёт роди́телей, он сли́шком лени́в, что́бы рабо́тать;"},{"t":"para","text":"Dịch: Cậu ta thích sống dựa vào bố mẹ, cậu ta quá lười để làm việc."},{"t":"para","text":"Giải thích: Có từ сли́шком (quá), bắt buộc dùng что́бы."},{"t":"para","text":"Đáp án sách: что́бы."},{"t":"para","text":"Соба́ка обу́чена повинова́ться кома́ндам хозя́ина;"},{"t":"para","text":"Dịch: Con chó được huấn luyện để tuân theo lệnh của chủ."},{"t":"para","text":"Giải thích: Обучена (được dạy/huấn luyện) làm gì. Đi trực tiếp với nguyên thể."},{"t":"para","text":"Đáp án sách: không điền."},{"t":"para","text":"Как же ты мог пропусти́ть сигна́л «Стоп!»?! Он сли́шком я́ркий, что́бы не заме́тить его́;"},{"t":"para","text":"Dịch: Sao bạn có thể bỏ qua biển báo \"Stop\" chứ?! Nó quá sáng để mà không nhận ra nó."},{"t":"para","text":"Giải thích: Có từ сли́шком (quá), bắt buộc dùng что́бы."},{"t":"para","text":"Đáp án sách: что́бы."},{"t":"para","text":"К сожале́нию, мне ну́жно ненадо́лго уйти́."},{"t":"para","text":"Dịch: Rất tiếc, tôi cần phải rời đi một lát."},{"t":"para","text":"Giải thích: Нужно (cần) + chủ thể (cách 3: мне) + động từ nguyên thể. Không dùng чтобы."},{"t":"para","text":"Đáp án sách: không điền."}]},{"id":"gra-12-s039","type":"exercise","title":"Bài 155","num":155,"blocks":[{"t":"instruction","text":"Раскройте скобки, употребляя определительные слова в нужной форме. Объясните ваше решение."},{"t":"para","text":"(Mở ngoặc đơn, sử dụng các từ định ngữ ở dạng đúng. Giải thích quyết định của bạn.)"},{"t":"subhead","text":"а)"},{"t":"para","text":"Tiếng Nga: Не понима́ют того́, что вре́мени не оста́лось. Никако́го (1) вре́мени нет. Е́сли бы меня́ спроси́ли, что тако́е (2) ста́рость, я бы сказа́л: э́то вре́мя, когда́ вре́мени нет. Потому́ что живём мы, дураки́, непра́вильно, сори́м вре́менем, тра́тим его́ по́пусту, туда́-сюда́, на то на сё, не сообража́я, кака́я (3) э́то изуми́тельная драгоце́нность, да́нная (4) нам неспроста́, а для того́, что́бы мы вы́полнили что́-то, дости́гли чего́-то, а не так — пробу́лькать жизнь лягу́шками на боло́те. Наприме́р, вы́полнить то, о чём сам мечта́л, дости́гнуть того́, чего́ сам хоте́л. А ведь одно́й (5) ма́лости не хвата́ет — вре́мени! Потому́ что порастра́чено, пораски́дано за го́ды, бог ты мой… Они́ говоря́т: куда́ ты, ста́рый (6), пое́дешь? Пого́да скве́рная (7), дожди́, хо́лод, просту́дишься, схва́тишь воспале́ние лёгких (8). В твоём (9) во́зрасте воспале́ние лёгких (8) — коне́ц. Подожди́ до весны́, никуда́ твоя́ (10) А́ся не убежи́т, никуда́ твой (11) Мигу́лин не де́нется. Поду́маешь, спех! Госуда́рственная (12) ва́жность! А о тако́м (13) не дога́дываешься: сам-то (14) я до весны́ никуда́ не де́нусь? Не́ту вре́мени ждать, не́ту, не́ту, ни одного́ (15) денёчка не остаётся (Ю. Три́фонов),,."},{"t":"para","text":"Dịch và giải thích:"},{"t":"para","text":"Dịch: Họ không hiểu rằng thời gian không còn nữa. Không có bất kỳ thời gian nào cả. Nếu người ta hỏi tôi già là gì, tôi sẽ nói: đó là khoảng thời gian khi không còn thời gian nữa. Bởi vì chúng ta, những kẻ ngốc, sống không đúng cách, phung phí thời gian, tiêu xài nó một cách vô ích, vào chuyện này chuyện kia, mà không nhận ra đây là món bảo vật tuyệt diệu như thế nào, thứ được ban tặng cho chúng ta không phải ngẫu nhiên, mà là để chúng ta thực hiện điều gì đó, đạt được điều gì đó, chứ không phải thế này — ùng ục sống hết đời như những con ếch trong đầm lầy. Ví dụ, thực hiện điều mà bản thân từng mơ ước, đạt được điều mà bản thân từng mong muốn. Nhưng lại thiếu một thứ nhỏ nhặt — thời gian! Bởi vì đã phung phí, đã vứt bỏ qua bao năm tháng, lạy chúa tôi... Họ nói: đi đâu, ông già, ông định đi đâu? Thời tiết tồi tệ, mưa, lạnh, ông sẽ bị cảm, sẽ bị viêm phổi đấy. Ở độ tuổi của ông, viêm phổi là dấu chấm hết. Hãy đợi đến mùa xuân, Aся của ông sẽ không chạy đi đâu mất, Migulin của ông cũng chẳng đi đâu mất. Tưởng gì, gấp gáp! Chuyện quan trọng của quốc gia cơ đấy! Thế còn về việc này (ông/bà) không đoán ra sao: rằng bản thân tôi đến mùa xuân cũng chẳng đi đâu mất? Không có thời gian để chờ đợi, không có, không có, không còn lại dù chỉ một ngày nhỏ nào cả."},{"t":"para","text":"Giải thích ngữ pháp:"},{"t":"para","text":"Никако́го: Dùng cách 2 (Genitive) số ít giống trung của đại từ phủ định никакой vì đứng sau từ phủ định нет (cấu trúc phủ định sở hữu/tồn tại)."},{"t":"para","text":"тако́е: Dùng giống trung số ít такое trong cấu trúc định nghĩa \"Что такое [danh từ]?\" (Cái gì là...? / ...là gì?), bất kể danh từ старость (tuổi già) là giống cái."},{"t":"para","text":"кака́я: Dùng cách 1 (Nominative) giống cái số ít để bổ nghĩa cho danh từ драгоценность (bảo vật - giống cái)."},{"t":"para","text":"да́нная: Tính động từ bị động quá khứ (participle), cách 1 giống cái số ít, bổ nghĩa cho драгоценность."},{"t":"para","text":"одно́й: Dùng cách 2 giống cái số ít của số từ один để bổ nghĩa cho малости (thứ nhỏ nhặt - giống cái) sau cấu trúc phủ định не хватает (thiếu)."},{"t":"para","text":"ста́рый: Dùng cách 1 (Nominative) như một hô ngữ (để gọi/xưng hô) chỉ người đàn ông (giống đực)."},{"t":"para","text":"скве́рная: Tính từ giống cái số ít cách 1, làm vị ngữ cho danh từ погода (thời tiết)."},{"t":"para","text":"лёгких: Dùng cách 2 số nhiều trong cụm từ cố định воспаление лёгких (viêm phổi - nghĩa đen là viêm các lá phổi)."},{"t":"para","text":"твоём: Đại từ sở hữu cách 6 (Prepositional) giống đực số ít, bổ nghĩa cho возрасте (độ tuổi), đi sau giới từ В."},{"t":"para","text":"твоя́: Đại từ sở hữu cách 1 giống cái số ít, bổ nghĩa cho tên riêng Ася."},{"t":"para","text":"твой: Đại từ sở hữu cách 1 giống đực số ít, bổ nghĩa cho tên riêng Мигулин."},{"t":"para","text":"Госуда́рственная: Tính từ cách 1 giống cái số ít, bổ nghĩa cho важность (sự quan trọng). Ở đây dùng như một câu cảm thán."},{"t":"para","text":"тако́м: Dùng cách 6 (Prepositional) giống trung của такой (như thế, việc như thế), đi sau giới từ о, ám chỉ một sự việc/tình huống nói chung (việc tôi có thể chết). Lưu ý: Đáp án trong sách dùng giống trung."},{"t":"para","text":"сам: Đại từ nhấn mạnh giống đực, bổ nghĩa cho chủ ngữ я (người nói là nam, dựa vào ngữ cảnh старый)."},{"t":"para","text":"одного́: Cách 2 giống đực số ít của số từ один, bổ nghĩa cho danh từ денёчка (ngày - dạng giảm nhẹ của день) trong cấu trúc phủ định nhấn mạnh ни одного... не...."},{"t":"subhead","text":"б)"},{"t":"para","text":"Tiếng Nga: Две бе́лки небе́сного (1) цве́та, черномо́рдые (2), чернохво́стые (3), увлечённо вгля́дывались в то, что твори́лось за сере́бряными (4) ли́ственницами. Я подошёл к де́реву, на ветвя́х кото́рого (5) они́ сиде́ли, почти́ вплотну́ю, и то́лько тогда́ бе́лки заме́тили меня́. Бе́личьи (6) ко́гти зашурша́ли по коре́ де́рева, си́ние (7) тела́ зверько́в метну́лись вверх и где́-то высоко́-высоко́ зати́хли. Кро́шки коры́ переста́ли сы́паться на снег. Я уви́дел то, что разгля́дывали бе́лки. На лесно́й (8) поля́не моли́лся челове́к. Мате́рчатая (9) ша́пка-уша́нка комо́чком лежа́ла у его́ ног, и́ней успе́л уже́ вы́белить стри́женную (10) го́лову. На лице́ его́ бы́ло выраже́ние удиви́тельное (11) — то са́мое (12), что быва́ет на ли́цах люде́й, вспомина́ющих (13) де́тство и́ли что́-либо равноце́нно дорого́е (14). Челове́к крести́лся разма́шисто и бы́стро: тремя́ сло́женными (15) па́льцами пра́вой (16) руки́ он бу́дто тяну́л вниз свою́ (17) со́бственную (17) го́лову. Я не сра́зу узна́л его́ — так мно́го но́вого (18) бы́ло в черта́х его́ лица́. Э́то был заключённый (19) Замя́тин, свяще́нник из одного́ (20) бара́ка со мно́й. Всё ещё не ви́дя меня́, он выгова́ривал негро́мко и торже́ственно неме́ющими (21) от хо́лода губа́ми привы́чные (22), запо́мненные (22) мной с де́тства слова́. Э́то бы́ли славя́нские фо́рмулы литурги́йной (23) слу́жбы — Замя́тин служи́л обе́дню в сере́бряном (24) лесу́ (В. Шала́мов),,,."},{"t":"para","text":"Dịch và giải thích:"},{"t":"para","text":"Dịch: Hai con sóc màu thiên thanh, mõm đen, đuôi đen, say sưa nhìn chằm chằm vào những gì đang diễn ra phía sau những cây thông rụng lá màu bạc. Tôi đến gần cái cây mà trên cành của nó chúng đang ngồi, gần như sát sạt, và chỉ khi đó những con sóc mới nhận ra tôi. Móng vuốt của sóc sột soạt trên vỏ cây, những thân mình màu xanh của lũ thú nhỏ lao vút lên cao và im bặt đâu đó tít trên cao. Những vụn vỏ cây ngừng rơi xuống tuyết. Tôi đã nhìn thấy cái mà những con sóc đang quan sát. Trên một bãi đất trống trong rừng, một người đàn ông đang cầu nguyện. Một chiếc mũ che tai bằng vải nằm cuộn tròn dưới chân ông, sương giá đã kịp nhuộm trắng mái đầu được cắt tóc ngắn. Trên khuôn mặt ông có một biểu cảm ngạc nhiên — chính cái biểu cảm thường có trên khuôn mặt của những người đang hồi tưởng lại tuổi thơ hoặc bất cứ điều gì quý giá tương đương. Người đàn ông làm dấu thánh một cách rộng rãi và nhanh chóng: với ba ngón tay chắp lại của bàn tay phải, ông như thể đang kéo cái đầu của chính mình xuống dưới. Tôi không nhận ra ông ngay lập tức — có quá nhiều điều mới lạ trong những đường nét trên khuôn mặt ông. Đó là tù nhân Zamyatin, một linh mục cùng lán trại với tôi. Vẫn chưa nhìn thấy tôi, ông ấy thốt ra khe khẽ và trang trọng bằng đôi môi đang tê đi vì lạnh những lời lẽ quen thuộc, được tôi ghi nhớ từ thuở ấu thơ. Đó là những công thức bằng tiếng Slav của buổi lễ phụng vụ — Zamyatin đang cử hành lễ mixa trong khu rừng bạc."},{"t":"para","text":"Giải thích ngữ pháp:"},{"t":"para","text":"небе́сного: Tính từ cách 2 (Genitive) giống đực số ít, bổ nghĩa cho цвета (màu sắc) trong cấu trúc chỉ đặc điểm \"của màu gì\"."},{"t":"para","text":"черномо́рдые: Tính từ cách 1 số nhiều. Quy tắc: Với chủ ngữ Две (hai) + danh từ giống cái (белки - cách 2 số ít), tính từ đi kèm thường ở cách 1 số nhiều (Nominative Plural)."},{"t":"para","text":"чернохво́стые: Tương tự như trên, tính từ cách 1 số nhiều bổ nghĩa cho две белки."},{"t":"para","text":"сере́бряными: Tính từ cách 5 (Instrumental) số nhiều, bổ nghĩa cho лиственницами sau giới từ за."},{"t":"para","text":"кото́рого: Đại từ quan hệ cách 2 giống trung số ít, thay thế cho дереву (cái cây) để chỉ sở hữu (cành của cái cây đó)."},{"t":"para","text":"Бе́личьи: Tính từ sở hữu, cách 1 số nhiều, bổ nghĩa cho когти (móng vuốt)."},{"t":"para","text":"си́ние: Tính từ cách 1 số nhiều, bổ nghĩa cho тела (thân mình)."},{"t":"para","text":"лесно́й: Tính từ cách 6 giống cái số ít, bổ nghĩa cho поляне sau giới từ На."},{"t":"para","text":"Мате́рчатая: Tính từ cách 1 giống cái số ít, bổ nghĩa cho chủ ngữ шапка-ушанка."},{"t":"para","text":"стри́женную: Tính động từ bị động/tính từ gốc động từ ở cách 4 (Accusative) giống cái số ít, bổ nghĩa cho голову. Lưu ý: Sách đáp án viết là \"стриженную\" (2 chữ н), coi nó như một tính động từ đầy đủ hoặc theo quy tắc chính tả riêng của sách."},{"t":"para","text":"удиви́тельное: Tính từ cách 1 giống trung số ít, bổ nghĩa cho выражение (biểu cảm)."},{"t":"para","text":"са́мое: Đại từ chỉ định/tính từ, cách 1 giống trung số ít, trong cụm cố định то самое (chính cái đó)."},{"t":"para","text":"вспомина́ющих: Tính động từ chủ động hiện tại, cách 2 số nhiều, bổ nghĩa cho людей."},{"t":"para","text":"дорого́е: Tính từ được danh từ hóa (hoặc bổ nghĩa cho что-либо), cách 1/4 giống trung số ít."},{"t":"para","text":"сло́женными: Tính động từ bị động quá khứ, cách 5 số nhiều, bổ nghĩa cho пальцами."},{"t":"para","text":"пра́вой: Tính từ cách 2 giống cái số ít, bổ nghĩa cho руки."},{"t":"para","text":"свою́ со́бственную: Đại từ sở hữu và tính từ nhấn mạnh, cách 4 giống cái số ít, bổ nghĩa cho голову."},{"t":"para","text":"но́вого: Tính từ dùng như danh từ, cách 2 giống trung số ít, sau từ chỉ lượng много."},{"t":"para","text":"заключённый: Danh từ (vốn là tính động từ), cách 1 giống đực số ít, làm vị ngữ giải thích (định danh)."},{"t":"para","text":"одного́: Số từ cách 2 giống đực số ít, bổ nghĩa cho барака sau giới từ из."},{"t":"para","text":"неме́ющими: Tính động từ chủ động hiện tại, cách 5 số nhiều, bổ nghĩa cho губами."},{"t":"para","text":"привы́чные, запо́мненные: Tính từ và tính động từ bị động quá khứ, cách 4 số nhiều (đối với danh từ bất động vật слова), bổ nghĩa cho слова."},{"t":"para","text":"литурги́йной: Tính từ cách 2 giống cái số ít, bổ nghĩa cho службы."},{"t":"para","text":"сере́бряном: Tính từ cách 6 giống đực số ít, bổ nghĩa cho лесу sau giới từ в."}]}]};
